'\ndo\n    local Environment =\n        type(getgenv) == "function"\n        and getgenv()\n        or _G\n\n    local Config =\n        type(Environment.SliceHubKeyGateConfig) == "table"\n        and Environment.SliceHubKeyGateConfig\n        or {}\n\n    local PendingSource = Config.Source\n    local PendingName =\n        tostring(Config.SourceName or "SliceHub")\n    local RequestedTier =\n        string.upper(\n            tostring(Config.BuildTier or "FREE")\n        )\n    local DiscordInvite =\n        tostring(\n            Config.DiscordInvite\n            or "https://discord.gg/Fg3tQG5CSA"\n        )\n    local DefaultApiUrl =\n        tostring(\n            Config.ApiUrl\n            or "https://YOUR_RAILWAY_DOMAIN/api/validate"\n        )\n\n    if type(PendingSource) ~= "string"\n        or PendingSource == "" then\n        warn("[SliceHub Key Gate] Missing pending source.")\n        return\n    end\n\n    local Players = game:GetService("Players")\n    local TweenService = game:GetService("TweenService")\n    local UserInputService =\n        game:GetService("UserInputService")\n    local HttpService =\n        game:GetService("HttpService")\n    local GuiService =\n        game:GetService("GuiService")\n    local CoreGui = game:GetService("CoreGui")\n\n    local Player = Players.LocalPlayer\n        or Players.PlayerAdded:Wait()\n    local PlayerGui =\n        Player:FindFirstChildOfClass("PlayerGui")\n        or Player:WaitForChild("PlayerGui")\n\n    local function trim(value)\n        return (\n            tostring(value or "")\n            :gsub("^%s+", "")\n            :gsub("%s+$", "")\n        )\n    end\n\n    local function findFunction(...)\n        local names = {...}\n\n        for _, name in ipairs(names) do\n            local value = Environment[name]\n\n            if type(value) == "function" then\n                return value\n            end\n        end\n\n        return nil\n    end\n\n    local readFile =\n        findFunction("readfile")\n        or (\n            type(readfile) == "function"\n            and readfile\n            or nil\n        )\n    local writeFile =\n        findFunction("writefile")\n        or (\n            type(writefile) == "function"\n            and writefile\n            or nil\n        )\n    local isFile =\n        findFunction("isfile")\n        or (\n            type(isfile) == "function"\n            and isfile\n            or nil\n        )\n    local makeFolder =\n        findFunction("makefolder")\n        or (\n            type(makefolder) == "function"\n            and makefolder\n            or nil\n        )\n    local isFolder =\n        findFunction("isfolder")\n        or (\n            type(isfolder) == "function"\n            and isfolder\n            or nil\n        )\n    local deleteFile =\n        findFunction("delfile")\n        or (\n            type(delfile) == "function"\n            and delfile\n            or nil\n        )\n\n    local Request =\n        (\n            type(Environment.request) == "function"\n            and Environment.request\n        )\n        or (\n            type(Environment.http_request) == "function"\n            and Environment.http_request\n        )\n        or (\n            type(Environment.httprequest) == "function"\n            and Environment.httprequest\n        )\n        or (\n            type(syn) == "table"\n            and type(syn.request) == "function"\n            and syn.request\n        )\n        or (\n            type(http) == "table"\n            and type(http.request) == "function"\n            and http.request\n        )\n        or (\n            type(fluxus) == "table"\n            and type(fluxus.request) == "function"\n            and fluxus.request\n        )\n\n    local function ensureFolder()\n        if type(makeFolder) ~= "function" then\n            return false\n        end\n\n        local exists = false\n\n        if type(isFolder) == "function" then\n            local ok, result = pcall(\n                isFolder,\n                "SH"\n            )\n            exists = ok and result == true\n        end\n\n        if not exists then\n            pcall(makeFolder, "SH")\n        end\n\n        return true\n    end\n\n    local function readTextFile(path)\n        if type(readFile) ~= "function" then\n            return nil\n        end\n\n        if type(isFile) == "function" then\n            local okExists, exists =\n                pcall(isFile, path)\n\n            if not okExists or exists ~= true then\n                return nil\n            end\n        end\n\n        local ok, result =\n            pcall(readFile, path)\n\n        if ok and type(result) == "string" then\n            return result\n        end\n\n        return nil\n    end\n\n    local function resolveApiUrl()\n        local override = trim(\n            Environment.SLICEHUB_KEY_API_URL\n            or Environment.SliceHubKeyApiUrl\n            or ""\n        )\n\n        if override ~= "" then\n            return override\n        end\n\n        local savedApi =\n            trim(\n                readTextFile(\n                    "SH/license_api.txt"\n                )\n                or ""\n            )\n\n        if savedApi ~= "" then\n            return savedApi\n        end\n\n        return trim(DefaultApiUrl)\n    end\n\n    local function normalizeUrlCandidates(raw)\n        raw = trim(raw)\n\n        if raw == ""\n            or string.find(\n                raw,\n                "YOUR_RAILWAY_DOMAIN",\n                1,\n                true\n            ) then\n            return {}\n        end\n\n        if not string.match(\n            string.lower(raw),\n            "^https?://"\n        ) then\n            raw = "https://" .. raw\n        end\n\n        raw = string.gsub(raw, "/+$", "")\n\n        local candidates = {}\n        local seen = {}\n\n        local function push(url)\n            if url ~= ""\n                and not seen[url] then\n                seen[url] = true\n                candidates[#candidates + 1] = url\n            end\n        end\n\n        if string.find(\n            string.lower(raw),\n            "/api/",\n            1,\n            true\n        )\n            or string.match(\n                string.lower(raw),\n                "/validate[%w%-%_]*$"\n            ) then\n            push(raw)\n        else\n            push(raw .. "/api/validate")\n            push(raw .. "/validate")\n        end\n\n        return candidates\n    end\n\n    local function savedLicense()\n        local content =\n            readTextFile("SH/license.json")\n\n        if not content or content == "" then\n            return nil\n        end\n\n        local ok, decoded = pcall(\n            HttpService.JSONDecode,\n            HttpService,\n            content\n        )\n\n        if ok and type(decoded) == "table" then\n            return decoded\n        end\n\n        return nil\n    end\n\n    local function saveLicense(key, data)\n        if type(writeFile) ~= "function" then\n            return false\n        end\n\n        ensureFolder()\n\n        local payload = {\n            key = key,\n            tier = data and (\n                data.tier\n                or data.plan\n                or data.licenseType\n            ) or nil,\n            expiresAt = data\n                and tonumber(\n                    data.expiresAt\n                    or data.expires\n                    or data.expiry\n                )\n                or nil,\n            savedAt = os.time(),\n        }\n\n        local okEncode, encoded = pcall(\n            HttpService.JSONEncode,\n            HttpService,\n            payload\n        )\n\n        if not okEncode then\n            return false\n        end\n\n        local okWrite = pcall(\n            writeFile,\n            "SH/license.json",\n            encoded\n        )\n\n        return okWrite\n    end\n\n    local function clearSavedLicense()\n        if type(deleteFile) == "function" then\n            pcall(\n                deleteFile,\n                "SH/license.json"\n            )\n        elseif type(writeFile) == "function" then\n            pcall(\n                writeFile,\n                "SH/license.json",\n                ""\n            )\n        end\n    end\n\n    local function requestStatus(response)\n        if type(response) ~= "table" then\n            return nil\n        end\n\n        return tonumber(\n            response.StatusCode\n            or response.Status\n            or response.status_code\n        )\n    end\n\n    local function requestBody(response)\n        if type(response) == "string" then\n            return response\n        end\n\n        if type(response) ~= "table" then\n            return nil\n        end\n\n        return response.Body\n            or response.body\n            or response.Response\n            or response.response\n    end\n\n    local function decodeResponse(body)\n        body = trim(body)\n\n        if body == "" then\n            return nil, "Empty response"\n        end\n\n        local ok, decoded = pcall(\n            HttpService.JSONDecode,\n            HttpService,\n            body\n        )\n\n        if ok and type(decoded) == "table" then\n            return decoded\n        end\n\n        if string.lower(body) == "true" then\n            return {valid = true}\n        end\n\n        return nil, "Invalid JSON response"\n    end\n\n    local function urlEncode(value)\n        local ok, result = pcall(\n            HttpService.UrlEncode,\n            HttpService,\n            tostring(value or "")\n        )\n\n        return ok and result or tostring(value or "")\n    end\n\n    local function resolveDeviceId()\n        local value = ""\n\n        local environment =\n            type(getgenv) == "function"\n            and getgenv()\n            or _G\n\n        local getHwid =\n            environment\n            and environment.gethwid\n            or gethwid\n\n        if type(getHwid) == "function" then\n            pcall(function()\n                value = tostring(getHwid())\n            end)\n        end\n\n        if value == "" then\n            pcall(function()\n                value = tostring(\n                    game:GetService(\n                        "RbxAnalyticsService"\n                    ):GetClientId()\n                )\n            end)\n        end\n\n        if value == "" then\n            -- Stable fallback so teleports between AOT:R places do not\n            -- create false HWID mismatches on limited executors.\n            value = "roblox-user:" .. tostring(Player.UserId)\n        end\n\n        return value\n    end\n\n    local function validateAtUrl(url, key)\n        local deviceId = resolveDeviceId()\n        local requestPayload = {\n            key = key,\n            scriptKey = key,\n            userId = tostring(Player.UserId),\n            username = tostring(Player.Name),\n            displayName = tostring(\n                Player.DisplayName\n                or Player.Name\n            ),\n            placeId = tonumber(game.PlaceId) or 0,\n            jobId = tostring(game.JobId or ""),\n            requestedTier = RequestedTier,\n            buildTier = RequestedTier,\n            deviceId = deviceId,\n            hwid = deviceId,\n            clientId = deviceId,\n            client = "SliceHub",\n            version = tostring(\n                Config.Version or "9.8.2.7"\n            ),\n        }\n\n        local encodedPayload =\n            HttpService:JSONEncode(\n                requestPayload\n            )\n\n        if type(Request) == "function" then\n            local okPost, response = pcall(\n                Request,\n                {\n                    Url = url,\n                    Method = "POST",\n                    Headers = {\n                        ["Content-Type"] =\n                            "application/json",\n                        ["Accept"] =\n                            "application/json",\n                    },\n                    Body = encodedPayload,\n                }\n            )\n\n            if okPost then\n                local status =\n                    requestStatus(response)\n                local body =\n                    requestBody(response)\n\n                if status == nil\n                    or (\n                        status >= 200\n                        and status < 300\n                    ) then\n                    local decoded, decodeError =\n                        decodeResponse(body)\n\n                    if decoded then\n                        return true, decoded\n                    end\n\n                    if status ~= nil then\n                        return false, nil, decodeError\n                    end\n                elseif status ~= 404\n                    and status ~= 405 then\n                    local decoded =\n                        select(\n                            1,\n                            decodeResponse(body)\n                        )\n\n                    local message =\n                        decoded\n                        and (\n                            decoded.message\n                            or decoded.error\n                            or decoded.reason\n                        )\n\n                    return false, nil,\n                        tostring(\n                            message\n                            or ("HTTP " .. status)\n                        )\n                end\n            end\n\n            local joiner =\n                string.find(url, "?", 1, true)\n                and "&"\n                or "?"\n\n            local getUrl =\n                url\n                .. joiner\n                .. "key="\n                .. urlEncode(key)\n                .. "&userId="\n                .. urlEncode(Player.UserId)\n                .. "&requestedTier="\n                .. urlEncode(RequestedTier)\n                .. "&deviceId="\n                .. urlEncode(deviceId)\n\n            local okGet, getResponse = pcall(\n                Request,\n                {\n                    Url = getUrl,\n                    Method = "GET",\n                    Headers = {\n                        ["Accept"] =\n                            "application/json",\n                    },\n                }\n            )\n\n            if okGet then\n                local status =\n                    requestStatus(getResponse)\n                local body =\n                    requestBody(getResponse)\n\n                if status == nil\n                    or (\n                        status >= 200\n                        and status < 300\n                    ) then\n                    local decoded, decodeError =\n                        decodeResponse(body)\n\n                    if decoded then\n                        return true, decoded\n                    end\n\n                    return false, nil, decodeError\n                end\n\n                local decoded =\n                    select(\n                        1,\n                        decodeResponse(body)\n                    )\n\n                return false, nil,\n                    tostring(\n                        decoded\n                        and (\n                            decoded.message\n                            or decoded.error\n                            or decoded.reason\n                        )\n                        or ("HTTP " .. tostring(status))\n                    )\n            end\n        end\n\n        local joiner =\n            string.find(url, "?", 1, true)\n            and "&"\n            or "?"\n\n        local getUrl =\n            url\n            .. joiner\n            .. "key="\n            .. urlEncode(key)\n            .. "&userId="\n            .. urlEncode(Player.UserId)\n            .. "&requestedTier="\n            .. urlEncode(RequestedTier)\n            .. "&deviceId="\n            .. urlEncode(deviceId)\n\n        local okHttp, body = pcall(\n            game.HttpGet,\n            game,\n            getUrl\n        )\n\n        if okHttp then\n            local decoded, decodeError =\n                decodeResponse(body)\n\n            if decoded then\n                return true, decoded\n            end\n\n            return false, nil, decodeError\n        end\n\n        return false, nil,\n            "No supported HTTP request method"\n    end\n\n    local function responseIsValid(data)\n        if type(data) ~= "table" then\n            return false, "Invalid server response"\n        end\n\n        local valid =\n            data.valid == true\n            or data.success == true\n            or data.authorized == true\n            or data.allowed == true\n\n        if not valid then\n            return false,\n                tostring(\n                    data.message\n                    or data.error\n                    or data.reason\n                    or "Key rejected"\n                )\n        end\n\n        local expiresAt = tonumber(\n            data.expiresAt\n            or data.expires\n            or data.expiry\n        )\n\n        if expiresAt\n            and expiresAt > 0\n            and expiresAt <= os.time() then\n            return false, "Key expired"\n        end\n\n        if RequestedTier == "PREMIUM" then\n            local responseTier =\n                string.upper(\n                    tostring(\n                        data.tier\n                        or data.plan\n                        or data.licenseType\n                        or ""\n                    )\n                )\n\n            local premium =\n                data.premium == true\n                or responseTier == "PREMIUM"\n                or responseTier == "PAID"\n                or responseTier == "LIFETIME"\n\n            if not premium then\n                return false,\n                    "This key does not unlock Premium"\n            end\n        end\n\n        return true\n    end\n\n    local function validateKey(key)\n        key = trim(key)\n\n        if key == "" then\n            return false, nil, "Enter your key"\n        end\n\n        local candidates =\n            normalizeUrlCandidates(\n                resolveApiUrl()\n            )\n\n        if #candidates == 0 then\n            return false, nil,\n                "Key server is not configured"\n        end\n\n        local lastError =\n            "Unable to contact key server"\n\n        for _, url in ipairs(candidates) do\n            local transportOk, data, errorMessage =\n                validateAtUrl(url, key)\n\n            if transportOk and data then\n                local accepted, reason =\n                    responseIsValid(data)\n\n                if accepted then\n                    return true, data, nil\n                end\n\n                return false, data, reason\n            end\n\n            lastError =\n                tostring(\n                    errorMessage\n                    or lastError\n                )\n        end\n\n        return false, nil, lastError\n    end\n\n    local function safeGuiParent(gui)\n        local parent = nil\n\n        if type(gethui) == "function" then\n            pcall(function()\n                parent = gethui()\n            end)\n        end\n\n        if not parent then\n            parent = CoreGui\n        end\n\n        local ok = pcall(function()\n            gui.Parent = parent\n        end)\n\n        if not ok or gui.Parent == nil then\n            gui.Parent = PlayerGui\n        end\n    end\n\n    local old =\n        CoreGui:FindFirstChild(\n            "SliceHubKeyGate"\n        )\n        or PlayerGui:FindFirstChild(\n            "SliceHubKeyGate"\n        )\n\n    if old then\n        old:Destroy()\n    end\n\n    local Screen = Instance.new("ScreenGui")\n    Screen.Name = "SliceHubKeyGate"\n    Screen.ResetOnSpawn = false\n    Screen.IgnoreGuiInset = true\n    Screen.DisplayOrder = 2147483647\n    Screen.ZIndexBehavior =\n        Enum.ZIndexBehavior.Global\n    safeGuiParent(Screen)\n\n    local Blocker = Instance.new("TextButton")\n    Blocker.Name = "InputBlocker"\n    Blocker.Size = UDim2.fromScale(1, 1)\n    Blocker.BackgroundColor3 =\n        Color3.fromRGB(3, 4, 9)\n    Blocker.BackgroundTransparency = 0.25\n    Blocker.BorderSizePixel = 0\n    Blocker.Text = ""\n    Blocker.AutoButtonColor = false\n    Blocker.Modal = true\n    Blocker.ZIndex = 900\n    Blocker.Parent = Screen\n\n    local Window = Instance.new("Frame")\n    Window.Name = "Window"\n    Window.AnchorPoint = Vector2.new(0.5, 0.5)\n    Window.Position = UDim2.fromScale(0.5, 0.5)\n    Window.Size = UDim2.fromOffset(460, 318)\n    Window.BackgroundColor3 =\n        Color3.fromRGB(12, 12, 19)\n    Window.BorderSizePixel = 0\n    Window.ZIndex = 910\n    Window.Parent = Screen\n\n    local WindowCorner = Instance.new("UICorner")\n    WindowCorner.CornerRadius =\n        UDim.new(0, 14)\n    WindowCorner.Parent = Window\n\n    local WindowStroke = Instance.new("UIStroke")\n    WindowStroke.Color =\n        Color3.fromRGB(91, 132, 255)\n    WindowStroke.Transparency = 0.18\n    WindowStroke.Thickness = 1.3\n    WindowStroke.Parent = Window\n\n    local Gradient = Instance.new("UIGradient")\n    Gradient.Color = ColorSequence.new({\n        ColorSequenceKeypoint.new(\n            0,\n            Color3.fromRGB(18, 18, 29)\n        ),\n        ColorSequenceKeypoint.new(\n            1,\n            Color3.fromRGB(8, 9, 15)\n        ),\n    })\n    Gradient.Rotation = 90\n    Gradient.Parent = Window\n\n    local Accent = Instance.new("Frame")\n    Accent.Size = UDim2.new(1, 0, 0, 3)\n    Accent.BackgroundColor3 =\n        Color3.fromRGB(73, 141, 255)\n    Accent.BorderSizePixel = 0\n    Accent.ZIndex =