w\n\n    local Scale = Instance.new("UIScale")\n    Scale.Name = "ResponsiveScale"\n    Scale.Parent = Window\n\n    local function updateScale()\n        local camera = workspace.CurrentCamera\n        local viewport = camera\n            and camera.ViewportSize\n            or Vector2.new(1280, 720)\n        local factor = math.min(\n            1,\n            math.max(\n                0.70,\n                math.min(\n                    viewport.X / 520,\n                    viewport.Y / 380\n                )\n            )\n        )\n        Scale.Scale = factor\n    end\n\n    updateScale()\n\n    if workspace.CurrentCamera then\n        workspace.CurrentCamera\n            :GetPropertyChangedSignal(\n                "ViewportSize"\n            )\n            :Connect(updateScale)\n    end\n\n    workspace:GetPropertyChangedSignal(\n        "CurrentCamera"\n    ):Connect(function()\n        task.defer(updateScale)\n    end)\n\n    do\n        local dragging = false\n        local dragStart = nil\n        local startPosition = nil\n\n        Window.InputBegan:Connect(\n            function(input)\n                if input.UserInputType\n                    == Enum.UserInputType.MouseButton1\n                    or input.UserInputType\n                    == Enum.UserInputType.Touch then\n\n                    dragging = true\n                    dragStart = input.Position\n                    startPosition = Window.Position\n                end\n            end\n        )\n\n        Window.InputEnded:Connect(\n            function(input)\n                if input.UserInputType\n                    == Enum.UserInputType.MouseButton1\n                    or input.UserInputType\n                    == Enum.UserInputType.Touch then\n                    dragging = false\n                end\n            end\n        )\n\n        UserInputService.InputChanged:Connect(\n            function(input)\n                if not dragging\n                    or (\n                        input.UserInputType\n                        ~= Enum.UserInputType.MouseMovement\n                        and input.UserInputType\n                        ~= Enum.UserInputType.Touch\n                    ) then\n                    return\n                end\n\n                local delta =\n                    input.Position - dragStart\n\n                Window.Position = UDim2.new(\n                    startPosition.X.Scale,\n                    startPosition.X.Offset\n                        + delta.X / Scale.Scale,\n                    startPosition.Y.Scale,\n                    startPosition.Y.Offset\n                        + delta.Y / Scale.Scale\n                )\n            end\n        )\n    end\n\n    local function setStatus(message, kind)\n        Status.Text = tostring(message or "")\n\n        if kind == "success" then\n            Status.TextColor3 =\n                Color3.fromRGB(104, 229, 160)\n            StatusCard.BackgroundColor3 =\n                Color3.fromRGB(15, 31, 25)\n        elseif kind == "error" then\n            Status.TextColor3 =\n                Color3.fromRGB(255, 123, 139)\n            StatusCard.BackgroundColor3 =\n                Color3.fromRGB(35, 17, 23)\n        elseif kind == "working" then\n            Status.TextColor3 =\n                Color3.fromRGB(121, 186, 255)\n            StatusCard.BackgroundColor3 =\n                Color3.fromRGB(15, 24, 38)\n        else\n            Status.TextColor3 =\n                Color3.fromRGB(157, 163, 184)\n            StatusCard.BackgroundColor3 =\n                Color3.fromRGB(16, 17, 26)\n        end\n    end\n\n    local function attemptOpenDiscord()\n        local openers = {\n            Environment.openurl,\n            Environment.open_url,\n            Environment.launch_url,\n            Environment.launchurl,\n            Environment.openbrowser,\n            type(syn) == "table"\n                and syn.open_url\n                or nil,\n        }\n\n        for _, opener in ipairs(openers) do\n            if type(opener) == "function" then\n                local ok = pcall(\n                    opener,\n                    DiscordInvite\n                )\n\n                if ok then\n                    return true, "Discord opened"\n                end\n            end\n        end\n\n        local okBrowser = pcall(\n            GuiService.OpenBrowserWindow,\n            GuiService,\n            DiscordInvite\n        )\n\n        if okBrowser then\n            return true, "Discord opened"\n        end\n\n        local clipboard =\n            Environment.setclipboard\n            or Environment.toclipboard\n            or (\n                type(setclipboard) == "function"\n                and setclipboard\n                or nil\n            )\n\n        if type(clipboard) == "function" then\n            local ok = pcall(\n                clipboard,\n                DiscordInvite\n            )\n\n            if ok then\n                return true,\n                    "Discord invite copied to clipboard"\n            end\n        end\n\n        return false,\n            "Open this invite: "\n            .. DiscordInvite\n    end\n\n    GetKey.Activated:Connect(function()\n        local ok, message =\n            attemptOpenDiscord()\n\n        setStatus(\n            message,\n            ok and "success" or "error"\n        )\n    end)\n\n    local Busy = false\n    local Launched = false\n\n    local function launchSource(key, data)\n        if Launched then\n            return\n        end\n\n        Launched = true\n        Busy = false\n\n        Environment.SCRIPT_KEY = key\n        Environment.SliceHubLicense = data\n        Environment.SliceHubKeyValidated = true\n\n        saveLicense(key, data)\n\n        setStatus(\n            "Key accepted. Launching "\n            .. PendingName\n            .. "...",\n            "success"\n        )\n\n        Verify.Text = "ACCESS GRANTED"\n        Verify.BackgroundColor3 =\n            Color3.fromRGB(55, 183, 111)\n\n        local onValidated = Config.OnValidated\n\n        if type(onValidated) == "function" then\n            pcall(onValidated, key, data)\n        end\n\n        task.wait(0.45)\n\n        if Screen.Parent then\n            Screen:Destroy()\n        end\n\n        local loader = loadstring or load\n\n        if type(loader) ~= "function" then\n            warn(\n                "[SliceHub Key Gate] loadstring/load unavailable."\n            )\n            return\n        end\n\n        local chunk, compileError =\n            loader(PendingSource)\n\n        if type(chunk) ~= "function" then\n            warn(\n                "[SliceHub Key Gate] Compile failed for "\n                .. PendingName\n                .. ": "\n                .. tostring(compileError)\n            )\n            return\n        end\n\n        print(\n            "[SliceHub Key Gate] Access approved:",\n            RequestedTier,\n            PendingName\n        )\n\n        task.spawn(function()\n            local ok, runtimeError =\n                pcall(chunk)\n\n            if not ok then\n                warn(\n                    "[SliceHub Key Gate] Runtime error in "\n                    .. PendingName\n                    .. ": "\n                    .. tostring(runtimeError)\n                )\n            end\n        end)\n    end\n\n    local function submit(key, automatic)\n        if Busy or Launched then\n            return\n        end\n\n        key = trim(key)\n\n        if key == "" then\n            setStatus("Enter your key first.", "error")\n            return\n        end\n\n        Busy = true\n        Verify.Text = "CHECKING..."\n        Verify.BackgroundColor3 =\n            Color3.fromRGB(48, 87, 164)\n\n        setStatus(\n            automatic\n                and "Checking saved key..."\n                or "Asking the SliceHub license server...",\n            "working"\n        )\n\n        task.spawn(function()\n            local ok, data, errorMessage =\n                validateKey(key)\n\n            Busy = false\n\n            if ok then\n                launchSource(key, data)\n                return\n            end\n\n            Verify.Text = "VERIFY & LAUNCH"\n            Verify.BackgroundColor3 =\n                Color3.fromRGB(67, 133, 255)\n\n            if automatic then\n                clearSavedLicense()\n            end\n\n            setStatus(\n                tostring(\n                    errorMessage\n                    or "Key rejected"\n                ),\n                "error"\n            )\n        end)\n    end\n\n    Verify.Activated:Connect(function()\n        submit(KeyBox.Text, false)\n    end)\n\n    KeyBox.FocusLost:Connect(\n        function(enterPressed)\n            if enterPressed then\n                submit(KeyBox.Text, false)\n            end\n        end\n    )\n\n    local initialKey =\n        trim(Environment.SCRIPT_KEY or "")\n\n    if initialKey == "" then\n        local saved = savedLicense()\n\n        if saved and type(saved.key) == "string" then\n            initialKey = trim(saved.key)\n        end\n    end\n\n    if initialKey ~= "" then\n        KeyBox.Text = initialKey\n\n        task.delay(0.15, function()\n            if Screen.Parent then\n                submit(initialKey, true)\n            end\n        end)\n    else\n        local candidates =\n            normalizeUrlCandidates(\n                resolveApiUrl()\n            )\n\n        if #candidates == 0 then\n            setStatus(\n                "Key server not configured yet. Add your Railway domain to SH/license_api.txt, then enter a key.",\n                "error"\n            )\n        end\n    end\nend\n'
local m=
'\n-- Slice Hub V3 Lobby Engine\n-- Primary path: exact S_Missions Create -> Modify -> Start protocol.\n-- Safety path: learned trace / Turbo UI fallback.\n\nlocal Players = game:GetService("Players")\nlocal TweenService = game:GetService("TweenService")\nlocal UserInputService = game:GetService("UserInputService")\nlocal HttpService = game:GetService("HttpService")\nlocal Workspace = game:GetService("Workspace")\nlocal VirtualInputManager = game:GetService("VirtualInputManager")\nlocal GuiService = game:GetService("GuiService")\n\nlocal player = Players.LocalPlayer\nlocal playerGui = player:WaitForChild("PlayerGui")\n\nlocal SaveFileName = "LobbyCreatorConfigs_v13.json"\nlocal SettingsFileName = "LobbyCreatorSettings_v13.json"\nlocal LastMissionInfoFileName = "AOT_LastMissionInfo_v1.json"\nlocal MissionRemoteTraceFileName = "AOT_MissionRemoteTrace_v1.json"\n\nlocal MissionData = {\n\t["Shiganshina"] = {"Skirmish", "Breach", "Random"},\n\t["Trost"] = {"Skirmish", "Protect", "Random"},\n\t["Outskirts"] = {"Skirmish", "Escort", "Random"},\n\t["Giant Forest"] = {"Skirmish", "Guard", "Random"},\n\t["Utgard Castle"] = {"Skirmish", "Defend", "Random"},\n\t["Loading Docks"] = {"Skirmish", "Stall", "Random"},\n\t["Stohess"] = {"Skirmish", "Random"},\n\t["Chapel"] = {"Skirmish", "Random"},\n}\n\nlocal MapOrder = {"Shiganshina", "Trost", "Outskirts", "Giant Forest", "Utgard Castle", "Loading Docks", "Stohess", "Chapel"}\n\n-- V4.2.0 grounded lobby raid catalog.\n-- Objective names are the raid runtime names used by the reward/cutscene modules.\nV401LobbyRaid = {\n    Order = {\n        "Shiganshina (Arm)",\n        "Shiganshina (Col)",\n        "Trost (Att)",\n        "Stohess (Female)",\n    },\n    Data = {\n        ["Shiganshina (Arm)"] = {\n            Map = "Shiganshina",\n            Objective = "Armored Titan",\n            Difficulties = {"Hard", "Severe", "Aberrant"},\n            Aliases = {"armored titan", "armored"},\n        },\n        ["Shiganshina (Col)"] = {\n            Map = "Shiganshina",\n            Objective = "Colossal Titan",\n            Minimum = 3,\n            Difficulties = {"Aberrant"},\n            Aliases = {"colossal titan", "colossal"},\n        },\n        ["Trost (Att)"] = {\n            Map = "Trost",\n            Objective = "Attack Titan",\n            Difficulties = {"Hard", "Severe", "Aberrant"},\n            Aliases = {"attack titan", "attack"},\n        },\n        ["Stohess (Female)"] = {\n            Map = "Stohess",\n            Objective = "Female Titan",\n            Difficulties = {"Hard", "Severe", "Aberrant"},\n            Aliases = {"female titan", "female"},\n        },\n    },\n}\n\n\nlocal Difficulties = {\n\t{Name = "Easy", Grade = "E-", Color = Color3.fromRGB(70, 220, 90)},\n\t{Name = "Normal", Grade = "E+", Color = Color3.fromRGB(150, 255, 80)},\n\t{Name = "Hard", Grade = "D+", Color = Color3.fromRGB(255, 220, 70)},\n\t{Name = "Severe", Grade = "B-", Color = Color3.fromRGB(170, 90, 255)},\n\t{Name = "Aberrant", Grade = "A-", Color = Color3.fromRGB(255, 80, 80)},\n}\n\nlocal DifficultyRank = {\n    Easy = 1,\n    Normal = 2,\n    Hard = 3,\n    Severe = 4,\n    Aberrant = 5,\n}\n\nV43RaidDifficultyGrade = {\n    Hard = "C-",\n    Severe = "B",\n    Aberrant = "A",\n}\n\nfunction V43RaidDifficultyAllowed(raidChoice, difficulty)\n    local raid = V401LobbyRaid.Data[tostring(raidChoice or "")]\n    if not raid then return false end\n\n    for _, allowed in ipairs(raid.Difficulties or {"Hard", "Severe", "Aberrant"}) do\n        if allowed == difficulty then return true end\n    end\n\n    return false\nend\n\nlocal Modifiers = {"No Perks", "No Skills", "No Memories", "Nightmare", "Oddball", "Injury Prone", "Chronic Injuries", "Fog", "Glass Cannon", "Time Trial", "Simple", "Boring"}\n\nlocal State = {\n\tCreateMode = "Mission",\n\tRaidChoice = "Shiganshina (Arm)",\n\tMap = "Shiganshina",\n\tObjective = "Skirmish",\n\tDifficulty = "Easy",\n\tModifiers = {},\n\tAutoStart = false,\n\tDelay = 0,\n}\n\nlocal Settings = {\n\tToggleKeyName = "RightShift", -- laptop-friendly default; change it in Settings tab\n\tAutoLoadConfig = false,\n\tAutoLoadConfigName = "",\n\tWeaponLoadoutMode = "Auto", -- Auto / Blades / Spears; lobby-only\n\tAutoWeaponSwitch = true, -- compatibility mirror for older settings files\n}\n\nlocal SavedConfigs = {}\nlocal SelectedConfig = nil\nlocal CurrentMode = "Unknown"\nlocal LastMode = "Unknown"\nlocal MenuOpen = true\nlocal CountdownToken = 0\n\nTheme = {\n\t-- V9.5.1: high-contrast lobby shell. Keep the mission GUI\'s graphite/blue\n\t-- language, but raise surface and text contrast for the bright lobby map.\n\tTop = Color3.fromRGB(20, 22, 29),\n\tBottom = Color3.fromRGB(14, 16, 22),\n\tPanel = Color3.fromRGB(28, 31, 41),\n\tPanel2 = Color3.fromRGB(21, 24, 32),\n\tCard = Color3.fromRGB(31, 35, 46),\n\tCardOn = Color3.fromRGB(42, 49, 66),\n\tStroke = Color3.fromRGB(79, 91, 116),\n\tAccent = Color3.fromRGB(89, 169, 255),\n\tAccent2 = Color3.fromRGB(139, 200, 255),\n\tText = Color3.fromRGB(248, 250, 255),\n\tMuted = Color3.fromRGB(202, 208, 222),\n\tDim = Color3.fromRGB(151, 160, 181),\n\tDanger = Color3.fromRGB(246, 103, 122),\n\tSuccess = Color3.fromRGB(100, 222, 171),\n\tWarn = Color3.fromRGB(241, 196, 79),\n}\n\nlocal function getEnv()\n\tlocal ok, env = pcall(function()\n\t\tif type(getgenv) == "function" then return getgenv() end\n\tend)\n\treturn (ok and type(env) == "table") and env or _G\nend\n\nlocal Env = getEnv()\n\n-- SliceHub build gates inside the lobby chunk. These read getgenv() directly so\n-- Free/Premium behavior still works even when this lobby code is executed as a\n-- separate loadstring chunk.\nlocal function SliceHubLobbyIsPremium()\n    local ok, env = pcall(function()\n        if type(getgenv) == "function" then return getgenv() end\n    end)\n    env = (ok and type(env) == "table") and env or _G\n    local hub = type(env.SliceHub) == "table" and env.SliceHub or nil\n    return hub and hub.IsPremium == true\nend\n\nfunction SliceHubLobbyFeatureEnabled(featureName)\n    local ok, env = pcall(function()\n        if type(getgenv) == "function" then return getgenv() end\n    end)\n    env = (ok and type(env) == "table") and env or _G\n    local hub = type(env.SliceHub) == "table" and env.SliceHub or nil\n    local profile = hub and type(hub.Profile) == "table" and hub.Profile or nil\n    local features = profile and type(profile.Features) == "table" and profile.Features or nil\n    local value = features and features[tostring(featureName or "")] or nil\n    if type(value) == "boolean" then return value end\n    return SliceHubLobbyIsPremium()\nend\n\nfunction SliceHubLobbyPrestigeThresholdsAllowed()\n    return SliceHubLobbyFeatureEnabled("PrestigeThresholds")\nend\n\nfunction SliceHubLobbyPrestigeBuffAllowed()\n    return SliceHubLobbyFeatureEnabled("PrestigeBuffSelection")\nend\n\nfunction SliceHubLobbyWavesAllowed()\n    return SliceHubLobbyFeatureEnabled("WaveAutomation")\n        and SliceHubLobbyIsPremium()\nend\n\nfunction SliceHubRaidChoiceAllowed(raidChoice)\n    raidChoice = tostring(raidChoice or "")\n    if raidChoice == "Shiganshina (Col)" then return true end\n    if SliceHubLobbyIsPremium() then return true end\n    return false\nend\n\nfunction SliceHubRaidRuntimeAllowed(raidName)\n    raidName = tostring(raidName or "")\n    if raidName == "Colossal Raid" then return true end\n    if SliceHubLobbyIsPremium() then return true end\n    if raidName == "Armored Raid" or raidName == "Attack Raid" or raidName == "Female Raid" then return false end\n    return true\nend\n\nfunction SliceHubRaidLockedReason(raidChoice)\n    raidChoice = tostring(raidChoice or "")\n    if raidChoice == "Shiganshina (Arm)" then return "Armored Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end\n    if raidChoice == "Trost (Att)" then return "Attack Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end\n    if raidChoice == "Stohess (Female)" then return "Female Raid is unsupported in the Free version. Free keeps Colossal Spears-only support." end\n    if raidChoice == "Shiganshina (Col)" then return "Colossal Raid is supported in both builds, but it is Spears-only." end\n    return "This raid is unsupported in the Free version."\nend\n\nfunction SliceHubRaidDisplayName(raidChoice)\n    raidChoice = tostring(raidChoice or "")\n    if raidChoice == "Shiganshina (Col)" then return raidChoice .. " \u{2022} Spears Only" end\n    if not SliceHubRaidChoiceAllowed(raidChoice) then return raidChoice .. " \u{1f512}" end\n    return raidChoice\nend\n\nfunction SliceHubClampAutoSkipCutscene(value)\n    return SliceHubLobbyIsPremium() and value == true or false\nend\n\nlocal readfileFn = type(Env.readfile) == "function" and Env.readfile or nil\nlocal writefileFn = type(Env.writefile) == "function" and Env.writefile or nil\n\n\n-- V9.5 Colossal policy: the tested route is Spears-only. Lobby reads the same\n-- persistent mission settings file before allowing a Colossal launch.\nV95LobbyWeaponPolicy = V95LobbyWeaponPolicy or {}\n\nfunction V95LobbyWeaponPolicy.Read()\n    if type(readfileFn) ~= "function" then\n        return false, false, "settings file access unavailable"\n    end\n\n    local okRead, raw = pcall(readfileFn, "TitanControlSettings_v101.json")\n    if not okRead or type(raw) ~= "string" or raw == "" then\n        return false, false, "mission settings not found"\n    end\n\n    local okDecode, document = pcall(function()\n        return HttpService:JSONDecode(raw)\n    end)\n    if not okDecode or type(document) ~= "table" then\n        return false, false, "mission settings unreadable"\n    end\n\n    local spears = type(document.Spears) == "table" and document.Spears or {}\n    local toggles = type(document.Toggles) == "table" and document.Toggles or {}\n    local spearReady = spears.SupportEnabled == true and spears.AutoFireEnabled ~= false\n    local bladesSaved = toggles.BladesEnabled == true or toggles.FarmEnabled == true\n    return spearReady, bladesSaved, spearReady and "ready" or "enable Spear Support + Auto Fire in the mission GUI"\nend\n\nfunction V95LobbyWeaponPolicy.ColossalReady()\n    local spearReady, bladesSaved, reason = V95LobbyWeaponPolicy.Read()\n    return spearReady == true, tostring(reason or "unknown"), bladesSaved == true\nend\n\nV5LobbyAutoExec = V5LobbyAutoExec or {}\n\nfunction V5LobbyAutoExec.Enabled()\n    if type(readfileFn) ~= "function" then return false end\n    local okRead, raw = pcall(readfileFn, "TitanControlSettings_v101.json")\n    if not okRead or type(raw) ~= "string" or raw == "" then return false end\n\n    local okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)\n    return okDecode\n        and type(decoded) == "table"\n        and type(decoded.Settings) == "table"\n        and decoded.Settings.AutoExecuteOnTeleport == true\nend\n\nfunction V5LobbyAutoExec.Queue()\n    if not V5LobbyAutoExec.Enabled() then return false end\n\n    local queueFn = Env.queue_on_teleport\n        or Env.queueonteleport\n        or Env.queue_on_tp\n        or (Env.syn and Env.syn.queue_on_teleport)\n\n    if type(queueFn) ~= "function" then return false end\n\n    local code = [[\nlocal loader = loadstring or load\nlocal source = nil\nif type(readfile) == "function" then\n    local ok, value = pcall(readfile, "SH/bootstrap.shc")\n    if ok then source = value end\nend\nif type(source) == "string" and type(loader) == "function" then\n    local chunk = loader(source)\n    if type(chunk) == "function" then chunk() end\nend\n]]\n\n    return pcall(queueFn, code)\nend\n\nif V5LobbyAutoExec.Connection then\n    pcall(function() V5LobbyAutoExec.Connection:Disconnect() end)\nend\n\nV5LobbyAutoExec.Connection = player.OnTeleport:Connect(function(state)\n    if state == Enum.TeleportState.RequestedFromServer\n        or state == Enum.TeleportState.Started then\n        pcall(V5LobbyAutoExec.Queue)\n    end\nend)\n\n-- V5.5 persistent Auto Raid Queue. Colossal is supported by the dedicated\n-- one-cannon P1 stall director and exact P2 Colossal boss lock.\nV51RaidQueue = V51RaidQueue or {\n    FileName = "AOT_RaidQueue_v51.json",\n    RaidOrder = {"Shiganshina (Arm)", "Shiganshina (Col)", "Trost (Att)", "Stohess (Female)"},\n    DifficultyOrder = {"Hard", "Severe", "Aberrant"},\n    UI = {},\n    AutoLaunchConsumed = false,\n}\n\nfunction V51RaidQueue.DefaultState()\n    return {\n        Version = 1,\n        Enabled = false,\n        RepeatQueue = false,\n        FailurePolicy = "Retry",\n        MaxRetries = 3,\n        CurrentRetries = 0,\n        Index = 1,\n        EntryDone = 0,\n        TotalCompleted = 0,\n        TotalFailed = 0,\n        LastResult = "None",\n        Modifiers = {},\n        Entries = {\n            {RaidChoice = "Shiganshina (Arm)", Difficulty = "Aberrant", Runs = 3},\n            {RaidChoice = "Trost (Att)", Difficulty = "Severe", Runs = 5},\n            {RaidChoice = "Stohess (Female)", Difficulty = "Aberrant", Runs = 2},\n        },\n    }\nend\n\nfunction V51RaidQueue.Normalize(document)\n    local base = V51RaidQueue.DefaultState()\n    document = type(document) == "table" and document or {}\n    base.Enabled = document.Enabled == true\n    base.RepeatQueue = document.RepeatQueue == true\n    local policy = tostring(document.FailurePolicy or "Retry")\n    if policy ~= "Retry" and policy ~= "Skip" and policy ~= "Stop" then policy = "Retry" end\n    base.FailurePolicy = policy\n    base.MaxRetries = math.clamp(math.floor((tonumber(document.MaxRetries) or 3) + 0.5), 0, 10)\n    base.CurrentRetries = math.clamp(math.floor((tonumber(document.CurrentRetries) or 0) + 0.5), 0, 99)\n    base.Index = math.max(1, math.floor((tonumber(document.Index) or 1) + 0.5))\n    base.EntryDone = math.max(0, math.floor((tonumber(document.EntryDone) or 0) + 0.5))\n    base.TotalCompleted = math.max(0, math.floor((tonumber(document.TotalCompleted) or 0) + 0.5))\n    base.TotalFailed = math.max(0, math.floor((tonumber(document.TotalFailed) or 0) + 0.5))\n    base.LastResult = tostring(document.LastResult or "None")\n    base.Modifiers = type(document.Modifiers) == "table" and document.Modifiers or {}\n\n    if type(document.Entries) == "table" then\n        for index = 1, 3 do\n            local source = document.Entries[index]\n            if type(source) == "table" then\n                local raid = tostring(source.RaidChoice or base.Entries[index].RaidChoice)\n                if not table.find(V51RaidQueue.RaidOrder, raid) then raid = base.Entries[index].RaidChoice end\n                local difficulty = tostring(source.Difficulty or base.Entries[index].Difficulty)\n                if not table.find(V51RaidQueue.DifficultyOrder, difficulty) then difficulty = "Aberrant" end\n                if raid == "Shiganshina (Col)" then difficulty = "Aberrant" end\n                base.Entries[index] = {\n                    RaidChoice = raid,\n                    Difficulty = difficulty,\n                    Runs = math.clamp(math.floor((tonumber(source.Runs) or base.Entries[index].Runs) + 0.5), 1, 99),\n                }\n            end\n        end\n    end\n\n    if base.Index > #base.Entries then base.Index = #base.Entries end\n\n    if type(SliceHubFeatureEnabled) == "function"\n        and not SliceHubFeatureEnabled("AutoRaidQueue") then\n        base.Enabled = false\n        base.RepeatQueue = false\n        base.CurrentRetries = 0\n        base.LastResult = "Premium Locked"\n    end\n\n    return base\nend\n\nfunction V51RaidQueue.Load()\n    local document = nil\n    if readfileFn then\n        local ok, raw = pcall(readfileFn, V51RaidQueue.FileName)\n        if ok and type(raw) == "string" and raw ~= "" then\n            local decodedOk, decoded = pcall(function() return HttpService:JSONDecode(raw) end)\n            if decodedOk then document = decoded end\n        end\n    end\n    V51RaidQueue.State = V51RaidQueue.Normalize(document)\n    return V51RaidQueue.State\nend\n\nfunction V51RaidQueue.Save()\n    V51RaidQueue.State = V51RaidQueue.Normalize(V51RaidQueue.State)\n    if writefileFn then\n        local okEncode, encoded = pcall(function() return HttpService:JSONEncode(V51RaidQueue.State) end)\n        if okEncode then pcall(writefileFn, V51RaidQueue.FileName, encoded) end\n    end\n    return V51RaidQueue.State\nend\n\nfunction V51RaidQueue.CurrentEntry()\n    local state = V51RaidQueue.State or V51RaidQueue.Load()\n    return state.Entries[state.Index], state\nend\n\nfunction V51RaidQueue.ApplyCurrentToLobbyState()\n    local entry, queue = V51RaidQueue.CurrentEntry()\n    if not entry or not queue.Enabled then return false end\n    State.CreateMode = "Raid"\n    State.RaidChoice = entry.RaidChoice\n    State.Difficulty = entry.Difficulty\n    State.Modifiers = {}\n    if type(queue.Modifiers) == "table" then\n        for _, modifier in ipairs(queue.Modifiers) do\n            State.Modifiers[#State.Modifiers + 1] = tostring(modifier)\n        end\n    end\n    State.AutoStart = false\n    State.Delay = 0\n    return true\nend\n\nV51RaidQueue.Load()\nV51RaidQueue.AutoLaunchConsumed = false\n\nlocal function copy(value)\n\treturn HttpService:JSONDecode(HttpService:JSONEncode(value))\nend\n\nlocal function cleanName(value)\n\tlocal raw = tostring(value or "")\n\tlocal kept = {}\n\tfor index = 1, #raw do\n\t\tlocal byte = string.byte(raw, index)\n\t\tif byte and byte >= 32 and byte ~= 127 then\n\t\t\tkept[#kept + 1] = string.sub(raw, index, index)\n\t\tend\n\tend\n\tlocal text = table.concat(kept)\n\ttext = string.gsub(text, "^%s+", "")\n\ttext = string.gsub(text, "%s+$", "")\n\treturn string.sub(text, 1, 24)\nend\n\nlocal function diffInfo(name)\n\tfor _, info in ipairs(Difficulties) do\n\t\tif info.Name == name then return info end\n\tend\n\treturn Difficulties[1]\nend\n\nlocal function difficultyGradeForMode(mode, difficulty)\n    if tostring(mode or "Mission") == "Raid" then\n        return V43RaidDifficultyGrade[tostring(difficulty or "")] or "?"\n    end\n    return diffInfo(difficulty).Grade\nend\n\nlocal function modSet()\n\tlocal set = {}\n\tfor _, name in ipairs(State.Modifiers) do set[name] = true end\n\treturn set\nend\n\nlocal function modsText(mods)\n\tmods = mods or State.Modifiers\n\tif #mods == 0 then return "None" end\n\treturn table.concat(mods, ", ")\nend\n\nlocal function normalizeConfig(data)\n\tdata = type(data) == "table" and data or {}\n\n\tlocal createMode = tostring(data.CreateMode or data.Mode or "Mission")\n\tif createMode ~= "Raid" and createMode ~= "Waves" then\n\t\tcreateMode = "Mission"\n\tend\n\n\tlocal raidChoice = tostring(data.RaidChoice or "Shiganshina (Arm)")\n\tif not V401LobbyRaid.Data[raidChoice] then\n\t\tfor choice, info in pairs(V401LobbyRaid.Data) do\n\t\t\tif tostring(data.Map or "") == info.Map\n\t\t\t\tand tostring(data.Objective or "") == info.Objective then\n\t\t\t\traidChoice = choice\n\t\t\t\tbreak\n\t\t\tend\n\t\tend\n\tend\n\tif not V401LobbyRaid.Data[raidChoice] then raidChoice = "Shiganshina (Arm)" end\n\n    if createMode == "Raid" and type(SliceHubRaidChoiceAllowed) == "function" and not SliceHubRaidChoiceAllowed(raidChoice) then\n        raidChoice = "Shiganshina (Col)"\n    end\n\n\tlocal map\n\tlocal objective\n\n\tif createMode == "Raid" then\n\t\tlocal raid = V401LobbyRaid.Data[raidChoice]\n\t\tmap = raid.Map\n\t\tobjective = raid.Objective\n\telseif createMode == "Waves" then\n\t\tmap = "Trost"\n\t\tobjective = "Waves"\n\telse\n\t\tmap = tostring(data.Map or "Shiganshina")\n\t\tif not MissionData[map] then map = "Shiganshina" end\n\n\t\tobjective = tostring(data.Objective or MissionData[map][1])\n\t\tlocal okObjective = false\n\t\tfor _, obj in ipairs(MissionData[map]) do\n\t\t\tif obj == objective then okObjective = true break end\n\t\tend\n\t\tif not okObjective then objective = MissionData[map][1] end\n\tend\n\n\tlocal difficulty = tostring(data.Difficulty or "Easy")\n\tlocal okDifficulty = false\n\tfor _, d in ipairs(Difficulties) do if d.Name == difficulty then okDifficulty = true end end\n\tif not okDifficulty then difficulty = "Easy" end\n\tif createMode == "Waves" then difficulty = "Easy" end\n\n\tlocal minimum = nil\n\tif createMode == "Raid" then\n\t\tlocal raid = V401LobbyRaid.Data[raidChoice]\n\t\tminimum = raid and tonumber(raid.Minimum) or nil\n\n        if not V43RaidDifficultyAllowed(raidChoice, difficulty) then\n            difficulty = raidChoice == "Shiganshina (Col)" and "Aberrant" or "Hard"\n        end\n\tend\n\n\tlocal allowed = {}\n\tfor _, m in ipairs(Modifiers) do allowed[m] = true end\n\tlocal mods = {}\n\tif createMode ~= "Waves" and type(data.Modifiers) == "table" then\n\t\tfor _, m in ipairs(data.Modifiers) do\n\t\t\tm = tostring(m)\n\t\t\tif allowed[m] then table.insert(mods, m) end\n\t\tend\n\tend\n\n\treturn {\n\t\tCreateMode = createMode,\n\t\tRaidChoice = raidChoice,\n\t\tMap = map,\n\t\tObjective = objective,\n\t\tDifficulty = difficulty,\n\t\tMinimum = minimum,\n\t\tModifiers = mods,\n\t\tAutoStart = data.AutoStart == true,\n\t\tDelay = math.clamp(math.floor((tonumber(data.Delay) or 0) + 0.5), 0, 30),\n\t}\nend\n\nlocal function captureConfig()\n\treturn normalizeConfig(State)\nend\n\n\n---------------------------------------------------------------------\n-- V2.2 LEARNED REMOTE FAST PATH\n---------------------------------------------------------------------\n\nlocal RemoteTraceStore = {Version = 1, Configs = {}}\n\nlocal RemoteTrace = {\n    Active = false,\n    Replaying = false,\n    Records = {},\n    StartedAt = 0,\n    CurrentSignature = nil,\n    TeleportSeen = false,\n    HookInstalled = false,\n}\n\nlocal function stableTraceConfig(config)\n    local modifiers = {}\n    for _, modifier in ipairs(config.Modifiers or {}) do\n        modifiers[#modifiers + 1] = tostring(modifier)\n    end\n    table.sort(modifiers)\n\n    return {\n        CreateMode = tostring(config.CreateMode or "Mission"),\n        RaidChoice = tostring(config.RaidChoice or ""),\n        Map = tostring(config.Map or ""),\n        Objective = tostring(config.Objective or ""),\n        Difficulty = tostring(config.Difficulty or ""),\n        Minimum = tonumber(config.Minimum),\n        Modifiers = modifiers,\n    }\nend\n\nlocal function traceConfigSignature(config)\n    local ok, encoded = pcall(function()\n        return HttpService:JSONEncode(stableTraceConfig(config))\n    end)\n    return ok and encoded or tostring(config.CreateMode) .. "|" .. tostring(config.Map) .. "|" .. tostring(config.Objective)\nend\n\nlocal function loadRemoteTraceStore()\n    if not readfileFn then return end\n    local okRead, raw = pcall(readfileFn, MissionRemoteTraceFileName)\n    if not okRead or type(raw) ~= "string" or raw == "" then return end\n\n    local okDecode, decoded = pcall(function()\n        return HttpService:JSONDecode(raw)\n    end)\n\n    if okDecode and type(decoded) == "table" and type(decoded.Configs) == "table" then\n        RemoteTraceStore = decoded\n    end\nend\n\nlocal function saveRemoteTraceStore()\n    if not writefileFn then return end\n\n    local okEncode, encoded = pcall(function()\n        return HttpService:JSONEncode(RemoteTraceStore)\n    end)\n\n    if okEncode and type(encoded) == "string" then\n        pcall(writefileFn, MissionRemoteTraceFileName, encoded)\n    end\nend\n\nlocal function serializeRemoteValue(value, depth)\n    depth = depth or 0\n    if depth > 6 then return nil, false end\n\n    local kind = typeof(value)\n\n    if value == nil then\n        return {__type = "nil"}, true\n    elseif kind == "boolean" or kind == "number" or kind == "string" then\n        return value, true\n    elseif kind == "Vector3" then\n        return {__type = "Vector3", x = value.X, y = value.Y, z = value.Z}, true\n    elseif kind == "Vector2" then\n        return {__type = "Vector2", x = value.X, y = value.Y}, true\n    elseif kind == "Color3" then\n        return {__type = "Color3", r = value.R, g = value.G, b = value.B}, true\n    elseif kind == "CFrame" then\n        return {__type = "CFrame", components = {value:GetComponents()}}, true\n    elseif kind == "table" then\n        local output = {__type = "Table", values = {}}\n        for key, child in pairs(value) do\n            if type(key) ~= "string" and type(key) ~= "number" then\n                return nil, false\n            end\n\n            local encoded, safe = serializeRemoteValue(child, depth + 1)\n            if not safe then return nil, false end\n            output.values[tostring(key)] = encoded\n        end\n        return output, true\n    end\n\n    return nil, false\nend\n\nlocal function deserializeRemoteValue(value)\n    if type(value) ~= "table" or value.__type == nil then\n        return value\n    end\n\n    if value.__type == "nil" then\n        return nil\n    elseif value.__type == "Vector3" then\n        return Vector3.new(value.x or 0, value.y or 0, value.z or 0)\n    elseif value.__type == "Vector2" then\n        return Vector2.new(value.x or 0, value.y or 0)\n    elseif value.__type == "Color3" then\n        return Color3.new(value.r or 0, value.g or 0, value.b or 0)\n    elseif value.__type == "CFrame" then\n        return CFrame.new(table.unpack(value.components or {}))\n    elseif value.__type == "Table" then\n        local output = {}\n        for key, child in pairs(value.values or {}) do\n            local numericKey = tonumber(key)\n            output[numericKey or key] = deserializeRemoteValue(child)\n        end\n        return output\n    end\n\n    return value\nend\n\nlocal function persistCurrentTrace()\n    local signature = RemoteTrace.CurrentSignature\n    if not signature or #RemoteTrace.Records == 0 then return end\n\n    local safe = true\n    for _, record in ipairs(RemoteTrace.Records) do\n        if record.Safe ~= true then\n            safe = false\n            break\n        end\n    end\n\n    RemoteTraceStore.Configs = RemoteTraceStore.Configs or {}\n    RemoteTraceStore.Configs[signature] = {\n        UpdatedAt = os.time(),\n        Safe = safe,\n        Records = copy(RemoteTrace.Records),\n    }\n\n    saveRemoteTraceStore()\nend\n\nlocal function beginRemoteTrace(config)\n    RemoteTrace.Active = true\n    RemoteTrace.Replaying = false\n    RemoteTrace.Records = {}\n    RemoteTrace.StartedAt = os.clock()\n    RemoteTrace.CurrentSignature = traceConfigSignature(config)\n    RemoteTrace.TeleportSeen = false\nend\n\nlocal function endRemoteTrace()\n    RemoteTrace.Active = false\n    persistCurrentTrace()\nend\n\nplayer.OnTeleport:Connect(function()\n    RemoteTrace.TeleportSeen = true\n    if RemoteTrace.Active then\n        task.defer(persistCurrentTrace)\n    end\nend)\n\nlocal function installMissionRemoteTraceHook()\n    if RemoteTrace.HookInstalled then return true end\n\n    local hookFn = Env.hookmetamethod or hookmetamethod\n    local getMethodFn = Env.getnamecallmethod or getnamecallmethod\n    local closureFn = Env.newcclosure or newcclosure\n\n    if type(hookFn) ~= "function" or type(getMethodFn) ~= "function" then\n        print("[LobbyCreator V2.2] Remote hook unavailable; Turbo UI only.")\n        return false\n    end\n\n    local oldNamecall\n    local okHook = pcall(function()\n        local wrapper = function(self, ...)\n            local method = getMethodFn()\n            local shouldRecord =\n                RemoteTrace.Active\n                and not RemoteTrace.Replaying\n                and (method == "FireServer" or method == "InvokeServer")\n                and typeof(self) == "Instance"\n                and (self.Name == "POST" or self.Name == "GET")\n                and string.find(self:GetFullName(), "Assets.Remotes", 1, true) ~= nil\n\n            if shouldRecord then\n                local argumentCount = select("#", ...)\n                local encodedArgs = {}\n                local safe = true\n\n                for index = 1, argumentCount do\n                    local encoded, argSafe = serializeRemoteValue(select(index, ...), 0)\n                    if not argSafe then\n                        safe = false\n                        break\n                    end\n                    encodedArgs[index] = encoded\n                end\n\n                RemoteTrace.Records[#RemoteTrace.Records + 1] = {\n                    Remote = self.Name,\n                    Method = method,\n                    Delay = math.max(0, os.clock() - RemoteTrace.StartedAt),\n                    ArgCount = argumentCount,\n                    Args = encodedArgs,\n                    Safe = safe,\n                }\n\n                task.defer(persistCurrentTrace)\n            end\n\n            return oldNamecall(self, ...)\n        end\n\n        if type(closureFn) == "function" then\n            wrapper = closureFn(wrapper)\n        end\n\n        oldNamecall = hookFn(game, "__namecall", wrapper)\n    end)\n\n    RemoteTrace.HookInstalled = okHook\n\n    if okHook then\n        print("[LobbyCreator V2.2] Learned remote trace hook ready.")\n    else\n        warn("[LobbyCreator V2.2] Remote hook failed; Turbo UI only.")\n    end\n\n    return okHook\nend\n\nlocal function getMissionRemote(name)\n    local replicatedStorage = game:GetService("ReplicatedStorage")\n    local assets = replicatedStorage:FindFirstChild("Assets")\n    local remotes = assets and assets:FindFirstChild("Remotes")\n    return remotes and remotes:FindFirstChild(name)\nend\n\nlocal function tryLearnedRemoteLaunch(config)\n    local signature = traceConfigSignature(config)\n    local trace = RemoteTraceStore.Configs and RemoteTraceStore.Configs[signature]\n\n    if type(trace) ~= "table"\n        or trace.Safe ~= true\n        or type(trace.Records) ~= "table"\n        or #trace.Records == 0 then\n        return false, "no safe learned trace"\n    end\n\n    RemoteTrace.Replaying = true\n    RemoteTrace.TeleportSeen = false\n\n    print("[LobbyCreator V2.2] Trying learned remote path:", #trace.Records, "calls")\n\n    local previousDelay = 0\n    local replayOk = true\n\n    for _, record in ipairs(trace.Records) do\n        local remote = getMissionRemote(record.Remote)\n        if not remote then\n            replayOk = false\n            break\n        end\n\n        local originalDelay = tonumber(record.Delay) or previousDelay\n        local delta = math.max(0, originalDelay - previousDelay)\n        previousDelay = originalDelay\n\n        task.wait(math.min(0.08, delta * 0.18))\n\n        local args = {}\n        local argCount = tonumber(record.ArgCount) or 0\n\n        for index = 1, argCount do\n            args[index] = deserializeRemoteValue((record.Args or {})[index])\n        end\n\n        local okCall = pcall(function()\n            if record.Method == "InvokeServer" and remote:IsA("RemoteFunction") then\n                remote:InvokeServer(table.unpack(args, 1, argCount))\n            elseif record.Method == "FireServer" and remote:IsA("RemoteEvent") then\n                remote:FireServer(table.unpack(args, 1, argCount))\n            else\n                error("remote method/class mismatch")\n            end\n        end)\n\n        if not okCall then\n            replayOk = false\n            break\n        end\n    end\n\n    RemoteTrace.Replaying = false\n\n    if not replayOk then\n        return false, "replay error"\n    end\n\n    local started = os.clock()\n    while os.clock() - started < 1.35 do\n        if RemoteTrace.TeleportSeen then\n            return true, "teleport detected"\n        end\n        task.wait(0.04)\n    end\n\n    return false, "no teleport"\nend\n\nlocal function turboWaitUntil(predicate, timeout, interval)\n    local started = os.clock()\n    repeat\n        local ok, result = pcall(predicate)\n        if ok and result then return true end\n        task.wait(interval or 0.025)\n    until os.clock() - started >= (timeout or 0.6)\n\n    return false\nend\n\n\n---------------------------------------------------------------------\n-- V3 EXACT MISSION ENGINE\n-- V3.0.1 register-pressure hotfix:\n-- all Exact Engine helpers live on one namespace table rather than\n-- consuming many top-level local registers in this already huge chunk.\n---------------------------------------------------------------------\n\nV3ExactMissionEngine = {\n    Busy = false,\n    TeleportSeen = false,\n    LastStage = "Idle",\n    LastError = nil,\n\n    InternalMapNames = {\n        ["Shiganshina"] = "Shiganshina",\n        ["Trost"] = "Trost",\n        ["Outskirts"] = "Outskirts",\n        ["Giant Forest"] = "Forest",\n        ["Utgard Castle"] = "Utgard",\n        ["Loading Docks"] = "Docks",\n        ["Stohess"] = "Stohess",\n        ["Chapel"] = "Chapel",\n    },\n}\n\nfunction V3ExactMissionEngine.Remote()\n    local replicatedStorage = game:GetService("ReplicatedStorage")\n    local assets = replicatedStorage:FindFirstChild("Assets")\n    local remotes = assets and assets:FindFirstChild("Remotes")\n    local remote = remotes and remotes:FindFirstChild("GET")\n\n    if remote and remote:IsA("RemoteFunction") then\n        return remote\n    end\n\n    return nil\nend\n\nfunction V3ExactMissionEngine.BuildPayload(config)\n    config = type(config) == "table" and config or {}\n\n    if tostring(config.CreateMode or "Mission") == "Waves" then\n        return {\n            Name = "Trost",\n            Difficulty = "Easy",\n            Type = "Waves",\n            Objective = "Waves",\n        }\n    end\n\n    if tostring(config.CreateMode or "Mission") == "Raid" then\n        local raid = V401LobbyRaid.Data[tostring(config.RaidChoice or "")]\n        local mapName = raid and raid.Map or tostring(config.Map or "Shiganshina")\n        local objective = raid and raid.Objective or tostring(config.Objective or "Armored Titan")\n        local minimum = raid and tonumber(raid.Minimum) or tonumber(config.Minimum)\n        local difficulty = tostring(config.Difficulty or "Hard")\n\n        if not V43RaidDifficultyAllowed(config.RaidChoice, difficulty) then\n            difficulty = tostring(config.RaidChoice or "") == "Shiganshina (Col)"\n                and "Aberrant"\n                or "Hard"\n        end\n\n        return {\n            Name = tostring(mapName),\n            Difficulty = difficulty,\n            Type = "Raids",\n            Objective = tostring(objective),\n            Minimum = minimum,\n        }\n    end\n\n    return {\n        Name = V3ExactMissionEngine.InternalMapNames[tostring(config.Map or "")]\n            or tostring(config.Map or "Shiganshina"),\n        Difficulty = tostring(config.Difficulty or "Easy"),\n        Type = "Missions",\n        Objective = tostring(config.Objective or "Skirmish"),\n    }\nend\n\nfunction V3ExactMissionEngine.Invoke(action, ...)\n    local remote = V3ExactMissionEngine.Remote()\n    if not remote then\n        return false, nil, "GET RemoteFunction missing"\n    end\n\n    local args = table.pack(...)\n    local ok, result = pcall(function()\n        return remote:InvokeServer(\n            "S_Missions",\n            action,\n            table.unpack(args, 1, args.n)\n        )\n    end)\n\n    if not ok then\n        return false, nil, tostring(result)\n    end\n\n    return true, result, nil\nend\n\nplayer.OnTeleport:Connect(function()\n    V3ExactMissionEngine.TeleportSeen = true\nend)\n\nfunction V3ExactMissionEngine.TeleportStarted()\n    if V3ExactMissionEngine.TeleportSeen then\n        return true\n    end\n\n    local value = player:GetAttribute("Teleporting")\n    return value ~= nil and value ~= false\nend\n\nfunction V3ExactMissionEngine.Cleanup()\n    pcall(function()\n        V3ExactMissionEngine.Invoke("Leave")\n    end)\nend\n\nfunction V3ExactMissionEngine.TryLaunch(config)\n    config = type(config) == "table" and config or {}\n\n    if tostring(config.CreateMode or "") == "Waves"\n        and not SliceHubLobbyWavesAllowed() then\n        return false, "This tab unlocks only when you have Premium."\n    end\n\n    if tostring(config.CreateMode or "") == "Raid"\n        and type(SliceHubRaidChoiceAllowed) == "function"\n        and not SliceHubRaidChoiceAllowed(config.RaidChoice) then\n        local reason = type(SliceHubRaidLockedReason) == "function"\n            and SliceHubRaidLockedReason(config.RaidChoice)\n            or "This raid is unsupported in the Free version."\n        warn("[SliceHub Free] " .. tostring(reason))\n        return false, tostring(reason)\n    end\n\n    if V3ExactMissionEngine.Busy then\n        return false, "exact engine busy"\n    end\n\n    V3ExactMissionEngine.Busy = true\n    V3ExactMissionEngine.TeleportSeen = false\n    V3ExactMissionEngine.LastError = nil\n    V3ExactMissionEngine.LastStage = "Create"\n\n    local function fail(reason, created)\n        V3ExactMissionEngine.LastError = tostring(reason)\n        V3ExactMissionEngine.LastStage = "Failed"\n\n        if created then\n            V3ExactMissionEngine.Cleanup()\n        end\n\n        V3ExactMissionEngine.Busy = false\n        return false, tostring(reason)\n    end\n\n    local payload = V3ExactMissionEngine.BuildPayload(config)\n    print("[Slice V4.2][EXACT] CREATE", HttpService:JSONEncode(payload))\n\n    local createOk, createdMission, createErr =\n        V3ExactMissionEngine.Invoke("Create", payload)\n\n    if not createOk then\n        return fail("Create invoke failed: " .. tostring(createErr), false)\n    end\n\n    local wavesMode = tostring(config.CreateMode or "") == "Waves"\n\n    -- Waves Create is server-accepted even when the RemoteFunction returns nil\n    -- or the map name. Missions/Raids keep their older strict validation.\n    if not wavesMode then\n        if createdMission == nil then\n            return fail("Create returned nil", false)\n        end\n\n        if type(createdMission) == "string" then\n            return fail("Create rejected: " .. tostring(createdMission), false)\n        end\n    end\n\n    task.wait(0.045)\n\n    V3ExactMissionEngine.LastStage = "Modifiers"\n\n    for _, modifierName in ipairs(config.Modifiers or {}) do\n        local modifyOk, enabled, modifyErr =\n            V3ExactMissionEngine.Invoke("Modify", tostring(modifierName))\n\n        if not modifyOk then\n            return fail(\n                "Modify failed for "\n                    .. tostring(modifierName)\n                    .. ": "\n                    .. tostring(modifyErr),\n                true\n            )\n        end\n\n        if enabled == nil then\n            return fail(\n                "Modify returned nil for " .. tostring(modifierName),\n                true\n            )\n        end\n\n        print(\n            "[Slice V4.2][EXACT] MODIFY",\n            tostring(modifierName),\n            "=>",\n            tostring(enabled)\n        )\n\n        task.wait(0.018)\n    end\n\n    V3ExactMissionEngine.LastStage = "Start"\n\n    local startOk, _, startErr = V3ExactMissionEngine.Invoke("Start")\n\n    if not startOk then\n        return fail("Start invoke failed: " .. tostring(startErr), true)\n    end\n\n    local startedAt = os.clock()\n\n    while os.clock() - startedAt < 3.0 do\n        if V3ExactMissionEngine.TeleportStarted() then\n            V3ExactMissionEngine.LastStage = "Teleporting"\n            V3ExactMissionEngine.Busy = false\n            return true, "exact direct launch"\n        end\n\n        task.wait(0.035)\n    end\n\n    return fail("Start sent but teleport was not detected", true)\nend\n\nloadRemoteTraceStore()\ninstallMissionRemoteTraceHook()\n\nlocal function applyConfig(config)\n\tlocal c = normalizeConfig(config)\n\tState.CreateMode = c.CreateMode\n\tState.RaidChoice = c.RaidChoice\n\tState.Map = c.Map\n\tState.Objective = c.Objective\n\tState.Difficulty = c.Difficulty\n\tState.Modifiers = c.Modifiers\n\tState.AutoStart = c.AutoStart\n\tState.Delay = c.Delay\nend\n\nlocal function saveConfigs()\n\tlocal doc = {Version = 11, Configs = SavedConfigs}\n\tif writefileFn then\n\t\tlocal okEncode, encoded = pcall(function() return HttpService:JSONEncode(doc) end)\n\t\tif not okEncode then return false, "JSON encode failed" end\n\t\tlocal okWrite = pcall(writefileFn, SaveFileName, encoded)\n\t\tif not okWrite then return false, "File write failed" end\n\t\treturn true, "Saved to file"\n\tend\n\tEnv.LobbyCreatorDebugConfigs_v11 = doc\n\treturn true, "Saved for this session"\nend\n\nlocal function loadConfigs()\n\tlocal doc = nil\n\tif readfileFn then\n\t\tlocal okRead, raw = pcall(readfileFn, SaveFileName)\n\t\tif okRead and type(raw) == "string" and raw ~= "" then\n\t\t\tlocal okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)\n\t\t\tif okDecode and type(decoded) == "table" then doc = decoded end\n\t\tend\n\telseif type(Env.LobbyCreatorDebugConfigs_v11) == "table" then\n\t\tdoc = Env.LobbyCreatorDebugConfigs_v11\n\tend\n\tif type(doc) ~= "table" then return end\n\tSavedConfigs = {}\n\tlocal configs = type(doc.Configs) == "table" and doc.Configs or doc\n\tfor name, config in pairs(configs) do\n\t\tlocal clean = cleanName(name)\n\t\tif clean ~= "" then SavedConfigs[clean] = normalizeConfig(config) end\n\tend\nend\n\nlocal function normalizeSettings(data)\n\tdata = type(data) == "table" and data or {}\n\n\tlocal keyName = tostring(data.ToggleKeyName or Settings.ToggleKeyName or "RightShift")\n\tif not Enum.KeyCode[keyName] or keyName == "Unknown" then\n\t\tkeyName = "RightShift"\n\tend\n\n\tlocal autoName = cleanName(data.AutoLoadConfigName or "")\n\tif autoName ~= "" and not SavedConfigs[autoName] then\n\t\tautoName = ""\n\tend\n\n\tlocal loadoutMode = tostring(data.WeaponLoadoutMode or "")\n\tif loadoutMode ~= "Auto" and loadoutMode ~= "Blades" and loadoutMode ~= "Spears" then\n\t\t-- V9.8.2.6 migration: old builds only had a hidden AutoWeaponSwitch boolean.\n\t\t-- Missing/legacy values now default to the visible AUTO loadout mode.\n\t\tloadoutMode = "Auto"\n\tend\n\n\treturn {\n\t\tToggleKeyName = keyName,\n\t\tAutoLoadConfig = data.AutoLoadConfig == true,\n\t\tAutoLoadConfigName = autoName,\n\t\tWeaponLoadoutMode = loadoutMode,\n\t\tAutoWeaponSwitch = loadoutMode == "Auto",\n\t}\nend\n\nlocal function saveSettings()\n\tlocal doc = {\n\t\tVersion = 13,\n\t\tSettings = normalizeSettings(Settings),\n\t}\n\n\tif writefileFn then\n\t\tlocal okEncode, encoded = pcall(function() return HttpService:JSONEncode(doc) end)\n\t\tif not okEncode then return false, "JSON encode failed" end\n\n\t\tlocal okWrite = pcall(writefileFn, SettingsFileName, encoded)\n\t\tif not okWrite then return false, "File write failed" end\n\t\treturn true, "Saved to file"\n\tend\n\n\tEnv.LobbyCreatorStatusSettings_v13 = doc\n\treturn true, "Saved for this session"\nend\n\nlocal function loadSettings()\n\tlocal doc = nil\n\n\tif readfileFn then\n\t\tlocal okRead, raw = pcall(readfileFn, SettingsFileName)\n\t\tif okRead and type(raw) == "string" and raw ~= "" then\n\t\t\tlocal okDecode, decoded = pcall(function() return HttpService:JSONDecode(raw) end)\n\t\t\tif okDecode and type(decoded) == "table" then doc = decoded end\n\t\tend\n\telseif type(Env.LobbyCreatorStatusSettings_v13) == "table" then\n\t\tdoc = Env.LobbyCreatorStatusSettings_v13\n\telseif type(Env.LobbyCreatorStatusSettings_v12) == "table" then\n\t\tdoc = Env.LobbyCreatorStatusSettings_v12\n\tend\n\n\tif type(doc) == "table" then\n\t\tSettings = normalizeSettings(type(doc.Settings) == "table" and doc.Settings or doc)\n\telse\n\t\tSettings = normalizeSettings(Settings)\n\tend\nend\n\nlocal function getToggleKeyCode()\n\tlocal keyName = tostring(Settings.ToggleKeyName or "RightShift")\n\treturn Enum.KeyCode[keyName] or Enum.KeyCode.RightShift\nend\n\nloadConfigs()\nloadSettings()\n\nif Settings.AutoLoadConfig and Settings.AutoLoadConfigName ~= "" and SavedConfigs[Settings.AutoLoadConfigName] then\n\tapplyConfig(SavedConfigs[Settings.AutoLoadConfigName])\n\tSelectedConfig = Settings.AutoLoadConfigName\nend\n\nlocal old = playerGui:FindFirstChild("LobbyCreator") or playerGui:FindFirstChild("LobbyCreatorStatus")\nif old then old:Destroy() end\n\nlocal gui = Instance.new("ScreenGui")\ngui.Name = "LobbyCreator"\ngui.ResetOnSpawn = false\ngui.IgnoreGuiInset = true\ngui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling\n-- Match the mission shell\'s rendering priority so native lobby overlays cannot\n-- wash out or dim Slice Hub controls.\ngui.DisplayOrder = 9999\ngui.Enabled = true\ngui.Parent = playerGui\n\nlocal function corner(parent, r)\n\tlocal c = Instance.new("UICorner")\n\tc.CornerRadius = UDim.new(0, r or 10)\n\tc.Parent = parent\n\treturn c\nend\n\nlocal function stroke(parent, color, transparency)\n\tlocal s = Instance.new("UIStroke")\n\ts.Color = color or Theme.Stroke\n\ts.Transparency = transparency or 0.35\n\ts.Thickness = 1\n\ts.Parent = parent\n\treturn s\nend\n\nlocal function tw(obj, props, time)\n\tlocal t = TweenService:Create(obj, TweenInfo.new(time or 0.18, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), props)\n\tt:Play()\n\treturn t\nend\n\nlocal notifyHolder = Instance.new("Frame")\nnotifyHolder.AnchorPoint = Vector2.new(1, 0)\nnotifyHolder.Position = UDim2.new(1, -18, 0, 18)\nnotifyHolder.Size = UDim2.fromOffset(310, 300)\nnotifyHolder.BackgroundTransparency = 1\nnotifyHolder.ZIndex = 100\nnotifyHolder.Parent = gui\n\nlocal notifyLayout = Instance.new("UIListLayout")\nnotifyLayout.Padding = UDim.new(0, 8)\nnotifyLayout.HorizontalAlignment = Enum.HorizontalAlignment.Right\nnotifyLayout.SortOrder = Enum.SortOrder.LayoutOrder\nnotifyLayout.Parent = notifyHolder\n\nlocal toastOrder = 0\nlocal function notify(title, message, kind)\n\ttoastOrder += 1\n\tlocal accent = kind == "error" and Theme.Danger or (kind == "success" and Theme.Success or Theme.Accent2)\n\tlocal toast = Instance.new("CanvasGroup")\n\ttoast.LayoutOrder = toastOrder\n\ttoast.Size = UDim2.fromOffset(292, 62)\n\ttoast.Position = UDim2.fromOff