siting the whole group too dark; a Frame keeps child text at\n-- full contrast while preserving the same hierarchy and clipping behavior.\nlocal window = Instance.new("Frame")\nwindow.AnchorPoint = Vector2.new(0.5, 0.5)\nwindow.Position = UDim2.fromScale(0.5, 0.5)\nwindow.Size = UDim2.fromOffset(920, 650)\nwindow.BackgroundColor3 = Theme.Bottom\nwindow.BackgroundTransparency = 0\nwindow.BorderSizePixel = 0\nwindow.ClipsDescendants = true\nwindow.Parent = gui\ncorner(window, 8); stroke(window, Theme.Stroke, 0.08)\n\nlocal grad = Instance.new("UIGradient")\ngrad.Color = ColorSequence.new({ColorSequenceKeypoint.new(0, Theme.Top), ColorSequenceKeypoint.new(1, Theme.Bottom)})\ngrad.Rotation = 90\ngrad.Parent = window\n\n-- V9.7 mobile fit: the lobby creator uses a desktop-sized 920x650\n-- shell. On mobile Roblox applies touch UI scaling, so force a lower\n-- UIScale and keep the panel centered instead of letting it overflow.\nfunction SliceHubLobbyCreatorMobileFit()\n    local camera = Workspace.CurrentCamera\n    if not camera then return end\n\n    local viewport = camera.ViewportSize\n    if viewport.X < 300 or viewport.Y < 240 then return end\n\n    local touchLike = UserInputService.TouchEnabled or viewport.X < 900 or viewport.Y < 620\n    local fit = math.min((viewport.X * 0.86) / 920, (viewport.Y * 0.82) / 650, 1)\n    local scale = touchLike and math.clamp(fit, 0.36, 0.54) or math.clamp(fit, 0.72, 1)\n\n    local windowFit = window:FindFirstChild("SliceHubLobbyFit")\n    if not windowFit then\n        windowFit = Instance.new("UIScale")\n        windowFit.Name = "SliceHubLobbyFit"\n        windowFit.Parent = window\n    end\n    windowFit.Scale = scale\n\n    local shadowFit = shadow:FindFirstChild("SliceHubLobbyFit")\n    if not shadowFit then\n        shadowFit = Instance.new("UIScale")\n        shadowFit.Name = "SliceHubLobbyFit"\n        shadowFit.Parent = shadow\n    end\n    shadowFit.Scale = scale\n\n    window.AnchorPoint = Vector2.new(0.5, 0.5)\n    window.Position = UDim2.fromScale(0.5, 0.5)\n    shadow.AnchorPoint = Vector2.new(0.5, 0.5)\n    shadow.Position = UDim2.new(0.5, 6 * scale, 0.5, 8 * scale)\nend\n\nSliceHubLobbyCreatorMobileFit()\nif Workspace.CurrentCamera then\n    Workspace.CurrentCamera:GetPropertyChangedSignal("ViewportSize"):Connect(SliceHubLobbyCreatorMobileFit)\nend\nWorkspace:GetPropertyChangedSignal("CurrentCamera"):Connect(function()\n    task.defer(SliceHubLobbyCreatorMobileFit)\nend)\n\nlocal title = Instance.new("Frame")\ntitle.Size = UDim2.new(1, 0, 0, 58)\ntitle.BackgroundColor3 = Theme.Top\ntitle.BorderSizePixel = 0\ntitle.Active = true\ntitle.Parent = window\n\nlocal titleText = Instance.new("TextLabel")\ntitleText.Position = UDim2.fromOffset(18, 7)\ntitleText.Size = UDim2.new(1, -150, 0, 23)\ntitleText.BackgroundTransparency = 1\ntitleText.Font = Enum.Font.GothamBold\ntitleText.Text = "Slice Hub"\ntitleText.TextColor3 = Theme.Text\ntitleText.TextSize = 17\ntitleText.TextXAlignment = Enum.TextXAlignment.Left\ntitleText.Parent = title\n\nlocal subText = Instance.new("TextLabel")\nsubText.Position = UDim2.fromOffset(18, 31)\nsubText.Size = UDim2.new(1, -150, 0, 17)\nsubText.BackgroundTransparency = 1\nsubText.Font = Enum.Font.GothamMedium\nsubText.Text = "AOT:R " .. tostring((getgenv and getgenv().SliceHub and getgenv().SliceHub.BuildTier) or "FREE")\nsubText.TextColor3 = Theme.Muted\nsubText.TextSize = 10\nsubText.TextXAlignment = Enum.TextXAlignment.Left\nsubText.Parent = title\n\nlocal keyHint = Instance.new("TextLabel")\nkeyHint.AnchorPoint = Vector2.new(1, 0.5)\nkeyHint.Position = UDim2.new(1, -16, 0.5, 0)\nkeyHint.Size = UDim2.fromOffset(84, 28)\nkeyHint.BackgroundColor3 = Theme.CardOn\nkeyHint.Font = Enum.Font.GothamBold\nkeyHint.Text = Settings.ToggleKeyName\nkeyHint.TextColor3 = Theme.Text\nkeyHint.TextSize = 10\nkeyHint.Parent = title\ncorner(keyHint, 5); stroke(keyHint, Theme.Stroke, 0.25)\n\nlocal headerAccentLine = Instance.new("Frame")\nheaderAccentLine.Position = UDim2.fromOffset(0, 57)\nheaderAccentLine.Size = UDim2.new(1, 0, 0, 1)\nheaderAccentLine.BackgroundColor3 = Theme.Accent\nheaderAccentLine.BorderSizePixel = 0\nheaderAccentLine.Parent = window\nlocal headerAccentGradient = Instance.new("UIGradient")\nheaderAccentGradient.Color = ColorSequence.new({\n    ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 92, 190)),\n    ColorSequenceKeypoint.new(0.48, Theme.Accent),\n    ColorSequenceKeypoint.new(1, Theme.Accent2),\n})\nheaderAccentGradient.Parent = headerAccentLine\n\nlocal tabBar = Instance.new("Frame")\ntabBar.Position = UDim2.fromOffset(14, 70)\ntabBar.Size = UDim2.fromOffset(154, 520)\ntabBar.BackgroundColor3 = Theme.Panel2\ntabBar.BorderSizePixel = 0\ntabBar.Parent = window\ncorner(tabBar, 6); stroke(tabBar, Theme.Stroke, 0.35)\n\nlocal tabSel = Instance.new("Frame")\ntabSel.Position = UDim2.fromOffset(3, 3)\ntabSel.Size = UDim2.new(1, -6, 1/7, -5)\ntabSel.BackgroundColor3 = Theme.Accent\ntabSel.BorderSizePixel = 0\ntabSel.ZIndex = 2\ntabSel.Parent = tabBar\ncorner(tabSel, 4)\n\nlocal pages = Instance.new("Frame")\npages.Position = UDim2.fromOffset(168, 70)\npages.Size = UDim2.new(1, -182, 0, 520)\npages.BackgroundTransparency = 1\npages.ClipsDescendants = true\npages.Parent = window\n\nlocal status = Instance.new("Frame")\nstatus.Position = UDim2.fromOffset(14, 604)\nstatus.Size = UDim2.new(1, -28, 0, 32)\nstatus.BackgroundColor3 = Theme.Panel2\nstatus.BorderSizePixel = 0\nstatus.Parent = window\ncorner(status, 5); stroke(status, Theme.Stroke, 0.35)\n\nlocal statusDot = Instance.new("Frame")\nstatusDot.Position = UDim2.fromOffset(12, 11)\nstatusDot.Size = UDim2.fromOffset(10, 10)\nstatusDot.BackgroundColor3 = Theme.Warn\nstatusDot.BorderSizePixel = 0\nstatusDot.Parent = status\ncorner(statusDot, 10)\n\nlocal statusLabel = Instance.new("TextLabel")\nstatusLabel.Position = UDim2.fromOffset(30, 0)\nstatusLabel.Size = UDim2.new(1, -42, 1, 0)\nstatusLabel.BackgroundTransparency = 1\nstatusLabel.Font = Enum.Font.GothamMedium\nstatusLabel.Text = "Mode: Unknown"\nstatusLabel.TextColor3 = Theme.Muted\nstatusLabel.TextSize = 10\nstatusLabel.TextXAlignment = Enum.TextXAlignment.Left\nstatusLabel.Parent = status\n\nlocal TabNames = {"Create", "Queue", "Configs", "Settings", "Auto Upgrade", "Auto Prestige", "Skill Tree", "Discord"}\ntabSel.Size = UDim2.new(1, -6, 1/#TabNames, -5)\nlocal TabButtons = {}\nlocal PageFrames = {}\nlocal ActiveTab = "Create"\n\nlocal function makeTab(name, index)\n\tlocal b = Instance.new("TextButton")\n\tb.Position = UDim2.new(0, 0, (index - 1)/#TabNames, 0)\n\tb.Size = UDim2.new(1, 0, 1/#TabNames, 0)\n\tb.BackgroundTransparency = 1\n\tb.AutoButtonColor = false\n\tb.Font = Enum.Font.GothamBold\n\tb.Text = "   " .. string.upper(name)\n\tb.TextSize = 12\n\tb.TextColor3 = index == 1 and Theme.Text or Theme.Dim\n\tb.TextXAlignment = Enum.TextXAlignment.Left\n\tb.ZIndex = 3\n\tb.Parent = tabBar\n\tTabButtons[name] = b\n\n\tlocal page = Instance.new("Frame")\n\tpage.Name = name .. "Page"\n\tpage.Size = UDim2.fromScale(1, 1)\n\tpage.BackgroundTransparency = 1\n\tpage.Visible = index == 1\n\tpage.Parent = pages\n\tPageFrames[name] = page\n\n\tlocal function switchLobbyTab()\n\t\tActiveTab = name\n\t\tfor i, tabName in ipairs(TabNames) do\n\t\t\tlocal page = PageFrames[tabName]\n\t\t\tlocal tabButton = TabButtons[tabName]\n\t\t\tif page then page.Visible = tabName == name end\n\t\t\tif tabButton then tabButton.TextColor3 = tabName == name and Theme.Text or Theme.Dim end\n\t\t\tif tabName == name and tabSel then\n\t\t\t\ttw(tabSel, {Position = UDim2.new(0, 3, (i - 1)/#TabNames, 3)}, 0.12)\n\t\t\tend\n\t\tend\n\t\tprint("[LobbyCreator] tab ->", tostring(name))\n\tend\n\n\tb.Active = true\n\tb.Selectable = true\n\tb.Activated:Connect(switchLobbyTab)\n\tb.MouseButton1Click:Connect(switchLobbyTab)\n\tb.InputBegan:Connect(function(input)\n\t\tif input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then\n\t\t\tswitchLobbyTab()\n\t\tend\n\tend)\nend\n\nfor i, name in ipairs(TabNames) do makeTab(name, i) end\n\n-- v61: lobby tab fallback. Some clients swallow TextButton.Activated in the lobby UI.\nUserInputService.InputBegan:Connect(function(input, gameProcessed)\n\tif not MenuOpen or not window.Visible or not tabBar.Visible then return end\n\tlocal kind = input.UserInputType\n\tif kind ~= Enum.UserInputType.MouseButton1 and kind ~= Enum.UserInputType.Touch then return end\n\tlocal p = input.Position\n\tlocal x = tonumber(p.X) or 0\n\tlocal y = tonumber(p.Y) or 0\n\tfor i, tabName in ipairs(TabNames) do\n\t\tlocal b = TabButtons[tabName]\n\t\tif b and b.Visible then\n\t\t\tlocal pos = b.AbsolutePosition\n\t\t\tlocal size = b.AbsoluteSize\n\t\t\tif x >= pos.X and x <= pos.X + size.X and y >= pos.Y and y <= pos.Y + size.Y then\n\t\t\t\tActiveTab = tabName\n\t\t\t\tfor j, name2 in ipairs(TabNames) do\n\t\t\t\t\tlocal page = PageFrames[name2]\n\t\t\t\t\tlocal tabButton = TabButtons[name2]\n\t\t\t\t\tif page then page.Visible = name2 == tabName end\n\t\t\t\t\tif tabButton then tabButton.TextColor3 = name2 == tabName and Theme.Text or Theme.Dim end\n\t\t\t\t\tif name2 == tabName and tabSel then\n\t\t\t\t\t\ttw(tabSel, {Position = UDim2.new(0, 3, (j - 1)/#TabNames, 3)}, 0.12)\n\t\t\t\t\tend\n\t\t\t\tend\n\t\t\t\tprint("[LobbyCreator] fallback tab ->", tostring(tabName))\n\t\t\t\treturn\n\t\t\tend\n\t\tend\n\tend\nend)\n\nlocal function label(parent, text, pos, size, bold)\n\tlocal l = Instance.new("TextLabel")\n\tl.Position = pos\n\tl.Size = size\n\tl.BackgroundTransparency = 1\n\tl.Font = bold and Enum.Font.GothamBold or Enum.Font.Gotham\n\tl.Text = text\n\tl.TextColor3 = bold and Theme.Text or Theme.Muted\n\tl.TextSize = bold and 13 or 10\n\tl.TextWrapped = not bold\n\tl.TextXAlignment = Enum.TextXAlignment.Left\n\tl.TextYAlignment = Enum.TextYAlignment.Top\n\tl.Parent = parent\n\treturn l\nend\n\nlocal function button(parent, text, pos, size, color)\n\tlocal b = Instance.new("TextButton")\n\tb.