t\t\tnotify("No config selected", "Go to Configs and select one, then set it as auto-load.", "error")\n\t\t\tif V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end\n\t\t\treturn\n\t\tend\n\tend\n\n\tlocal ok, msg = saveSettings()\n\tif V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end\n\tif V94LobbyRefresh.Configs then V94LobbyRefresh.Configs() end\n\tnotify(ok and "Auto-load updated" or "Save failed", ok and ("Auto-load is now " .. (Settings.AutoLoadConfig and "ON" or "OFF")) or msg, ok and "success" or "error")\nend)\n\nclearAutoLoadButton.Activated:Connect(function()\n\tSettings.AutoLoadConfig = false\n\tSettings.AutoLoadConfigName = ""\n\tlocal ok, msg = saveSettings()\n\tif V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end\n\tif V94LobbyRefresh.Configs then V94LobbyRefresh.Configs() end\n\tnotify(ok and "Auto-load cleared" or "Save failed", ok and "No config will auto-load on startup." or msg, ok and "success" or "error")\nend)\n\nif V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end\n\n-- Drag and menu toggle.\nlocal dragging, dragStart, startPos = false, nil, nil\nlocal function startDrag(input)\n\tdragging = true\n\tdragStart = input.Position\n\tstartPos = window.Position\nend\n\ntitle.InputBegan:Connect(function(input)\n\tif input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then startDrag(input) end\nend)\nUserInputService.InputChanged:Connect(function(input)\n\tif dragging and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then\n\t\tlocal delta = input.Position - dragStart\n\t\tlocal pos = UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y)\n\t\twindow.Position = pos\n\t\tshadow.Position = UDim2.new(pos.X.Scale, pos.X.Offset + 6, pos.Y.Scale, pos.Y.Offset + 8)\n\tend\nend)\nUserInputService.InputEnded:Connect(function(input)\n\tif input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then dragging = false end\nend)\nUserInputService.InputBegan:Connect(function(input, processed)\n\tif bindingKey then\n\t\tif input.KeyCode and input.KeyCode ~= Enum.KeyCode.Unknown then\n\t\t\tSettings.ToggleKeyName = input.KeyCode.Name\n\t\t\tbindingKey = false\n\t\t\tlocal ok, msg = saveSettings()\n\t\t\tif V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end\n\t\t\tnotify(ok and "Keybind saved" or "Save failed", ok and ("Menu key is now " .. Settings.ToggleKeyName) or msg, ok and "success" or "error")\n\t\tend\n\t\treturn\n\tend\n\n\tif input.UserInputType == Enum.UserInputType.Keyboard\n\t\tand input.KeyCode == getToggleKeyCode() then\n\t\tMenuOpen = not MenuOpen\n\t\twindow.Visible = MenuOpen\n\t\tshadow.Visible = MenuOpen\n\t\treturn\n\tend\n\n\tif processed then return end\nend)\n\nend)()\n\nrefreshAll()\nif V94LobbyRefresh.Configs then V94LobbyRefresh.Configs() end\nif V94LobbyRefresh.AutoUpgrade then V94LobbyRefresh.AutoUpgrade() end\nif V94LobbyRefresh.Settings then V94LobbyRefresh.Settings() end\nif Settings.AutoLoadConfig and Settings.AutoLoadConfigName ~= "" and SavedConfigs[Settings.AutoLoadConfigName] then\n\tnotify("Auto-loaded config", Settings.AutoLoadConfigName .. " loaded into Create tab.", "success")\nelse\n\tnotify("V9.6.1 Lobby ready", "Remote Auto Upgrade is armed for testing; V9.5 mission behavior remains unchanged.", "success")\nend\n\ntask.spawn(function()\n\twhile gui.Parent do\n\t\ttask.wait(0.35)\n\t\tCurrentMode = detectMode()\n\t\tstatusDot.BackgroundColor3 = modeColor(CurrentMode)\n\t\tlocal runName\n\t\tif State.CreateMode == "Raid" then\n\t\t\trunName = State.RaidChoice\n\t\telseif State.CreateMode == "Waves" then\n\t\t\trunName = "Trost / Waves"\n\t\telse\n\t\t\trunName = State.Map .. " / " .. State.Objective\n\t\tend\n\t\tstatusLabel.Text = "Mode: " .. CurrentMode .. " \u{2022} " .. State.CreateMode .. " \u{2022} " .. runName .. " / "