= 10\n\tmessageText.TextWrapped = true\n\tmessageText.TextXAlignment = Enum.TextXAlignment.Left\n\tmessageText.TextYAlignment = Enum.TextYAlignment.Top\n\tmessageText.ZIndex = 52\n\tmessageText.Parent = toast\n\n\tTweenService:Create(toast, TweenInfo.new(0.28, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {\n\t\tGroupTransparency = 0,\n\t\tPosition = UDim2.fromOffset(0, 0),\n\t}):Play()\n\n\ttask.delay(2.8, function()\n\t\tif not toast.Parent then return end\n\t\tTweenService:Create(toast, TweenInfo.new(0.22, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {\n\t\t\tGroupTransparency = 1,\n\t\t\tPosition = UDim2.fromOffset(24, 0),\n\t\t}):Play()\n\t\ttask.delay(0.24, function()\n\t\t\tif toast.Parent then toast:Destroy() end\n\t\tend)\n\tend)\nend\n\n\nV51PhaseStats = V51PhaseStats or {\n    SessionStartedAt = os.clock(),\n    CurrentRaid = "Unknown",\n    CurrentPhase = "Idle",\n    PhaseStartedAt = os.clock(),\n    Completed = 0,\n    Failed = 0,\n    TotalSeconds = 0,\n    FastestSeconds = nil,\n}\n\nfunction V51PhaseStats.CurrentPhaseSeconds()\n    return math.max(0, os.clock() - (V51PhaseStats.PhaseStartedAt or os.clock()))\nend\n\nfunction V51PhaseStats.Observe()\n    if not V4RaidDirector or not V4RaidDirector.Enabled then return end\n    local raid = tostring(V4RaidDirector.RaidName or "Unknown")\n    local phase = tostring(V4RaidDirector.Phase or "Idle")\n    if raid ~= V51PhaseStats.CurrentRaid or phase ~= V51PhaseStats.CurrentPhase then\n        V51PhaseStats.CurrentRaid = raid\n        V51PhaseStats.CurrentPhase = phase\n        V51PhaseStats.PhaseStartedAt = os.clock()\n    end\nend\n\ntask.spawn(function()\n    while true do\n        task.wait(0.5)\n        pcall(V51PhaseStats.Observe)\n    end\nend)\n\n;(function() -- mobile cleanup: disable old always-on HUD\n\tMiniHUD = {Labels = {}, Update = function() end}\n\tpcall(function()\n\t\tif screenGui then\n\t\t\tlocal oldHud = screenGui:FindFirstChild("MiniFarmHUD")\n\t\t\tif oldHud then oldHud:Destroy() end\n\t\tend\n\tend)\nend)()\n\n\n\n---------------------------------------------------------------------\n-- V9.8.1.4 WAVES RUNTIME DIRECTOR\n-- Premium-only orchestration around the existing blade engine.\n-- Auto Farm Waves reuses Auto Blades; no second killing system is created.\n---------------------------------------------------------------------\n\n;(function()\n    WavesRuntimeDirector = WavesRuntimeDirector or {\n        Busy = false,\n        Status = "Idle",\n        CurrentCrate = nil,\n        BoundFolder = nil,\n        FolderConnection = nil,\n        LastReadyAttempt = 0,\n        LastCrateAttempt = 0,\n        OwnedBlades = false,\n        ResumeFarmAfterMove = false,\n        MovementOriginCFrame = nil,\n        RoundActiveSince = nil,\n        RoundGateReason = "Waiting for wave start",\n        SetupMissingSince = nil,\n        SetupFailureNotified = false,\n        UIStatusLabel = nil,\n    }\n\n    local VirtualInputManager = game:GetService("VirtualInputManager")\n\n    local function premiumAllowed()\n        return type(SliceHubWaveAutomationAllowed) == "function"\n            and SliceHubWaveAutomationAllowed() == true\n    end\n\n    local function liveCharacter()\n        local characterModel = player.Character\n        local humanoidObject = characterModel and characterModel:FindFirstChildOfClass("Humanoid")\n        local root = characterModel\n            and (\n                characterModel:FindFirstChild("HumanoidRootPart")\n                or characterModel.PrimaryPart\n            )\n        if not characterModel or not humanoidObject or humanoidObject.Health <= 0 or not root then\n            return nil, nil, nil\n        end\n        return characterModel, humanoidObject, root\n    end\n\n    local function waitUntil(predicate, timeout, interval)\n        local started = os.clock()\n        repeat\n            local ok, result = pcall(predicate)\n            if ok and result then return true end\n            task.wait(interval or 0.04)\n        until os.clock() - started >= (timeout or 2)\n        return false\n    end\n\n    local function setStatus(value)\n        WavesRuntimeDirector.Status = tostring(value or "Idle")\n        local label = WavesRuntimeDirector.UIStatusLabel\n        if label and label.Parent then\n            label.Text = "Status: " .. WavesRuntimeDirector.Status\n        end\n    end\n\n    function WavesRuntimeDirector.IsRuntime()\n        local waves = Workspace:FindFirstChild("Waves")\n        local unclimbable = Workspace:FindFirstChild("Unclimbable")\n        local objective = unclimbable and unclimbable:FindFirstChild("Objective")\n        local waveObjective = objective and objective:FindFirstChild("Waves")\n        return waves ~= nil and waveObjective ~= nil\n    end\n\n    function WavesRuntimeDirector.GetObjective()\n        local unclimbable = Workspace:FindFirstChild("Unclimbable")\n        local objective = unclimbable and unclimbable:FindFirstChild("Objective")\n        return objective and objective:FindFirstChild("Waves")\n    end\n\n    function WavesRuntimeDirector.GetCratesFolder()\n        local waves = Workspace:FindFirstChild("Waves")\n        return waves and waves:FindFirstChild("Crates")\n    end\n\n    -- Combat readiness and crate readiness are separate.\n    -- A late-loaded script can enter after READY was already pressed, while\n    -- Workspace.Waves.Crates is absent or between crate cycles. That must not\n    -- disable the proven blade engine or incorrectly demand a rejoin.\n    function WavesRuntimeDirector.IsServerSetupReady()\n        local waves = Workspace:FindFirstChild("Waves")\n        if not waves then\n            return false, "Waiting for Workspace.Waves"\n        end\n\n        local objective = WavesRuntimeDirector.GetObjective()\n        if not objective then\n            return false, "Waiting for Waves objective"\n        end\n\n        return true, "Waves runtime ready"\n    end\n\n    function WavesRuntimeDirector.IsCrateSetupReady(requireDropoff)\n        local waves = Workspace:FindFirstChild("Waves")\n        if not waves then\n            return false, "Waiting for Workspace.Waves"\n        end\n\n        local crates = waves:FindFirstChild("Crates")\n        if not crates or not crates:IsA("Folder") then\n            return false, "Waiting for live crate system"\n        end\n\n        if requireDropoff == true then\n            local props = waves:FindFirstChild("Props")\n            local dropoff = props and props:FindFirstChild("Dropoff")\n            if not dropoff then\n                return false, "Waiting for crate delivery station"\n            end\n        end\n\n        return true, "Crate system ready"\n    end\n\n    -- The Waves map creates a temporary/pre-wave crate while the READY\n    -- countdown and cutscene are still active. Moving to that crate can leave\n    -- the character on a roof or at an unloaded spawn when the server deletes\n    -- it at round start. Combat and crate movement are therefore armed only\n    -- after the READY/countdown state has fully cleared and remained stable.\n    function WavesRuntimeDirector.IsRoundActive()\n        if not WavesRuntimeDirector.IsRuntime() then\n            WavesRuntimeDirector.RoundActiveSince = nil\n            WavesRuntimeDirector.RoundGateReason = "Waiting for Waves runtime"\n            return false, WavesRuntimeDirector.RoundGateReason\n        end\n\n        local setupReady, setupReason = WavesRuntimeDirector.IsServerSetupReady()\n        if not setupReady then\n            WavesRuntimeDirector.RoundActiveSince = nil\n            WavesRuntimeDirector.RoundGateReason = setupReason or "Waiting for Waves server setup"\n            return false, WavesRuntimeDirector.RoundGateReason\n        end\n\n        local objective = WavesRuntimeDirector.GetObjective()\n        if not objective then\n            WavesRuntimeDirector.RoundActiveSince = nil\n            WavesRuntimeDirector.RoundGateReason = "Waiting for Waves objective"\n            return false, WavesRuntimeDirector.RoundGateReason\n        end\n\n        local countdown = tonumber(objective:GetAttribute("Countdown"))\n        local ready = tonumber(objective:GetAttribute("Ready")) or 0\n        local show = objective:GetAttribute("Show")\n        local phase = tostring(objective:GetAttribute("Phase") or "")\n\n        if countdown and countdown > 0 then\n            WavesRuntimeDirector.RoundActiveSince = nil\n            WavesRuntimeDirector.RoundGateReason = "Waiting for READY countdown"\n            return false, WavesRuntimeDirector.RoundGateReason\n        end\n\n        if ready == 1 then\n            WavesRuntimeDirector.RoundActiveSince = nil\n            WavesRuntimeDirector.RoundGateReason = "Waiting for READY countdown"\n            return false, WavesRuntimeDirector.RoundGateReason\n        end\n\n        -- During the pre-round transition the game can briefly remove the\n        -- Countdown attribute before re-showing the READY/Skip panel. Keep the\n        -- gate closed through that transient state.\n        if show == true and (phase == "Start" or phase == "Skip") then\n            WavesRuntimeDirector.RoundActiveSince = nil\n            WavesRuntimeDirector.RoundGateReason = "Waiting for cutscene release"\n            return false, WavesRuntimeDirector.RoundGateReason\n        end\n\n        local now = os.clock()\n        if not WavesRuntimeDirector.RoundActiveSince then\n            WavesRuntimeDirector.RoundActiveSince = now\n            WavesRuntimeDirector.RoundGateReason = "Round starting; stabilizing"\n            return false, WavesRuntimeDirector.RoundGateReason\n        end\n\n        if now - WavesRuntimeDirector.RoundActiveSince < 0.85 then\n            WavesRuntimeDirector.RoundGateReason = "Round starting; stabilizing"\n            return false, WavesRuntimeDirector.RoundGateReason\n        end\n\n        WavesRuntimeDirector.RoundGateReason = "Wave round active"\n        return true, WavesRuntimeDirector.RoundGateReason\n    end\n\n    function WavesRuntimeDirector.GetDropoff()\n        local waves = Workspace:FindFirstChild("Waves")\n        local props = waves and waves:FindFirstChild("Props")\n        return props and props:FindFirstChild("Dropoff")\n    end\n\n    function WavesRuntimeDirector.GetPlayerCrate()\n        local folder = WavesRuntimeDirector.GetCratesFolder()\n        if not folder then return nil end\n\n        -- Waves creates one server-owned crate per player. Never fall back to\n        -- another player\'s crate in multiplayer servers.\n        local exact = folder:FindFirstChild("Crate_" .. tostring(player.Name))\n        return exact and exact:IsA("Model") and exact or nil\n    end\n\n    function WavesRuntimeDirector.GetCrateHitbox(crate)\n        if not crate then return nil end\n        local hitbox = crate:FindFirstChild("Hitbox")\n        if hitbox and hitbox:IsA("BasePart") then return hitbox end\n        return crate:FindFirstChildWhichIsA("BasePart", true)\n    end\n\n    function WavesRuntimeDirector.MoveCharacter(targetPosition, lookPosition)\n        if typeof(targetPosition) ~= "Vector3" then return false end\n        local characterModel, humanoidObject, root = liveCharacter()\n        if not characterModel then return false end\n\n        local look = typeof(lookPosition) == "Vector3"\n            and lookPosition\n            or targetPosition + Vector3.new(0, 0, -1)\n        if (look - targetPosition).Magnitude < 0.05 then\n            look = targetPosition + Vector3.new(0, 0, -1)\n        end\n\n        characterModel:PivotTo(CFrame.lookAt(targetPosition, look))\n        root.AssemblyAngularVelocity = Vector3.zero\n        root.AssemblyLinearVelocity = Vector3.zero\n        humanoidObject.Sit = false\n        humanoidObject.PlatformStand = false\n        return true\n    end\n\n    function WavesRuntimeDirector.BeginMovement(reason)\n        if WavesRuntimeDirector.Busy then return false end\n\n        local _, _, root = liveCharacter()\n        WavesRuntimeDirector.MovementOriginCFrame = root and root.CFrame or nil\n        WavesRuntimeDirector.Busy = true\n        WavesRuntimeDirector.ResumeFarmAfterMove = State.FarmEnabled == true\n        State.FarmEnabled = false\n        pcall(function() clearCurrentTarget(false) end)\n        setStatus(reason or "Crate movement")\n        return true\n    end\n\n    function WavesRuntimeDirector.EndMovement(reason, restoreOrigin)\n        local resume = WavesRuntimeDirector.ResumeFarmAfterMove == true\n        local origin = WavesRuntimeDirector.MovementOriginCFrame\n\n        WavesRuntimeDirector.ResumeFarmAfterMove = false\n        WavesRuntimeDirector.MovementOriginCFrame = nil\n        WavesRuntimeDirector.Busy = false\n        WavesRuntimeDirector.CurrentCrate = nil\n\n        -- Failed/pre-wave crate attempts must not strand the character at the\n        -- temporary crate spawn. Successful pickup/delivery keeps its live\n        -- position so the blade engine can naturally reacquire a target.\n        if restoreOrigin == true and typeof(origin) == "CFrame" then\n            local characterModel, humanoidObject, root = liveCharacter()\n            if characterModel and root then\n                pcall(function()\n                    characterModel:PivotTo(origin)\n                    root.AssemblyAngularVelocity = Vector3.zero\n                    root.AssemblyLinearVelocity = Vector3.zero\n                    humanoidObject.Sit = false\n                    humanoidObject.PlatformStand = false\n                end)\n            end\n        end\n\n        if State.WavesAutoFarmEnabled == true\n            and premiumAllowed()\n            and WavesRuntimeDirector.IsRuntime() then\n            local active = WavesRuntimeDirector.IsRoundActive()\n            State.FarmEnabled = active == true\n        elseif resume then\n            State.FarmEnabled = true\n        end\n\n        setStatus(reason or "Idle")\n    end\n\n    function WavesRuntimeDirector.EnsureBladeFarm()\n        if not premiumAllowed()\n            or State.WavesAutoFarmEnabled ~= true\n            or not WavesRuntimeDirector.IsRuntime()\n            or WavesRuntimeDirector.Busy then\n            return false\n        end\n\n        local roundActive, gateReason = WavesRuntimeDirector.IsRoundActive()\n        if not roundActive then\n            -- Auto Farm Waves owns movement while enabled. Never let the blade\n            -- engine target anything during the cutscene/READY transition.\n            if State.FarmEnabled == true then\n                State.FarmEnabled = false\n                pcall(function() clearCurrentTarget(false) end)\n            end\n            setStatus(gateReason or "Waiting for wave start")\n            return false\n        end\n\n        if State.BladesEnabled ~= true then\n            WavesRuntimeDirector.OwnedBlades = true\n            State.BladesEnabled = true\n            if Controls and Controls.Farm and Controls.Farm.Set then\n                pcall(function() Controls.Farm:Set(true, true) end)\n            elseif V5FarmRouter and V5FarmRouter.Sync then\n                V5FarmRouter.Sync("waves auto farm")\n            else\n                State.FarmEnabled = true\n            end\n        elseif State.FarmEnabled ~= true then\n            if V5FarmRouter and V5FarmRouter.Sync then\n                V5FarmRouter.Sync("waves auto farm resume")\n            else\n                State.FarmEnabled = true\n            end\n        end\n\n        setStatus("Auto farming Waves with blade engine")\n        return true\n    end\n\n    function WavesRuntimeDirector.DisableOwnedBladeFarm()\n        if not WavesRuntimeDirector.OwnedBlades then return end\n        WavesRuntimeDirector.OwnedBlades = false\n\n        if Controls and Controls.Farm and Controls.Farm.Set then\n            pcall(function() Controls.Farm:Set(false, true) end)\n        else\n            State.BladesEnabled = false\n            if V5FarmRouter and V5FarmRouter.Sync then\n                V5FarmRouter.Sync("waves auto farm disabled")\n            else\n                State.FarmEnabled = false\n            end\n        end\n    end\n\n    function WavesRuntimeDirector.FindReadyGui()\n        local interface = playerGui:FindFirstChild("Interface")\n        local wavesGui = interface and interface:FindFirstChild("Waves")\n        local inner = wavesGui and wavesGui:FindFirstChild("Inner")\n        local main = inner and inner:FindFirstChild("Main")\n        local vote = main and main:FindFirstChild("Vote")\n        if vote and vote:IsA("GuiObject") then return vote end\n\n        for _, object in ipairs(playerGui:GetDescendants()) do\n            if (object:IsA("TextLabel") or object:IsA("TextButton"))\n                and string.upper(tostring(object.Text or "")) == "READY" then\n                local node = object\n                while node and node ~= playerGui do\n                    if node:IsA("GuiButton") then return node end\n                    node = node.Parent\n                end\n                if object:IsA("GuiObject") then return object end\n            end\n        end\n        return nil\n    end\n\n    function WavesRuntimeDirector.TryReady()\n        if not premiumAllowed()\n            or State.WavesAutoFarmEnabled ~= true\n            or not WavesRuntimeDirector.IsRuntime() then\n            return false\n        end\n\n        local setupReady, setupReason = WavesRuntimeDirector.IsServerSetupReady()\n        if not setupReady then\n            setStatus(setupReason or "Waiting for Waves server setup")\n            return false\n        end\n\n        local objective = WavesRuntimeDirector.GetObjective()\n        if not objective or tonumber(objective:GetAttribute("Ready")) == 1 then\n            return false\n        end\n\n        local now = os.clock()\n        if now - (WavesRuntimeDirector.LastReadyAttempt or 0) < 0.85 then\n            return false\n        end\n        WavesRuntimeDirector.LastReadyAttempt = now\n\n        local target = WavesRuntimeDirector.FindReadyGui()\n        if not target or not target.Visible then return false end\n\n        local fired = false\n        local env = type(getgenv) == "function" and getgenv() or _G\n        local fireSignal = env and env.firesignal or nil\n        if type(fireSignal) == "function" and target:IsA("GuiButton") then\n            fired = pcall(function()\n                fireSignal(target.Activated)\n                if target:IsA("TextButton") or target:IsA("ImageButton") then\n                    fireSignal(target.MouseButton1Click)\n                end\n            end)\n        end\n\n        if not fired then\n            local position = target.AbsolutePosition + target.AbsoluteSize / 2\n            pcall(function()\n                VirtualInputManager:SendMouseMoveEvent(position.X, position.Y, game)\n                VirtualInputManager:SendMouseButtonEvent(position.X, position.Y, 0, true, game, 0)\n                task.wait(0.04)\n                VirtualInputManager:SendMouseButtonEvent(position.X, position.Y, 0, false, game, 0)\n            end)\n        end\n\n        setStatus("READY vote sent")\n        return true\n    end\n\n    function WavesRuntimeDirector.Pickup(crate)\n        if not crate or not crate.Parent then return false, "crate missing" end\n        if crate:GetAttribute("Occupied") == true then return true, "already occupied" end\n        if State.WavesAutoPickupEnabled ~= true then return false, "pickup disabled" end\n\n        local hitbox = WavesRuntimeDirector.GetCrateHitbox(crate)\n        if not hitbox then return false, "crate hitbox missing" end\n\n        for attempt = 1, 6 do\n            if not crate.Parent then return false, "crate removed" end\n            if crate:GetAttribute("Occupied") == true then return true, "picked up" end\n\n            local target = hitbox.Position + Vector3.new(0, 0.45, 0)\n            WavesRuntimeDirector.MoveCharacter(target, hitbox.Position)\n\n            local _, _, root = liveCharacter()\n            local env = type(getgenv) == "function" and getgenv() or _G\n            local touch = env and env.firetouchinterest or nil\n            if root and type(touch) == "function" then\n                pcall(function()\n                    touch(root, hitbox, 0)\n                    task.wait(0.03)\n                    touch(root, hitbox, 1)\n                end)\n            end\n\n            if waitUntil(function()\n                return crate.Parent == nil\n                    or crate:GetAttribute("Occupied") == true\n            end, 0.48, 0.025) then\n                return crate.Parent ~= nil, crate.Parent and "picked up" or "crate removed"\n            end\n        end\n\n        return crate:GetAttribute("Occupied") == true, "pickup timeout"\n    end\n\n    function WavesRuntimeDirector.DropoffTargets(dropoff)\n        local output = {}\n        local pivot = dropoff:GetPivot()\n        local center = pivot.Position\n\n        -- Two confirmed deliveries landed roughly 8-13 studs from this live model.\n        output[#output + 1] = center + Vector3.new(-10, 4, 2)\n        output[#output + 1] = center + Vector3.new(-14, 4, 0)\n        output[#output + 1] = center + Vector3.new(-7, 4, 6)\n        output[#output + 1] = center + Vector3.new(0, 4, 0)\n        output[#output + 1] = (pivot * CFrame.new(-10, 4, 2)).Position\n        output[#output + 1] = (pivot * CFrame.new(-14, 4, 0)).Position\n\n        local added = 0\n        for _, object in ipairs(dropoff:GetDescendants()) do\n            if object:IsA("BasePart") and object.Name == "Crate" then\n                output[#output + 1] = object.Position + Vector3.new(0, 3.5, 0)\n                added += 1\n                if added >= 5 then break end\n            end\n        end\n\n        return output, center\n    end\n\n    function WavesRuntimeDirector.Deliver(crate)\n        if not crate or not crate.Parent then return true, "already removed" end\n        if State.WavesAutoDeliverEnabled ~= true then return false, "delivery disabled" end\n        if crate:GetAttribute("Occupied") ~= true then return false, "crate is not occupied" end\n\n        local dropoff = WavesRuntimeDirector.GetDropoff()\n        if not dropoff then return false, "Workspace.Waves.Props.Dropoff missing" end\n\n        local targets, center = WavesRuntimeDirector.DropoffTargets(dropoff)\n        for _, target in ipairs(targets) do\n            if not crate.Parent then return true, "delivered" end\n            WavesRuntimeDirector.MoveCharacter(target, center)\n\n            if waitUntil(function()\n                local folder = WavesRuntimeDirector.GetCratesFolder()\n                return crate.Parent == nil\n                    or not crate:IsDescendantOf(Workspace)\n                    or (folder and not crate:IsDescendantOf(folder))\n            end, 0.55, 0.025) then\n                return true, "delivered"\n            end\n        end\n\n        return not crate.Parent, crate.Parent and "dropoff timeout" or "delivered"\n    end\n\n    function WavesRuntimeDirector.ProcessCrate(crate)\n        if not premiumAllowed()\n            or WavesRuntimeDirector.Busy\n            or not WavesRuntimeDirector.IsRuntime()\n            or not crate\n            or not crate.Parent then\n            return false\n        end\n\n        local roundActive, gateReason = WavesRuntimeDirector.IsRoundActive()\n        if not roundActive then\n            setStatus((gateReason or "Waiting for wave start") .. " \u{2022} crates paused")\n            return false\n        end\n\n        local wantsPickup = State.WavesAutoPickupEnabled == true\n        local wantsDeliver = State.WavesAutoDeliverEnabled == true\n        local occupied = crate:GetAttribute("Occupied") == true\n\n        if not occupied and not wantsPickup then return false end\n        if occupied and not wantsDeliver then return false end\n        if not WavesRuntimeDirector.BeginMovement("Claiming supply crate") then return false end\n\n        WavesRuntimeDirector.CurrentCrate = crate\n\n        task.spawn(function()\n            local ok, success, reason = pcall(function()\n                if crate:GetAttribute("Occupied") ~= true and wantsPickup then\n                    setStatus("Picking up supply crate")\n                    local picked, pickupReason = WavesRuntimeDirector.Pickup(crate)\n                    if not picked then\n                        return false, pickupReason\n                    end\n                end\n\n                if crate.Parent\n                    and crate:GetAttribute("Occupied") == true\n                    and State.WavesAutoDeliverEnabled == true then\n                    setStatus("Delivering supply crate")\n                    return WavesRuntimeDirector.Deliver(crate)\n                end\n\n                return true, "crate picked up"\n            end)\n\n            if not ok then\n                local restore = not crate.Parent\n                    or crate:GetAttribute("Occupied") ~= true\n                WavesRuntimeDirector.EndMovement(\n                    "Crate error: " .. tostring(success),\n                    restore\n                )\n            elseif success then\n                if not crate.Parent then\n                    WavesRuntimeDirector.EndMovement("Crate delivered")\n                elseif crate:GetAttribute("Occupied") == true then\n                    WavesRuntimeDirector.EndMovement(\n                        State.WavesAutoDeliverEnabled == true\n                            and "Crate delivery finished"\n                            or "Crate picked up; delivery disabled"\n                    )\n                else\n                    WavesRuntimeDirector.EndMovement(tostring(reason or "Crate action finished"))\n                end\n            else\n                local restore = not crate.Parent\n                    or crate:GetAttribute("Occupied") ~= true\n                WavesRuntimeDirector.EndMovement(\n                    "Crate failed: " .. tostring(reason or "unknown"),\n                    restore\n                )\n            end\n        end)\n\n        return true\n    end\n\n    function WavesRuntimeDirector.BindCratesFolder(folder)\n        if WavesRuntimeDirector.BoundFolder == folder then return end\n        if WavesRuntimeDirector.FolderConnection then\n            pcall(function() WavesRuntimeDirector.FolderConnection:Disconnect() end)\n        end\n\n        WavesRuntimeDirector.BoundFolder = folder\n        WavesRuntimeDirector.FolderConnection = folder.ChildAdded:Connect(function(child)\n            if not child:IsA("Model")\n                or child.Name ~= ("Crate_" .. tostring(player.Name)) then\n                return\n            end\n\n            task.defer(function()\n                task.wait(0.03)\n                if State.WavesAutoPickupEnabled == true then\n                    WavesRuntimeDirector.ProcessCrate(child)\n                end\n            end)\n        end)\n    end\n\n    task.spawn(function()\n        while true do\n            task.wait(0.08)\n\n            if not premiumAllowed() then\n                State.WavesAutoFarmEnabled = false\n                State.WavesAutoPickupEnabled = false\n                State.WavesAutoDeliverEnabled = false\n                continue\n            end\n\n            if not WavesRuntimeDirector.IsRuntime() then\n                if not WavesRuntimeDirector.Busy then setStatus("Waiting for Waves runtime") end\n                continue\n            end\n\n            local setupReady, setupReason = WavesRuntimeDirector.IsServerSetupReady()\n            local folder = WavesRuntimeDirector.GetCratesFolder()\n            if folder then WavesRuntimeDirector.BindCratesFolder(folder) end\n\n            if not setupReady then\n                if not WavesRuntimeDirector.Busy then\n                    setStatus(setupReason or "Waiting for Waves runtime")\n                end\n                State.FarmEnabled = false\n                pcall(function() clearCurrentTarget(false) end)\n                continue\n            end\n\n            -- Late execution is supported. If READY was already pressed or the\n            -- wave is already active, TryReady simply does nothing and the\n            -- round gate arms the existing blade engine from current state.\n            if State.WavesAutoFarmEnabled == true then\n                WavesRuntimeDirector.TryReady()\n                WavesRuntimeDirector.EnsureBladeFarm()\n            end\n\n            if not WavesRuntimeDirector.Busy then\n                local roundActive, gateReason = WavesRuntimeDirector.IsRoundActive()\n                local crateAutomation = State.WavesAutoPickupEnabled == true\n                    or State.WavesAutoDeliverEnabled == true\n\n                if crateAutomation and not roundActive then\n                    setStatus((gateReason or "Waiting for wave start") .. " \u{2022} crates paused")\n                elseif crateAutomation then\n                    local crateReady, crateReason =\n                        WavesRuntimeDirector.IsCrateSetupReady(\n                            State.WavesAutoDeliverEnabled == true\n                        )\n\n                    if not crateReady then\n                        if State.WavesAutoFarmEnabled == true and roundActive then\n                            setStatus(\n                                "Auto farming Waves \u{2022} "\n                                .. tostring(crateReason or "waiting for crates")\n                            )\n                        else\n                            setStatus(crateReason or "Waiting for live crate system")\n                        end\n                    else\n                        local crate = WavesRuntimeDirector.GetPlayerCrate()\n                        if crate then\n                            local occupied = crate:GetAttribute("Occupied") == true\n                            if (not occupied and State.WavesAutoPickupEnabled == true)\n                                or (occupied and State.WavesAutoDeliverEnabled == true) then\n                                WavesRuntimeDirector.ProcessCrate(crate)\n                            end\n                        elseif State.WavesAutoFarmEnabled ~= true then\n                            setStatus("Waiting for supply crate")\n                        end\n                    end\n                elseif State.WavesAutoFarmEnabled ~= true then\n                    setStatus("Waves runtime ready")\n                end\n            end\n        end\n    end)\nend)()\n\n---------------------------------------------------------------------\n-- SLICE HUB V1 LAB SHELL \u{2022} v117 FEATURE PORT\n-- Proven input model: PlayerGui + native Activated + modal shield.\n---------------------------------------------------------------------\n\n;(function()\n    -- Keep the exact environment that passed the GUI LAB test.\n    pcall(function() screenGui.Parent = playerGui end)\n    screenGui.IgnoreGuiInset = false\n    screenGui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling\n    screenGui.DisplayOrder = 9999\n    screenGui.Enabled = true\n\n    -- V9.2 remastered shell: flat graphite surfaces with restrained saved-theme accent.\n    Theme.WindowTop = Color3.fromRGB(13, 12, 17)\n    Theme.WindowBottom = Color3.fromRGB(10, 10, 14)\n    Theme.Title = Color3.fromRGB(15, 14, 20)\n    Theme.TabBar = Color3.fromRGB(11, 10, 15)\n    Theme.Card = Color3.fromRGB(20, 18, 26)\n    Theme.CardActive = Color3.fromRGB(25, 24, 33)\n    Theme.CardSoft = Color3.fromRGB(16, 15, 21)\n    Theme.ElementBg = Color3.fromRGB(13, 12, 17)\n    Theme.Stroke = Color3.fromRGB(38, 38, 46)\n    Theme.StrokeSoft = Color3.fromRGB(45, 46, 57)\n    Theme.SwitchOff = Color3.fromRGB(22, 21, 28)\n    Theme.Button = Color3.fromRGB(24, 23, 31)\n    Theme.ButtonHover = Color3.fromRGB(31, 30, 40)\n    Theme.Text = Color3.fromRGB(232, 232, 236)\n    Theme.TextMuted = Color3.fromRGB(166, 165, 174)\n    Theme.TextDim = Color3.fromRGB(112, 111, 121)\n    Theme.Accent = (ThemePresets[PersistentSettings.ThemeName] or ThemePresets.Blue).Accent\n    Theme.AccentColor = Theme.Accent\n    Theme.AccentLight = (ThemePresets[PersistentSettings.ThemeName] or ThemePresets.Blue).AccentLight\n    Theme.TabSelectedA = Theme.Accent\n    Theme.TabSelectedB = (ThemePresets[PersistentSettings.ThemeName] or ThemePresets.Blue).TabSelectedB\n    Theme.Danger = Color3.fromRGB(236, 92, 112)\n\n    local function uiCorner(parent, radius)\n        local value = Instance.new("UICorner")\n        value.CornerRadius = UDim.new(0, radius or 10)\n        value.Parent = parent\n        return value\n    end\n\n    local function uiStroke(parent, color, transparency, thickness)\n        local value = Instance.new("UIStroke")\n        value.Color = color or Theme.Stroke\n        value.Transparency = transparency or 0.35\n        value.Thickness = thickness or 1\n        value.Parent = parent\n        return value\n    end\n\n    function tween(instance, duration, style, direction, properties)\n        local animation = TweenService:Create(\n            instance,\n            TweenInfo.new(duration or 0.14, style or Enum.EasingStyle.Quad, direction or Enum.EasingDirection.Out),\n            properties\n        )\n        animation:Play()\n        return animation\n    end\n\n    inputShield = Instance.new("TextButton")\n    inputShield.Name = "InputShield"\n    inputShield.Size = UDim2.fromScale(1, 1)\n    inputShield.BackgroundTransparency = 1\n    inputShield.Text = ""\n    inputShield.AutoButtonColor = false\n    inputShield.Active = true\n    inputShield.Modal = true\n    inputShield.Selectable = false\n    inputShield.ZIndex = 1\n    inputShield.Parent = screenGui\n\n    shadow = Instance.new("Frame")\n    shadow.Name = "Shadow"\n    shadow.AnchorPoint = Vector2.new(0.5, 0.5)\n    shadow.Position = UDim2.new(0.5, 5, 0.5, 7)\n    shadow.Size = UDim2.fromOffset(920, 600)\n    shadow.BackgroundColor3 = Color3.fromRGB(0, 0, 0)\n    shadow.BackgroundTransparency = 0.60\n    shadow.BorderSizePixel = 0\n    shadow.ZIndex = 2\n    shadow.Parent = screenGui\n    uiCorner(shadow, 7)\n\n    window = Instance.new("Frame")\n    window.Name = "Window"\n    window.AnchorPoint = Vector2.new(0.5, 0.5)\n    window.Position = UDim2.fromScale(0.5, 0.5)\n    window.Size = UDim2.fromOffset(920, 600)\n    window.BackgroundColor3 = Theme.WindowBottom\n    window.BackgroundTransparency = 0\n    window.BorderSizePixel = 0\n    window.Active = true\n    window.ZIndex = 3\n    window.Parent = screenGui\n    uiCorner(window, 7)\n    windowStroke = uiStroke(window, Theme.Stroke, 0.12, 1)\n\n    windowGradient = Instance.new("UIGradient")\n    windowGradient.Color = ColorSequence.new(Theme.WindowTop, Theme.WindowBottom)\n    windowGradient.Rotation = 90\n    windowGradient.Parent = window\n\n    windowScale = Instance.new("UIScale")\n    windowScale.Name = "ViewportFit"\n    windowScale.Scale = 1\n    windowScale.Parent = window\n\n    shadowScale = Instance.new("UIScale")\n    shadowScale.Name = "ViewportFit"\n    shadowScale.Scale = 1\n    shadowScale.Parent = shadow\n\n    function updateV1Scale()\n        local camera = Workspace.CurrentCamera\n        if not camera then return end\n        local viewport = camera.ViewportSize\n        if viewport.X < 300 or viewport.Y < 250 then return end\n        local fit = math.min((viewport.X * 0.82) / 920, (viewport.Y * 0.80) / 600, 1)\n        if UserInputService.TouchEnabled or viewport.Y < 560 or viewport.X < 760 then\n            fit = math.min(fit, 0.50)\n            windowScale.Scale = fit\n            shadowScale.Scale = fit\n            return\n        end\n        local userScale = math.clamp((tonumber(PersistentSettings.MenuScale) or 100) / 100, 0.8, 1.2)\n        windowScale.Scale = fit * userScale\n        shadowScale.Scale = fit * userScale\n    end\n    updateV1Scale()\n    if Workspace.CurrentCamera then\n        Workspace.CurrentCamera:GetPropertyChangedSignal("ViewportSize"):Connect(updateV1Scale)\n    end\n    Workspace:GetPropertyChangedSignal("CurrentCamera"):Connect(function()\n        task.defer(updateV1Scale)\n    end)\n\n    titleBar = Instance.new("Frame")\n    titleBar.Name = "Header"\n    titleBar.Size = UDim2.new(1, 0, 0, 52)\n    titleBar.BackgroundColor3 = Theme.Title\n    titleBar.BackgroundTransparency = 0\n    titleBar.BorderSizePixel = 0\n    titleBar.Active = true\n    titleBar.ZIndex = 4\n    titleBar.Parent = window\n    uiCorner(titleBar, 7)\n\n    titleGradient = Instance.new("UIGradient")\n    titleGradient.Color = ColorSequence.new(Theme.WindowTop, Theme.Title)\n    titleGradient.Parent = titleBar\n\n    local headerMask = Instance.new("Frame")\n    headerMask.Position = UDim2.new(0, 0, 1, -7)\n    headerMask.Size = UDim2.new(1, 0, 0, 7)\n    headerMask.BackgroundColor3 = Theme.Title\n    headerMask.BorderSizePixel = 0\n    headerMask.ZIndex = 4\n    headerMask.Parent = titleBar\n\n    local title = Instance.new("TextLabel")\n    title.Position = UDim2.fromOffset(14, 7)\n    title.Size = UDim2.fromOffset(180, 22)\n    title.BackgroundTransparency = 1\n    title.Font = Enum.Font.GothamBold\n    title.Text = "Slice Hub"\n    title.TextColor3 = Theme.Text\n    title.TextSize = 17\n    title.TextXAlignment = Enum.TextXAlignment.Left\n    title.ZIndex = 5\n    title.Parent = titleBar\n\n    local subtitle = Instance.new("TextLabel")\n    subtitle.Position = UDim2.fromOffset(14, 29)\n    subtitle.Size = UDim2.fromOffset(200, 16)\n    subtitle.BackgroundTransparency = 1\n    subtitle.Font = Enum.Font.GothamMedium\n\t\tsubtitle.Text = "AOT:R " .. tostring((getgenv and getgenv().SliceHub and getgenv().SliceHub.BuildTier) or "FREE")\n    subtitle.TextColor3 = Theme.TextMuted\n    subtitle.TextSize = 9\n    subtitle.TextXAlignment = Enum.TextXAlignment.Left\n    subtitle.ZIndex = 5\n    subtitle.Parent = titleBar\n\n    keyHint = Instance.new("TextLabel")\n    keyHint.AnchorPoint = Vector2.new(1, 0.5)\n    keyHint.Position = UDim2.new(1, -46, 0.5, 0)\n    keyHint.Size = UDim2.fromOffset(72, 28)\n    keyHint.BackgroundColor3 = Theme.CardSoft\n    keyHint.BorderSizePixel = 0\n    keyHint.Font = Enum.Font.GothamBold\n    keyHint.Text = tostring(PersistentSettings.MenuToggleKeyName or "RightShift")\n    keyHint.TextColor3 = Theme.Text\n    keyHint.TextSize = 10\n    keyHint.ZIndex = 5\n    keyHint.Parent = titleBar\n    uiCorner(keyHint, 4)\n    uiStroke(keyHint, Theme.Stroke, 0.45)\n\n    closeButton = Instance.new("TextButton")\n    closeButton.Name = "CloseButton"\n    closeButton.AnchorPoint = Vector2.new(1, 0.5)\n    closeButton.Position = UDim2.new(1, -10, 0.5, 0)\n    closeButton.Size = UDim2.fromOffset(28, 28)\n    closeButton.BackgroundTransparency = 1\n    closeButton.BorderSizePixel = 0\n    closeButton.AutoButtonColor = false\n    closeButton.Font = Enum.Font.Gotham\n    closeButton.Text = "\u{d7}"\n    closeButton.TextColor3 = Theme.TextMuted\n    closeButton.TextSize = 22\n    closeButton.ZIndex = 6\n    closeButton.Parent = titleBar\n    closeButton.MouseEnter:Connect(function() closeButton.TextColor3 = Theme.Text end)\n    closeButton.MouseLeave:Connect(function() closeButton.TextColor3 = Theme.TextMuted end)\n    closeButton.Activated:Connect(function()\n        if type(setMenuOpen) == "function" then\n            setMenuOpen(false)\n        else\n            window.Visible = false\n            shadow.Visible = false\n        end\n    end)\n\n    accentLine = Instance.new("Frame")\n    accentLine.Name = "AccentLine"\n    accentLine.Position = UDim2.fromOffset(0, 51)\n    accentLine.Size = UDim2.new(1, 0, 0, 1)\n    accentLine.BackgroundColor3 = Theme.Accent\n    accentLine.BorderSizePixel = 0\n    accentLine.ZIndex = 5\n    accentLine.Parent = window\n    local accentGradient = Instance.new("UIGradient")\n    accentGradient.Color = ColorSequence.new({\n        ColorSequenceKeypoint.new(0, Color3.fromRGB(255, 92, 190)),\n        ColorSequenceKeypoint.new(0.48, Theme.Accent),\n        ColorSequenceKeypoint.new(1, Theme.AccentLight),\n    })\n    accentGradient.Parent = accentLine\n\n    -- Dual candy glow rails make the shell visually different from the old V5 card layout.\n    local leftGlow = Instance.new("Frame")\n    leftGlow.Position = UDim2.fromOffset(0, 72)\n    leftGlow.Size = UDim2.fromOffset(4, 588)\n    leftGlow.BackgroundColor3 = Theme.Accent\n    leftGlow.BackgroundTransparency = 1\n    leftGlow.BorderSizePixel = 0\n    leftGlow.ZIndex = 5\n    leftGlow.Parent = window\n    local leftGlowGradient = Instance.new("UIGradient")\n    leftGlowGradient.Rotation = 90\n    leftGlowGradient.Color = ColorSequence.new(Color3.fromRGB(255, 92, 190), Theme.Accent)\n    leftGlowGradient.Parent = leftGlow\n\n    local rightGlow = Instance.new("Frame")\n    rightGlow.AnchorPoint = Vector2.new(1, 0)\n    rightGlow.Position = UDim2.new(1, 0, 0, 72)\n    rightGlow.Size = UDim2.fromOffset(4, 588)\n    rightGlow.BackgroundColor3 = Theme.AccentLight\n    rightGlow.BackgroundTransparency = 1\n    rightGlow.BorderSizePixel = 0\n    rightGlow.ZIndex = 5\n    rightGlow.Parent = window\n    local rightGlowGradient = Instance.new("UIGradient")\n    rightGlowGradient.Rotation = 90\n    rightGlowGradient.Color = ColorSequence.new(Theme.AccentLight, Theme.Accent)\n    rightGlowGradient.Parent = rightGlow\n\n    tabBar = Instance.new("Frame")\n    tabBar.Name = "Sidebar"\n    tabBar.Position = UDim2.fromOffset(0, 52)\n    tabBar.Size = UDim2.fromOffset(210, 548)\n    tabBar.BackgroundColor3 = Theme.TabBar\n    tabBar.BorderSizePixel = 0\n    tabBar.ZIndex = 4\n    tabBar.Parent = window\n    uiCorner(tabBar, 0)\n    tabBarStroke = uiStroke(tabBar, Theme.Stroke, 0.20, 1)\n\n    local brand = Instance.new("TextLabel")\n    brand.Position = UDim2.fromOffset(14, 12)\n    brand.Size = UDim2.new(1, -28, 0, 20)\n    brand.BackgroundTransparency = 1\n    brand.Font = Enum.Font.GothamBold\n    brand.Text = "SLICE HUB"\n    brand.Visible = false\n    brand.TextColor3 = Theme.Text\n    brand.TextSize = 12\n    brand.TextXAlignment = Enum.TextXAlignment.Left\n    brand.ZIndex = 5\n    brand.Parent = tabBar\n\n    local brandSub = Instance.new("TextLabel")\n    brandSub.Position = UDim2.fromOffset(14, 34)\n    brandSub.Size = UDim2.new(1, -28, 0, 16)\n    brandSub.BackgroundTransparency = 1\n    brandSub.Font = Enum.Font.GothamMedium\n    brandSub.Text = "AOT:R " .. tostring((getgenv and getgenv().SliceHub and getgenv().SliceHub.BuildTier) or "FREE")\n    brandSub.Visible = false\n    brandSub.TextColor3 = Theme.TextDim\n    brandSub.TextSize = 9\n    brandSub.TextXAlignment = Enum.TextXAlignment.Left\n    brandSub.ZIndex = 5\n    brandSub.Parent = tabBar\n\n    local divider = Instance.new("Frame")\n    divider.Position = UDim2.fromOffset(12, 58)\n    divider.Size = UDim2.new(1, -24, 0, 1)\n    divider.BackgroundColor3 = Theme.Stroke\n    divider.BackgroundTransparency = 0.65\n    divider.BorderSizePixel = 0\n    divider.ZIndex = 5\n    divider.Parent = tabBar\n    divider.Visible = false\n\n    local navHolder = Instance.new("ScrollingFrame")\n    navHolder.Position = UDim2.fromOffset(12, 12)\n    navHolder.Size = UDim2.new(1, -24, 1, -24)\n    navHolder.BackgroundTransparency = 1\n    navHolder.BorderSizePixel = 0\n    navHolder.ScrollBarThickness = 3\n    navHolder.ScrollBarImageColor3 = Theme.AccentLight\n    navHolder.CanvasSize = UDim2.fromOffset(0, 0)\n    navHolder.AutomaticCanvasSize = Enum.AutomaticSize.Y\n    navHolder.ScrollingDirection = Enum.ScrollingDirection.Y\n    navHolder.ZIndex = 5\n    navHolder.Parent = tabBar\n\n    local navLayout = Instance.new("UIListLayout")\n    navLayout.Padding = UDim.new(0, 2)\n    navLayout.SortOrder = Enum.SortOrder.LayoutOrder\n    navLayout.Parent = navHolder\n\n    local contentSurface = Instance.new("Frame")\n    contentSurface.Name = "ContentSurface"\n    contentSurface.Position = UDim2.fromOffset(210, 52)\n    contentSurface.Size = UDim2.new(1, -210, 1, -52)\n    contentSurface.BackgroundColor3 = Color3.fromRGB(10, 10, 14)\n    contentSurface.BackgroundTransparency = 0\n    contentSurface.BorderSizePixel = 0\n    contentSurface.ZIndex = 3\n    contentSurface.Parent = window\n    uiCorner(contentSurface, 0)\n    uiStroke(contentSurface, Theme.Stroke, 0.35, 1)\n\n    local pageRail = Instance.new("Frame")\n    pageRail.Position = UDim2.fromOffset(226, 62)\n    pageRail.Size = UDim2.new(1, -242, 0, 26)\n    pageRail.BackgroundTransparency = 1\n    pageRail.ZIndex = 7\n    pageRail.Parent = window\n\n    local activePageTitle = Instance.new("TextLabel")\n    activePageTitle.Size = UDim2.new(1, -120, 1, 0)\n    activePageTitle.BackgroundTransparency = 1\n    activePageTitle.Font = Enum.Font.GothamBold\n    activePageTitle.Text = "WELCOME / OVERVIEW"\n    activePageTitle.TextColor3 = Theme.Text\n    activePageTitle.TextSize = 14\n    activePageTitle.TextXAlignment = Enum.TextXAlignment.Left\n    activePageTitle.ZIndex = 8\n    activePageTitle.Parent = pageRail\n\n    local liveChip = Instance.new("TextLabel")\n    liveChip.AnchorPoint = Vector2.new(1, 0)\n    liveChip.Position = UDim2.new(1, 0, 0, 0)\n    liveChip.Size = UDim2.fromOffset(106, 22)\n    liveChip.BackgroundColor3 = Theme.CardSoft\n    liveChip.BorderSizePixel = 0\n    liveChip.Font = Enum.Font.GothamBold\n    liveChip.Text = "\u{25cf}  CORE LIVE"\n    liveChip.TextColor3 = Theme.AccentLight\n    liveChip.TextSize = 9\n    liveChip.ZIndex = 8\n    liveChip.Parent = pageRail\n    uiCorner(liveChip, 3)\n    uiStroke(liveChip, Theme.AccentLight, 0.55, 1)\n\n    pagesHolder = Instance.new("Frame")\n    pagesHolder.Name = "Content"\n    pagesHolder.Position = UDim2.fromOffset(226, 96)\n    pagesHolder.Size = UDim2.new(1, -242, 1, -142)\n    pagesHolder.BackgroundTransparency = 1\n    pagesHolder.ClipsDescendants = true\n    pagesHolder.ZIndex = 4\n    pagesHolder.Parent = window\n\n    V1Pages = {}\n    V1NavButtons = {}\n    activeV1Page = nil\n\n    local function createV1Page(name)\n        local page = Instance.new("ScrollingFrame")\n        page.Name = name .. "Page"\n        page.Size = UDim2.fromScale(1, 1)\n        page.BackgroundTransparency = 1\n        page.BorderSizePixel = 0\n        page.ScrollBarThickness = 2\n        page.ScrollBarImageColor3 = Theme.AccentLight\n        page.CanvasSize = UDim2.fromOffset(0, 0)\n        page.AutomaticCanvasSize = Enum.AutomaticSize.Y\n        page.ScrollingDirection = Enum.ScrollingDirection.Y\n        page.Visible = false\n        page.ZIndex = 4\n        page.Parent = pagesHolder\n\n        local layout = Instance.new("UIListLayout")\n        layout.Padding = UDim.new(0, 8)\n        layout.SortOrder = Enum.SortOrder.LayoutOrder\n        layout.Parent = page\n\n        V1Pages[name] = page\n        return page\n    end\n\n    local function createSectionHost(parent, order, name)\n        local section = Instance.new("Frame")\n        section.Name = name or "Section"\n        section.LayoutOrder = order\n        section.Size = UDim2.new(1, -4, 0, 0)\n        section.AutomaticSize = Enum.AutomaticSize.Y\n        section.BackgroundColor3 = Theme.CardSoft\n        section.BackgroundTransparency = 0\n        section.BorderSizePixel = 0\n        section.ZIndex = 5\n        section.Parent = parent\n        uiCorner(section, 4)\n        uiStroke(section, Theme.Stroke, 0.20, 1)\n\n        local padding = Instance.new("UIPadding")\n        padding.PaddingTop = UDim.new(0, 8)\n        padding.PaddingBottom = UDim.new(0, 8)\n        padding.PaddingLeft = UDim.new(0, 10)\n        padding.PaddingRight = UDim.new(0, 10)\n        padding.Parent = section\n\n        local layout = Instance.new("UIListLayout")\n        layout.Padding = UDim.new(0, 4)\n        layout.SortOrder = Enum.SortOrder.LayoutOrder\n        layout.Parent = section\n\n        local heading = Instance.new("TextLabel")\n        heading.Name = "GroupTitle"\n        heading.LayoutOrder = -1000\n        heading.Size = UDim2.new(1, 0, 0, 24)\n        heading.BackgroundTransparency = 1\n        heading.Font = Enum.Font.GothamBold\n        heading.Text = string.upper(({BladesCore="BLADE ENGINE", FarmAutomation="MISSION AUTOMATION", SpearsCore="SPEAR ENGINE", StallDestroyer="STALL DESTROYER", CombatCore="COMBAT SETTINGS", ConfigCore="PROFILES & PRESETS", VisualPerformance="VISUAL PERFORMANCE", StatsCore="LIVE STATS", SettingsCore="SETTINGS", RaidDirector="RAID DIRECTOR", WavesAutomation="WAVES AUTOMATION"})[name] or tostring(name or "SECTION"))\n        heading.TextColor3 = Theme.TextMuted\n        heading.TextSize = 12\n        heading.TextXAlignment = Enum.TextXAlignment.Left\n        heading.Parent = section\n        return section\n    end\n\n    local function createNavButton(name, order)\n        local button = Instance.new("TextButton")\n        button.Name = name .. "Nav"\n        button.LayoutOrder = order * 10\n        button.Size = UDim2.new(1, 0, 0, 28)\n        button.BackgroundColor3 = Theme.CardSoft\n        button.BackgroundTransparency = 1\n        button.BorderSizePixel = 0\n        button.AutoButtonColor = false\n        button.Font = Enum.Font.GothamMedium\n        local navName = ({\n            Welcome = "Overview",\n            Farm = "Missions",\n            Config = "Profiles",\n            Waves = SliceHubWaveAutomationAllowed() and "Waves" or "Waves \u{1f512}",\n        })[name] or name\n        button.Text = "  " .. navName\n        button.TextColor3 = Theme.TextDim\n        button.TextSize = 10\n        button.TextXAlignment = Enum.TextXAlignment.Left\n        button.Active = true\n        button.Selectable = true\n        button.ZIndex = 6\n        button.Parent = navHolder\n        uiCorner(button, 3)\n        local indicator = Instance.new("Frame")\n        indicator.Name = "Indicator"\n        indicator.AnchorPoint = Vector2.new(0, 1)\n        indicator.Position = UDim2.new(0, 8, 1, 0)\n        indicator.Size = UDim2.fromOffset(14, 2)\n        indicator.BackgroundColor3 = Theme.AccentLight\n        indicator.BackgroundTransparency = 1\n        indicator.BorderSizePixel = 0\n        indicator.ZIndex = 7\n        indicator.Parent = button\n        uiCorner(indicator, 2)\n        V1NavButtons[name] = button\n        return button\n    end\n\n    local lastLockedPageNoticeAt = 0\n    function setV1Page(name)\n        if name == "Waves" and not SliceHubWaveAutomationAllowed() then\n            local now = os.clock()\n            if now - lastLockedPageNoticeAt >= 0.75 then\n                lastLockedPageNoticeAt = now\n                showNotification("Premium only", "This tab unlocks only when you have Premium.", "info")\n            end\n            return\n        end\n        local target = V1Pages[name]\n        if not target then return end\n        activeV1Page = name\n        for pageName, page in pairs(V1Pages) do\n            page.Visible = pageName == name\n            if pageName == name then page.CanvasPosition = Vector2.zero end\n        end\n        for buttonName, button in pairs(V1NavButtons) do\n            local selected = buttonName == name\n            button.BackgroundTransparency = 1\n            button.BackgroundColor3 = Theme.CardSoft\n            button.TextColor3 = selected and Theme.Text or Theme.TextDim\n            local indicator = button:FindFirstChild("Indicator")\n            if indicator then indicator.BackgroundTransparency = selected and 0 or 1 end\n        end\n        activePageTitle.Text = name == "Welcome" and "OVERVIEW" or string.upper(({Farm="MISSIONS", Config="PROFILES"})[name] or name)\n        print("[SliceHub V3] page ->", name)\n    end\n\n    local tabNames = {"Welcome", "Farm", "Raids", "Waves", "Blades", "Spears", "Combat", "Stall", "Stats", "Webhook", "Optimization", "Config", "Settings", "Discord"}\n    for index, name in ipairs(tabNames) do\n        createV1Page(name)\n        if name == "Welcome" or name == "Blades" or name == "Stats" or name == "Config" then\n            local group = Instance.new("TextLabel")\n            group.Name = name .. "GroupLabel"\n            group.LayoutOrder = index * 10 - 1\n            group.Size = UDim2.new(1, 0, 0, 26)\n            group.BackgroundTransparency = 1\n            group.Font = Enum.Font.GothamBold\n            group.Text = ({Welcome="FARMING", Blades="COMBAT", Stats="UTILITY", Config="CONFIGURATION"})[name]\n            group.TextColor3 = Color3.fromRGB(126, 126, 134)\n            group.TextSize = 11\n            group.TextXAlignment = Enum.TextXAlignment.Left\n            group.Parent = navHolder\n        end\n        local button = createNavButton(name, index)\n        local function activatePage()\n            setV1Page(name)\n        end\n        button.Activated:Connect(activatePage)\n        button.MouseEnter:Connect(function()\n            if activeV1Page ~= name then\n                tween(button, 0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {\n                    BackgroundTransparency = 0.35,\n                    BackgroundColor3 = Theme.CardSoft,\n                })\n            end\n        end)\n        button.MouseLeave:Connect(function()\n            if activeV1Page ~= name then\n                tween(button, 0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {\n                    BackgroundTransparency = 1,\n                })\n            end\n        end)\n    end\n\n\n    -----------------------------------------------------------------\n    -- V5.7.7 CANDY FEATURE SEARCH\n    -----------------------------------------------------------------\n    local searchBar = Instance.new("Frame")\n    searchBar.Name = "FeatureSearchBar"\n    searchBar.Position = UDim2.fromOffset(248, 11)\n    searchBar.Size = UDim2.fromOffset(410, 30)\n    searchBar.BackgroundColor3 = Theme.CardSoft\n    searchBar.BorderSizePixel = 0\n    searchBar.ZIndex = 12\n    searchBar.Parent = window\n    uiCorner(searchBar, 4)\n    uiStroke(searchBar, Theme.StrokeSoft, 0.34)\n\n    local searchIcon = Instance.new("TextLabel")\n    searchIcon.Position = UDim2.fromOffset(12, 0)\n    searchIcon.Size = UDim2.fromOffset(26, 30)\n    searchIcon.BackgroundTransparency = 1\n    searchIcon.Font = Enum.Font.GothamBold\n    searchIcon.Text = "\u{2315}"\n    searchIcon.TextColor3 = Theme.AccentLight\n    searchIcon.TextSize = 20\n    searchIcon.ZIndex = 13\n    searchIcon.Parent = searchBar\n\n    local searchBox = Instance.new("TextBox")\n    searchBox.Name = "FeatureSearch"\n    searchBox.Position = UDim2.fromOffset(40, 0)\n    searchBox.Size = UDim2.new(1, -52, 1, 0)\n    searchBox.BackgroundTransparency = 1\n    searchBox.ClearTextOnFocus = false\n    searchBox.Font = Enum.Font.GothamMedium\n    searchBox.PlaceholderText = "Search features..."\n    searchBox.PlaceholderColor3 = Theme.TextDim\n    searchBox.Text = ""\n    searchBox.TextColor3 = Theme.Text\n    searchBox.TextSize = 11\n    searchBox.TextXAlignment = Enum.TextXAlignment.Left\n    searchBox.ZIndex = 13\n    searchBox.Parent = searchBar\n\n    local searchPanel = Instance.new("Frame")\n    searchPanel.Name = "SearchResults"\n    searchPanel.Position = UDim2.fromOffset(226, 54)\n    searchPanel.Size = UDim2.new(1, -242, 0, 286)\n    searchPanel.BackgroundColor3 = Color3.fromRGB(13, 12, 17)\n    searchPanel.BackgroundTransparency = 0.02\n    searchPanel.BorderSizePixel = 0\n    searchPanel.Visible = false\n    searchPanel.ZIndex = 30\n    searchPanel.Parent = window\n    uiCorner(searchPanel, 4)\n    uiStroke(searchPanel, Theme.AccentLight, 0.18, 1.2)\n\n    local resultsScroll = Instance.new("ScrollingFrame")\n    resultsScroll.Position = UDim2.fromOffset(8, 8)\n    resultsScroll.Size = UDim2.new(1, -16, 1, -16)\n    resultsScroll.BackgroundTransparency = 1\n    resultsScroll.BorderSizePixel = 0\n    resultsScroll.ScrollBarThickness = 3\n    resultsScroll.ScrollBarImageColor3 = Theme.AccentLight\n    resultsScroll.AutomaticCanvasSize = Enum.AutomaticSize.Y\n    resultsScroll.CanvasSize = UDim2.fromOffset(0, 0)\n    resultsScroll.ZIndex = 31\n    resultsScroll.Parent = searchPanel\n\n    local resultsLayout = Instance.new("UIListLayout")\n    resultsLayout.Padding = UDim.new(0, 5)\n    resultsLayout.SortOrder = Enum.SortOrder.LayoutOrder\n    resultsLayout.Parent = resultsScroll\n\n    local function owningPageFor(object)\n        for pageName, page in pairs(V1Pages) do\n            if object and object:IsDescendantOf(page) then\n                return pageName, page\n            end\n        end\n        return nil, nil\n    end\n\n    local function searchTargetFor(label, page)\n        local node = label\n        local candidate = label\n        while node and node.Parent and node.Parent ~= page do\n            if node:IsA("GuiButton") then candidate = node end\n            if node:IsA("Frame") and tonumber(node.LayoutOrder) and node.LayoutOrder > 0 then candidate = node end\n            node = node.Parent\n        end\n        return candidate\n    end\n\n    local function clearSearchResults()\n        for _, child in ipairs(resultsScroll:GetChildren()) do\n            if child:IsA("GuiButton") then child:Destroy() end\n        end\n    end\n\n    local function refreshFeatureSearch()\n        clearSearchResults()\n        local query = string.lower(string.gsub(tostring(searchBox.Text or ""), "^%s*(.-)%s*$", "%1"))\n        if #query < 2 then\n            searchPanel.Visible = false\n            return\n        end\n\n        local seen = {}\n        local matches = {}\n        for _, page in pairs(V1Pages) do\n            for _, label in ipairs(page:GetDescendants()) do\n                if label:IsA("TextLabel") then\n                    local textValue = tostring(label.Text or "")\n                    local lower = string.lower(textValue)\n                    if textValue ~= "" and string.find(lower, query, 1, true) then\n                        local pageName, ownerPage = owningPageFor(label)\n                        local key = tostring(pageName) .. "|" .. lower\n                        if pageName and ownerPage and not seen[key] then\n                            seen[key] = true\n                            matches[#matches + 1] = {\n                                PageName = pageName,\n                                Page = ownerPage,\n                                Label = label,\n                                Target = searchTargetFor(label, ownerPage),\n                                Text = textValue,\n                            }\n                        end\n                    end\n                end\n            end\n        end\n\n        table.sort(matches, function(a, b)\n            if a.PageName ~= b.PageName then return a.PageName < b.PageName end\n            return a.Text < b.Text\n        end)\n\n        for index = 1, math.min(#matches, 18) do\n            local info = matches[index]\n            local result = Instance.new("TextButton")\n            result.LayoutOrder = index\n            result.Size = UDim2.new(1, -4, 0, 38)\n            result.BackgroundColor3 = Theme.CardSoft\n            result.BorderSizePixel = 0\n            result.AutoButtonColor = false\n            result.Font = Enum.Font.GothamMedium\n            result.Text = "  " .. tostring(info.PageName) .. "  \u{203a}  " .. string.sub(string.gsub(info.Text, "\\n", " "), 1, 82)\n            result.TextColor3 = Theme.Text\n            result.TextSize = 10\n            result.TextXAlignment = Enum.TextXAlignment.Left\n            result.ZIndex = 32\n            result.Parent = resultsScroll\n            uiCorner(result, 8)\n            result.MouseEnter:Connect(function() result.BackgroundColor3 = Theme.CardActive end)\n            result.MouseLeave:Connect(function() result.BackgroundColor3 = Theme.CardSoft end)\n            result.Activated:Connect(function()\n                setV1Page(info.PageName)\n                searchBox.Text = ""\n                searchPanel.Visible = false\n                task.defer(function()\n                    if info.Target and info.Target.Parent and info.Page and info.Page.Parent then\n                        local offset = info.Target.AbsolutePosition.Y - info.Page.AbsolutePosition.Y + info.Page.CanvasPosition.Y - 14\n                        info.Page.CanvasPosition = Vector2.new(0, math.max(0, offset))\n                    end\n                end)\n            end)\n        end\n\n        if #matches == 0 then\n            local empty = Instance.new("TextButton")\n            empty.Size = UDim2.new(1, -4, 0, 42)\n            empty.BackgroundColor3 = Theme.CardSoft\n            empty.BorderSizePixel = 0\n            empty.AutoButtonColor = false\n            empty.Font = Enum.Font.GothamMedium\n            empty.Text = "No feature matched  \u{2018}" .. query .. "\u{2019}"\n            empty.TextColor3 = Theme.TextDim\n            empty.TextSize = 10\n            empty.ZIndex = 32\n            empty.Parent = resultsScroll\n            uiCorner(empty, 8)\n        end\n\n        searchPanel.Visible = true\n    end\n\n    searchBox:GetPropertyChangedSignal("Text"):Connect(refreshFeatureSearch)\n    searchBox.FocusLost:Connect(function()\n        if searchBox.Text == "" then searchPanel.Visible = false end\n    end)\n\n    -- V4.2 GUI repair: screen-position fallback for clients/executors that swallow GuiButton events.\n    UserInputService.InputBegan:Connect(function(input)\n        if not State.MenuOpen or not window or not window.Visible then return end\n        local kind = input.UserInputType\n        if kind ~= Enum.UserInputType.MouseButton1 and kind ~= Enum.UserInputType.Touch then return end\n\n        local p = input.Position\n        local x = tonumber(p.X) or 0\n        local y = tonumber(p.Y) or 0\n\n        for _, pageName in ipairs(tabNames) do\n            local button = V1NavButtons[pageName]\n            if button and button.Visible then\n                local pos = button.AbsolutePosition\n                local size = button.AbsoluteSize\n                if x >= pos.X and x <= pos.X + size.X\n                    and y >= pos.Y and y <= pos.Y + size.Y then\n                    if pageName == "Waves" and not SliceHubWaveAutomationAllowed() then\n                        showNotification("Premium only", "This tab unlocks only when you have Premium.", "info")\n                    else\n                        setV1Page(pageName)\n                    end\n                    return\n                end\n            end\n        end\n    end)\n\n    -- Keep the top-level page visibility invariant repaired even if later feature code touches Visible.\n    task.spawn(function()\n        while screenGui and screenGui.Parent do\n            task.wait(0.5)\n            if State.MenuOpen then\n                for pageName, page in pairs(V1Pages) do\n                    local shouldShow = pageName == activeV1Page\n                    if page.Visible ~= shouldShow then\n                        page.Visible = shouldShow\n                    end\n                end\n            end\n        end\n    end)\n\n    -- Map v117\'s proven feature builders into the V1 navigation.\n    mainPage = createSectionHost(V1Pages.Blades, 10, "BladesCore")\n    autoPage = createSectionHost(V1Pages.Farm, 10, "FarmAutomation")\n    spearsPage = createSectionHost(V1Pages.Spears, 10, "SpearsCore")\n    stallPage = createSectionHost(V1Pages.Stall, 10, "StallDestroyer")\n    raidsPage = createSectionHost(V1Pages.Raids, 10, "RaidDirector")\n    wavesPage = createSectionHost(V1Pages.Waves, 10, "WavesAutomation")\n    combatPage = createSectionHost(V1Pages.Combat, 10, "CombatCore")\n    configPage = createSectionHost(V1Pages.Config, 10, "ConfigCore")\n    performancePage = createSectionHost(V1Pages.Optimization, 10, "VisualPerformance")\n    statsPage = createSectionHost(V1Pages.Stats, 10, "StatsCore")\n    settingsPage = createSectionHost(V1Pages.Settings, 10, "SettingsCore")\n    settingsOuterPage = V1Pages.Settings\n\n    webhookPage = Instance.new("Frame")\n    webhookPage.Name = "WebhookSection"\n    webhookPage.LayoutOrder = 20\n    webhookPage.Size = UDim2.new(1, -4, 0, 442)\n    webhookPage.BackgroundColor3 = Theme.CardSoft\n    webhookPage.BackgroundTransparency = 0.08\n    webhookPage.BorderSizePixel = 0\n    webhookPage.ZIndex = 5\n    webhookPage.Parent = V1Pages.Webhook\n    uiCorner(webhookPage, 4)\n    uiStroke(webhookPage, Theme.Stroke, 0.20)\n\n    -- Compatibility tables retained for profile/settings code that expects them.\n    activeTab = "Welcome"\n    TabOrder = tabNames\n    TabPages = {\n        Welcome = V1Pages.Welcome,\n        Main = V1Pages.Blades,\n        Blades = V1Pages.Blades,\n        Auto = V1Pages.Farm,\n        Config = V1Pages.Config,\n        Performance = V1Pages.Optimization,\n        Stats = V1Pages.Stats,\n        Spears = V1Pages.Spears,\n        Stall = V1Pages.Stall,\n        Webhook = V1Pages.Webhook,\n        Settings = V1Pages.Settings,\n        Raids = V1Pages.Raids,\n        Waves = V1Pages.Waves,\n        Combat = V1Pages.Combat,\n        Discord = V1Pages.Discord,\n    }\n    TabButtons = {}\n    for name, button in pairs(V1NavButtons) do TabButtons[name] = button end\n\n    tabSelection = Instance.new("Frame")\n    tabSelection.Visible = false\n    tabSelection.Parent = tabBar\n    tabSelectionGradient = Instance.new("UIGradient")\n    tabSelectionGradient.Parent = tabSelection\n\n    function switchTab(tabName)\n        local map = {\n            Main = "Blades",\n            Blades = "Blades",\n            Auto = "Farm",\n            Config = "Config",\n            Performance = "Optimization",\n            Stats = "Stats",\n            Spears = "Spears",\n            Stall = "Stall",\n            Webhook = "Webhook",\n            Settings = "Settings",\n            Welcome = "Welcome",\n            Raids = "Raids",\n            Waves = "Waves",\n            Combat = "Combat",\n            Discord = "Discord",\n        }\n        activeTab = tostring(tabName or "Welcome")\n        setV1Page(map[activeTab] or activeTab)\n    end\n\n    local function makeInfoCard(parent, order, height, headingText, bodyText)\n        local card = Instance.new("Frame")\n        card.LayoutOrder = order\n        card.Size = UDim2.new(1, -4, 0, height)\n        card.BackgroundColor3 = Theme.CardSoft\n        card.BorderSizePixel = 0\n        card.ZIndex = 5\n        card.Parent = parent\n        uiCorner(card, 4)\n        uiStroke(card, Theme.Stroke, 0.20)\n\n        local heading = Instance.new("TextLabel")\n        heading.Position = UDim2.fromOffset(16, 12)\n        heading.Size = UDim2.new(1, -32, 0, 24)\n        heading.BackgroundTransparency = 1\n        heading.Font = Enum.Font.GothamBold\n        heading.Text = headingText\n        heading.TextColor3 = Theme.Text\n        heading.TextSize = 14\n        heading.TextXAlignment = Enum.TextXAlignment.Left\n        heading.ZIndex = 6\n        heading.Parent = card\n\n        local body = Instance.new("TextLabel")\n        body.Position = UDim2.fromOffset(16, 40)\n        body.Size = UDim2.new(1, -32, 1, -50)\n        body.BackgroundTransparency = 1\n        body.Font = Enum.Font.GothamMedium\n        body.Text = bodyText or ""\n        body.TextColor3 = Theme.TextMuted\n        body.TextSize = 10\n        body.TextWrapped = true\n        body.TextXAlignment = Enum.TextXAlignment.Left\n        body.TextYAlignment = Enum.TextYAlignment.Top\n        body.ZIndex = 6\n        body.Parent = card\n        return card\n    end\n\n    makeInfoCard(V1Pages.Welcome, 1, 112, "SLICE HUB V9.8.2.5", "Free and Premium share the cleaned Combat page, lobby-only weapon preparation, and the corrected tier-aware Titans Per Swing route. Waves remain unchanged in this patch.")\n    makeInfoCard(V1Pages.Welcome, 2, 150, "CONTROL ROUTES", "FARMING \u{2022} Missions, Raids, and Premium Waves\\nCOMBAT \u{2022} target priority, blades, spears, boss pressure, and stall flow\\nUTILITY \u{2022} stats, webhooks, optimization\\nCONFIGURATION \u{2022} profiles, persistence, themes, keybinds")\n\n    local sessionCard = makeInfoCard(V1Pages.Welcome, 3, 92, "SESSION ACTIONS", "Return to the AOT:R lobby from any supported mission or raid instance.")\n    local lobbyButton = Instance.new("TextButton")\n    lobbyButton.AnchorPoint = Vector2.new(1, 1)\n    lobbyButton.Position = UDim2.new(1, -14, 1, -12)\n    lobbyButton.Size = UDim2.fromOffset(176, 30)\n    lobbyButton.BackgroundColor3 = Theme.Button\n    lobbyButton.BorderSizePixel = 0\n    lobbyButton.AutoButtonColor = false\n    lobbyButton.Font = Enum.Font.GothamBold\n    lobbyButton.Text = "TELEPORT TO LOBBY"\n    lobbyButton.TextColor3 = Theme.Text\n    lobbyButton.TextSize = 10\n    lobbyButton.ZIndex = 7\n    lobbyButton.Parent = sessionCard\n    uiCorner(lobbyButton, 4)\n    uiStroke(lobbyButton, Theme.Stroke, 0.20)\n    lobbyButton.Activated:Connect(function()\n        if ReturnToLobby and ReturnToLobby.Run then ReturnToLobby.Run() end\n    end)\n    makeInfoCard(V1Pages.Discord, 1, 128, "JOIN DISCORD", "Join the Slice Hub Discord for feature previews, sneaks, new releases, support, giveaways, premium updates, and community chat.\\n\\nInvite: discord.gg/Fg3tQG5CSA")\n    makeInfoCard(V1Pages.Discord, 2, 92, "WHY JOIN?", "Get release notes, feature polls, premium announcements, bug status, and help from the community.")\n\n    setV1Page("Welcome")\n    print("[SliceHub V3] EXACT ENGINE UI READY")\nend)()\n\nlocal function createToggle(parent, order, displayName, description, default, callback)\n    local enabled = default == true\n\n    local row = Instance.new("TextButton")\n    row.Name = displayName:gsub("%s+", "") .. "Toggle"\n    row.LayoutOrder = order\n    row.Size = UDim2.new(1, 0, 0, 52)\n    row.BackgroundColor3 = Theme.ElementBg\n    row.BackgroundTransparency = 0.18\n    row.BorderSizePixel = 0\n    row.Text = ""\n    row.AutoButtonColor = false\n    row.Parent = parent\n\n    local corner = Instance.new("UICorner")\n    corner.CornerRadius = UDim.new(0, 3)\n    corner.Parent = row\n\n    local stroke = Instance.new("UIStroke")\n    stroke.Color = Theme.Stroke\n    stroke.Transparency = 0.30\n    stroke.Thickness = 1\n    stroke.Parent = row\n\n    local nameLabel = Instance.new("TextLabel")\n    nameLabel.Position = UDim2.fromOffset(6, 5)\n    nameLabel.Size = UDim2.new(1, -54, 0, 20)\n    nameLabel.BackgroundTransparency = 1\n    nameLabel.Font = Enum.Font.GothamMedium\n    nameLabel.Text = displayName\n    nameLabel.TextColor3 = Theme.Text\n    nameLabel.TextSize = 13\n    nameLabel.TextXAlignment = Enum.TextXAlignment.Left\n    nameLabel.Parent = row\n\n    local descriptionLabel = Instance.new("TextLabel")\n    descriptionLabel.Position = UDim2.fromOffset(6, 26)\n    descriptionLabel.Size = UDim2.new(1, -54, 0, 16)\n    descriptionLabel.BackgroundTransparency = 1\n    descriptionLabel.Font = Enum.Font.Gotham\n    descriptionLabel.Text = description\n    descriptionLabel.TextColor3 = Theme.TextDim\n    descriptionLabel.TextSize = 10\n    descriptionLabel.TextTruncate = Enum.TextTruncate.AtEnd\n    descriptionLabel.TextXAlignment = Enum.TextXAlignment.Left\n    descriptionLabel.Parent = row\n\n    local check = Instance.new("TextLabel")\n    check.Name = "Checkbox"\n    check.AnchorPoint = Vector2.new(1, 0.5)\n    check.Position = UDim2.new(1, -6, 0.5, 0)\n    check.Size = UDim2.fromOffset(28, 28)\n    check.BackgroundColor3 = Theme.ElementBg\n    check.BorderSizePixel = 0\n    check.Font = Enum.Font.GothamBold\n    check.Text = ""\n    check.TextColor3 = Color3.fromRGB(255, 255, 255)\n    check.TextSize = 18\n    check.Parent = row\n\n    local checkCorner = Instance.new("UICorner")\n    checkCorner.CornerRadius = UDim.new(0, 4)\n    checkCorner.Parent = check\n\n    local checkStroke = Instance.new("UIStroke")\n    checkStroke.Color = Theme.StrokeSoft\n    checkStroke.Transparency = 0.12\n    checkStroke.Thickness = 1\n    checkStroke.Parent = check\n\n    local function renderState(animated)\n        local duration = animated and 0.14 or 0\n        tween(row, duration, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {\n            BackgroundColor3 = enabled and Theme.CardActive or Theme.ElementBg,\n            BackgroundTransparency = enabled and 0.02 or 0.18,\n        })\n        tween(check, duration, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {\n            BackgroundColor3 = enabled and Theme.Accent or Theme.ElementBg,\n        })\n        tween(checkStroke, duration, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {\n            Color = enabled and Theme.AccentLight or Theme.StrokeSoft,\n            Transparency = enabled and 0 or 0.12,\n        })\n        check.Text = enabled and "\u{2713}" or ""\n    end\n\n    local controller = {}\n    function controller:Set(value, animated)\n        value = value == true\n        if value == enabled then return false end\n        enabled = value\n        renderState(animated ~= false)\n        callback(enabled)\n        return true\n    end\n    function controller:Get()\n        return enabled\n    end\n\n    row.MouseEnter:Connect(function()\n        tween(stroke, 0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Transparency = 0.04})\n    end)\n    row.MouseLeave:Connect(function()\n        tween(stroke, 0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Transparency = 0.30})\n    end)\n    row.Activated:Connect(function()\n        controller:Set(not enabled, true)\n    end)\n\n    renderState(false)\n    callback(enabled)\n    return controller\nend\n\nlocal function createPremiumLockedToggle(parent, order, displayName, description)\n    local row = Instance.new("TextButton")\n    row.Name = displayName:gsub("%s+", "") .. "PremiumLocked"\n    row.LayoutOrder = order\n    row.Size = UDim2.new(1, 0, 0, 52)\n    row.BackgroundColor3 = Theme.ElementBg\n    row.BackgroundTransparency = 0.28\n    row.BorderSizePixel = 0\n    row.Text = ""\n    row.AutoButtonColor = false\n    row.Parent = parent\n\n    local corner = Instance.new("UICorner")\n    corner.CornerRadius = UDim.new(0, 3)\n    corner.Parent = row\n\n    local stroke = Instance.new("UIStroke")\n    stroke.Color = Theme.StrokeSoft or Theme.Stroke\n    stroke.Transparency = 0.18\n    stroke.Thickness = 1\n    stroke.Parent = row\n\n    local nameLabel = Instance.new("TextLabel")\n    nameLabel.Position = UDim2.fromOffset(6, 5)\n    nameLabel.Size = UDim2.new(1, -64, 0, 20)\n    nameLabel.BackgroundTransparency = 1\n    nameLabel.Font = Enum.Font.GothamMedium\n    nameLabel.Text = tostring(displayName or "Premium Feature") .. " \u{1f512}"\n    nameLabel.TextColor3 = Theme.TextMuted or Theme.Text\n    nameLabel.TextSize = 13\n    nameLabel.TextXAlignment = Enum.TextXAlignment.Left\n    nameLabel.Parent = row\n\n    local descriptionLabel = Instance.new("TextLabel")\n    descriptionLabel.Position = UDim2.fromOffset(6, 26)\n    descriptionLabel.Size = UDim2.new(1, -64, 0, 16)\n    descriptionLabel.BackgroundTransparency = 1\n    descriptionLabel.Font = Enum.Font.Gotham\n    descriptionLabel.Text = description or "Premium only. Upgrade to unlock this feature."\n    descriptionLabel.TextColor3 = Theme.TextDim\n    descriptionLabel.TextSize = 10\n    descriptionLabel.TextTruncate = Enum.TextTruncate.AtEnd\n    descriptionLabel.TextXAlignment = Enum.TextXAlignment.Left\n    descriptionLabel.Parent = row\n\n    local lockBox = Instance.new("TextLabel")\n    lockBox.Name = "PremiumLock"\n    lockBox.AnchorPoint = Vector2.new(1, 0.5)\n    lockBox.Position = UDim2.new(1, -6, 0.5, 0)\n    lockBox.Size = UDim2.fromOffset(28, 28)\n    lockBox.BackgroundColor3 = Theme.ElementBg\n    lockBox.BorderSizePixel = 0\n    lockBox.Font = Enum.Font.GothamBold\n    lockBox.Text = "\u{1f512}"\n    lockBox.TextColor3 = Theme.TextMuted or Theme.Text\n    lockBox.TextSize = 15\n    lockBox.Parent = row\n\n    local lockCorner = Instance.new("UICorner")\n    lockCorner.CornerRadius = UDim.new(0, 4)\n    lockCorner.Parent = lockBox\n\n    local lockStroke = Instance.new("UIStroke")\n    lockStroke.Color = Theme.StrokeSoft or Theme.Stroke\n    lockStroke.Transparency = 0.12\n    lockStroke.Thickness = 1\n    lockStroke.Parent = lockBox\n\n    row.MouseEnter:Connect(function()\n        tween(stroke, 0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Transparency = 0.04})\n    end)\n    row.MouseLeave:Connect(function()\n        tween(stroke, 0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Transparency = 0.18})\n    end)\n    row.Activated:Connect(function()\n        if type(showNotification) == "function" then\n            showNotification("Premium feature", tostring(displayName or "This feature") .. " is available in Premium only.", "info")\n        end\n    end)\n\n    local controller = {}\n    function controller:Set()\n        return false\n    end\n    function controller:Get()\n        return false\n    end\n    return controller\nend\n\nfunction createIntegerSlider(parent, order, displayName, description, minimum, maximum, default, callback)\n    local currentValue = math.clamp(math.floor((tonumber(default) or minimum) + 0.5), minimum, maximum)\n    local draggingSlider = false\n\n    local row = Instance.new("Frame")\n    row.Name = displayName:gsub("%s+", "") .. "Slider"\n    row.LayoutOrder = order\n    row.Size = UDim2.new(1, 0, 0, 64)\n    row.BackgroundColor3 = Theme.ElementBg\n    row.BackgroundTransparency = 0.18\n    row.BorderSizePixel = 0\n    row.Parent = parent\n\n    local corner = Instance.new("UICorner")\n    corner.CornerRadius = UDim.new(0, 3)\n    corner.Parent = row\n    local stroke = Instance.new("UIStroke")\n    stroke.Color = Theme.Stroke\n    stroke.Transparency = 0.30\n    stroke.Thickness = 1\n    stroke.Parent = row\n\n    local nameLabel = Instance.new("TextLabel")\n    nameLabel.Position = UDim2.fromOffset(6, 5)\n    nameLabel.Size = UDim2.new(1, -80, 0, 20)\n    nameLabel.BackgroundTransparency = 1\n    nameLabel.Font = Enum.Font.GothamMedium\n    nameLabel.Text = displayName\n    nameLabel.TextColor3 = Theme.Text\n    nameLabel.TextSize = 13\n    nameLabel.TextXAlignment = Enum.TextXAlignment.Left\n    nameLabel.Parent = row\n\n    local descriptionLabel = Instance.new("TextLabel")\n    descriptionLabel.Position = UDim2.fromOffset(6, 24)\n    descriptionLabel.Size = UDim2.new(1, -18, 0, 16)\n    descriptionLabel.BackgroundTransparency = 1\n    descriptionLabel.Font = Enum.Font.Gotham\n    descriptionLabel.Text = description\n    descriptionLabel.TextColor3 = Theme.TextDim\n    descriptionLabel.TextSize = 10\n    descriptionLabel.TextTruncate = Enum.TextTruncate.AtEnd\n    descriptionLabel.TextXAlignment = Enum.TextXAlignment.Left\n    descriptionLabel.Parent = row\n\n    local valueText = Instance.new("TextLabel")\n    valueText.AnchorPoint = Vector2.new(1, 0)\n    valueText.Position = UDim2.new(1, -6, 0, 5)\n    valueText.Size = UDim2.fromOffset(68, 20)\n    valueText.BackgroundTransparency = 1\n    valueText.Font = Enum.Font.GothamMedium\n    valueText.TextColor3 = Theme.TextMuted\n    valueText.TextSize = 12\n    valueText.TextXAlignment = Enum.TextXAlignment.Right\n    valueText.Parent = row\n\n    local track = Instance.new("TextButton")\n    track.Name = "Track"\n    track.Position = UDim2.fromOffset(6, 49)\n    track.Size = UDim2.new(1, -12, 0, 4)\n    track.BackgroundColor3 = Color3.fromRGB(43, 42, 50)\n    track.Text = ""\n    track.AutoButtonColor = false\n    track.BorderSizePixel = 0\n    track.Parent = row\n    local trackCorner = Instance.new("UICorner")\n    trackCorner.CornerRadius = UDim.new(1, 0)\n    trackCorner.Parent = track\n\n    local fill = Instance.new("Frame")\n    fill.Name = "Fill"\n    fill.Size = UDim2.fromScale(0, 1)\n    fill.BackgroundColor3 = Theme.Accent\n    fill.BorderSizePixel = 0\n    fill.Parent = track\n    local fillCorner = Instance.new("UICorner")\n    fillCorner.CornerRadius = UDim.new(1, 0)\n    fillCorner.Parent = fill\n\n    local knob = Instance.new("Frame")\n    knob.Name = "Knob"\n    knob.AnchorPoint = Vector2.new(0.5, 0.5)\n    knob.Position = UDim2.new(0, 0, 0.5, 0)\n    knob.Size = UDim2.fromOffset(10, 10)\n    knob.BackgroundColor3 = Color3.fromRGB(244, 244, 247)\n    knob.BorderSizePixel = 0\n    knob.Parent = track\n    local knobCorner = Instance.new("UICorner")\n    knobCorner.CornerRadius = UDim.new(1, 0)\n    knobCorner.Parent = knob\n\n    local controller = {}\n    local function setValue(value, animated, invokeCallback)\n        value = math.clamp(math.floor((tonumber(value) or minimum) + 0.5), minimum, maximum)\n        local changed = value ~= currentValue\n        currentValue = value\n        local alpha = maximum == minimum and 0 or (currentValue - minimum) / (maximum - minimum)\n        valueText.Text = tostring(currentValue)\n        if animated then\n            tween(fill, 0.10, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Size = UDim2.fromScale(alpha, 1)})\n            tween(knob, 0.10, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {Position = UDim2.new(alpha, 0, 0.5, 0)})\n        else\n            fill.Size = UDim2.fromScale(alpha, 1)\n            knob.Position = UDim2.new(alpha, 0, 0.5, 0)\n        end\n        if changed and invokeCallback ~= false then callback(currentValue) end\n        return changed\n    end\n\n    function controller:Set(value, animated)\n        return setValue(value, animated ~= false, true)\n    end\n    function controller:Get() return currentValue end\n\n    local function setFromScreenX(screenX)\n        local width = track.AbsoluteSize.X\n        if width <= 0 then return end\n        local alpha = math.clamp((screenX - track.AbsolutePosition.X) / width, 0, 1)\n        setValue(minimum + (maximum - minimum) * alpha, true, true)\n    end\n\n    track.InputBegan:Connect(function(input)\n        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then\n            draggingSlider = true\n            setFromScreenX(input.Position.X)\n            knob.Size = UDim2.fromOffset(13, 13)\n        end\n    end)\n    track.InputEnded:Connect(function(input)\n        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then\n            draggingSlider = false\n            knob.Size = UDim2.fromOffset(10, 10)\n        end\n    end)\n    UserInputService.InputChanged:Connect(function(input)\n        if not draggingSlider then return end\n        if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then\n            setFromScreenX(input.Position.X)\n        end\n    end)\n    UserInputService.InputEnded:Connect(function(input)\n        if draggingSlider and (input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch) then\n            draggingSlider = false\n            knob.Size = UDim2.fromOffset(10, 10)\n        end\n    end)\n\n    setValue(currentValue, false, false)\n    callback(currentValue)\n    return controller\nend\n\nControls = {}\n\n\n-- V9.8.1 Premium Waves page. Auto Farm reuses the existing blade engine.\n;(function()\n    local function createComingSoonRow(parent, order, displayName, description)\n        local row = Instance.new("TextButton")\n        row.Name = displayName:gsub("%s+", "") .. "ComingSoon"\n        row.LayoutOrder = order\n        row.Size = UDim2.new(1, 0, 0, 52)\n        row.BackgroundColor3 = Theme.ElementBg\n        row.BackgroundTransparency = 0.28\n        row.BorderSizePixel = 0\n        row.Text = ""\n        row.AutoButtonColor = false\n        row.Parent = parent\n\n        local corner = Instance.new("UICorner")\n        corner.CornerRadius = UDim.new(0, 3)\n        corner.Parent = row\n\n        local stroke = Instance.new("UIStroke")\n        stroke.Color = Theme.Stroke\n        stroke.Transparency = 0.45\n        stroke.Parent = row\n\n        local title = Instance.new("TextLabel")\n        title.Position = UDim2.fromOffset(6, 5)\n        title.Size = UDim2.new(1, -116, 0, 20)\n        title.BackgroundTransparency = 1\n        title.Font = Enum.Font.GothamMedium\n        title.Text = displayName\n        title.TextColor3 = Theme.TextMuted\n        title.TextSize = 13\n        title.TextXAlignment = Enum.TextXAlignment.Left\n        title.Parent = row\n\n        local body = Instance.new("TextLabel")\n        body.Position = UDim2.fromOffset(6, 26)\n        body.Size = UDim2.new(1, -116, 0, 16)\n        body.BackgroundTransparency = 1\n        body.Font = Enum.Font.Gotham\n        body.Text = description\n        body.TextColor3 = Theme.TextDim\n        body.TextSize = 9\n        body.TextXAlignment = Enum.TextXAlignment.Left\n        body.TextTruncate = Enum.TextTruncate.AtEnd\n        body.Parent = row\n\n        local badge = Instance.new("TextLabel")\n        badge.AnchorPoint = Vector2.new(1, 0.5)\n        badge.Position = UDim2.new(1, -8, 0.5, 0)\n        badge.Size = UDim2.fromOffset(96, 24)\n        badge.BackgroundColor3 = Theme.CardActive\n        badge.BorderSizePixel = 0\n        badge.Font = Enum.Font.GothamBold\n        badge.Text = "COMING SOON"\n        badge.TextColor3 = Theme.TextDim\n        badge.TextSize = 9\n        badge.Parent = row\n        local badgeCorner = Instance.new("UICorner")\n        badgeCorner.CornerRadius = UDim.new(0, 7)\n        badgeCorner.Parent = badge\n\n        row.Activated:Connect(function()\n            showNotification("Coming soon", displayName .. " is in the Waves roadmap and is GUI-only in this build.", "info")\n        end)\n\n        return row\n    end\n\n    if SliceHubWaveAutomationAllowed() then\n        Controls.WavesAutoFarm = createToggle(\n            wavesPage or V1Pages.Waves,\n            1,\n            "Auto Farm Waves",\n            "Auto-votes READY, waits for the cutscene/countdown to release, then reuses the proven Auto Blades engine.",\n            State.WavesAutoFarmEnabled,\n            function(value)\n                State.WavesAutoFarmEnabled = value == true\n                if State.WavesAutoFarmEnabled then\n                    WavesRuntimeDirector.EnsureBladeFarm()\n                    WavesRuntimeDirector.TryReady()\n                else\n                    WavesRuntimeDirector.DisableOwnedBladeFarm()\n                end\n                saveSettingsIfReady()\n            end\n        )\n\n        Controls.WavesAutoPickup = createToggle(\n            wavesPage or V1Pages.Waves,\n            2,\n            "Auto Pick Up Crates",\n            "Claims your supply crate immediately after the live wave begins; temporary pre-wave crates are ignored.",\n            State.WavesAutoPickupEnabled,\n            function(value)\n                State.WavesAutoPickupEnabled = value == true\n                saveSettingsIfReady()\n                if State.WavesAutoPickupEnabled then\n                    local crate = WavesRuntimeDirector.GetPlayerCrate()\n                    if crate then WavesRuntimeDirector.ProcessCrate(crate) end\n                end\n            end\n        )\n\n        Controls.WavesAutoDeliver = createToggle(\n            wavesPage or V1Pages.Waves,\n            3,\n            "Auto Deliver Crates",\n            "Carries an occupied crate to the live Workspace.Waves.Props.Dropoff station and verifies removal.",\n            State.WavesAutoDeliverEnabled,\n            function(value)\n                State.WavesAutoDeliverEnabled = value == true\n                saveSettingsIfReady()\n                if State.WavesAutoDeliverEnabled then\n                    local crate = WavesRuntimeDirector.GetPlayerCrate()\n                    if crate then WavesRuntimeDirector.ProcessCrate(crate) end\n                end\n            end\n        )\n\n        createComingSoonRow(\n            wavesPage or V1Pages.Waves,\n            4,\n            "Auto Upgrade Gear",\n            "UI placeholder only; upgrade protocol will be connected in a future build."\n        )\n\n        createComingSoonRow(\n            wavesPage or V1Pages.Waves,\n            5,\n            "Auto Upgrade HQ",\n            "UI placeholder only; MAX HP / Regen / Replenish logic is not enabled yet."\n        )\n\n        local statusCard = Instance.new("Frame")\n        statusCard.Name = "WavesRuntimeStatus"\n        statusCard.LayoutOrder = 6\n        statusCard.Size = UDim2.new(1, 0, 0, 70)\n        statusCard.BackgroundColor3 = Theme.CardSoft\n        statusCard.BorderSizePixel = 0\n        statusCard.Parent = wavesPage or V1Pages.Waves\n        local statusCorner = Instance.new("UICorner")\n        statusCorner.CornerRadius = UDim.new(0, 8)\n        statusCorner.Parent = statusCard\n        local statusStroke = Instance.new("UIStroke")\n        statusStroke.Color = Theme.StrokeSoft\n        statusStroke.Transparency = 0.35\n        statusStroke.Parent = statusCard\n\n        local title = Instance.new("TextLabel")\n        title.Position = UDim2.fromOffset(12, 8)\n        title.Size = UDim2.new(1, -24, 0, 18)\n        title.BackgroundTransparency = 1\n        title.Font = Enum.Font.GothamBold\n        title.Text = "WAVES RUNTIME"\n        title.TextColor3 = Theme.Text\n        title.TextSize = 11\n        title.TextXAlignment = Enum.TextXAlignment.Left\n        title.Parent = statusCard\n\n        local status = Instance.new("TextLabel")\n        status.Position = UDim2.fromOffset(12, 29)\n        status.Size = UDim2.new(1, -24, 0, 30)\n        status.BackgroundTransparency = 1\n        status.Font = Enum.Font.GothamMedium\n        status.Text = "Status: " .. tostring(WavesRuntimeDirector.Status or "Idle")\n        status.TextColor3 = Theme.TextMuted\n        status.TextSize = 10\n        status.TextWrapped = true\n        status.TextXAlignment = Enum.TextXAlignment.Left\n        status.TextYAlignment = Enum.TextYAlignment.Top\n        status.Parent = statusCard\n        WavesRuntimeDirector.UIStatusLabel = status\n    end\nend)()\n\n-- V5.5.0: build the only Raid control after Controls exists.\n;(function()\n    local raidUiOk, raidUiErr = xpcall(function()\n        Controls.RaidAutoOpenChests = createToggle(\n            raidsPage or V1Pages.Raids,\n            1,\n            "Auto Open Raid Chests",\n            "When the chest screen appears, opens Free first and then Premium when an Emperor\'s Key is available.",\n            State.RaidAutoOpenChestsEnabled,\n            function(value)\n                State.RaidAutoOpenChestsEnabled = value == true\n                saveSettingsIfReady()\n            end\n        )\n\n        if type(SliceHubFeatureEnabled) == "function" and not SliceHubFeatureEnabled("RaidAutomation") then\n            createPremiumLockedToggle(\n                raidsPage or V1Pages.Raids,\n                2,\n                "Auto Farm Raids",\n                "Premium only \u{2014} full raid automation for Female, Attack, and Armored raids."\n            )\n\n            createPremiumLockedToggle(\n                raidsPage or V1Pages.Raids,\n                3,\n                "Auto Raid Queue",\n                "Premium only \u{2014} queues raid runs and continues across teleports with retry logic."\n            )\n\n            createPremiumLockedToggle(\n                raidsPage or V1Pages.Raids,\n                4,\n                "Female / Attack / Armored Raids",\n                "Premium only \u{2014} Colossal Spears route remains available in Free."\n            )\n        end\n    end, function(err)\n        return tostring(err)\n    end)\n\n    if not raidUiOk then\n        warn("[SliceHub V5.5.0][GUI] Raid chest toggle build failed: " .. tostring(raidUiErr))\n    end\nend)()\n\nStatsTracker = {\n\tLabels = {},\n\tLastSignature = "",\n\tLastAt = 0,\n}\n\nfunction StatsTracker:Fmt(value)\n\tlocal number = tonumber(value) or 0\n\tlocal text = tostring(math.floor(number))\n\tlocal sign = ""\n\tif string.sub(text, 1, 1) == "-" then\n\t\tsign = "-"\n\t\ttext = string.sub(text, 2)\n\tend\n\tlocal result = text\n\twhile true do\n\t\tlocal nextText, replaced = string.gsub(result, "^(%d+)(%d%d%d)", "%1,%2")\n\t\tresult = nextText\n\t\tif replaced == 0 then break end\n\tend\n\treturn sign .. result\nend\n\nfunction StatsTracker:ResultKind(data)\n\tlocal joined = ""\n\tif type(data) == "table" and type(data.lines) == "table" then\n\t\tjoined = string.lower(table.concat(data.lines, " "))\n\tend\n\tif string.find(joined, "raid", 1, true) then\n\t\treturn "raid"\n\tend\n\treturn "mission"\nend\n\nfunction StatsTracker:AddResult(data)\n\tif type(data) ~= "table" then return end\n\tlocal sig = table.concat({\n\t\ttostring(data.resultType or "result"),\n\t\ttostring(data.timeTaken or ""),\n\t\ttostring(data.titanKills or 0),\n\t\ttostring(data.exp or 0),\n\t\ttostring(data.gold or 0),\n\t\ttostring(data.gems or 0),\n\t}, "|")\n\tlocal now = tick()\n\tif sig == self.LastSignature and now - (self.LastAt or 0) < 25 then\n\t\treturn\n\tend\n\tself.LastSignature = sig\n\tself.LastAt = now\n\n\tlocal kind = self:ResultKind(data)\n\tlocal failed = tostring(data.resultType or "") == "failed"\n\tif kind == "raid" then\n\t\tif failed then\n\t\t\tState.StatsRaidFailed = (tonumber(State.StatsRaidFailed) or 0) + 1\n\t\telse\n\t\t\tState.StatsRaidCompleted = (tonumber(State.StatsRaidCompleted) or 0) + 1\n\t\tend\n\telse\n\t\tif failed then\n\t\t\tState.StatsMissionFailed = (tonumber(State.StatsMissionFailed) or 0) + 1\n\t\telse\n\t\t\tState.StatsMissionCompleted = (tonumber(State.StatsMissionCompleted) or 0) + 1\n\t\tend\n\tend\n\n\tState.StatsTotalXP = (tonumber(State.StatsTotalXP) or 0) + (tonumber(data.exp) or 0)\n\tState.StatsTotalGold = (tonumber(State.StatsTotalGold) or 0) + (tonumber(data.gold) or 0)\n\tState.StatsTotalGems = (tonumber(State.StatsTotalGems) or 0) + (tonumber(data.gems) or 0)\n\tself:Refresh()\n\tsaveSettingsIfReady()\nend\n\nfunction StatsTracker:Reset()\n\tState.StatsMissionCompleted = 0\n\tState.StatsRaidCompleted = 0\n\tState.StatsMissionFailed = 0\n\tState.StatsRaidFailed = 0\n\tState.StatsTotalXP = 0\n\tState.StatsTotalGold = 0\n\tState.StatsTotalGems = 0\n\tself:Refresh()\n\tsaveSettingsIfReady()\nend\n\nfunction StatsTracker:Refresh()\n\tlocal labels = self.Labels or {}\n\tif labels.MissionCompleted then labels.MissionCompleted.Text = "Missions completed: " .. self:Fmt(State.StatsMissionCompleted) end\n\tif labels.RaidCompleted then labels.RaidCompleted.Text = "Raids completed: " .. self:Fmt(State.StatsRaidCompleted) end\n\tif labels.MissionFailed then labels.MissionFailed.Text = "Failed missions: " .. self:Fmt(State.StatsMissionFailed) end\n\tif labels.RaidFailed then labels.RaidFailed.Text = "Failed raids: " .. self:Fmt(State.StatsRaidFailed) end\n\tif labels.TotalXP then labels.TotalXP.Text = "Total XP: " .. self:Fmt(State.StatsTotalXP) end\n\tif labels.TotalGold then labels.TotalGold.Text = "Total Gold: " .. self:Fmt(State.StatsTotalGold) end\n\tif labels.TotalGems then labels.TotalGems.Text = "Total Gems: " .. self:Fmt(State.StatsTotalGems) end\nend\n\nSpearSupport = {\n\tStatusLabel = nil,\n\tRefilling = false,\n\tLastFireMessage = "Spears disabled in v111",\n}\n\nfunction SpearSupport:GetFooterText()\n\treturn "Spears disabled in v111; blades only."\nend\n\nfunction SpearSupport:RefreshStatus()\n\tif self.StatusLabel then\n\t\tself.StatusLabel.Text = self:GetFooterText()\n\tend\nend\n\nfunction SpearSupport:ValidateMode(mode)\n\tif tostring(mode or "Blades") == "Spears" then\n\t\tshowNotification("Spears disabled", "v111 is blades-only. Use Farm + Titan Ripper.", "info")\n\tend\nend\n\nfunction SpearSupport:FireAtCurrentTarget(manual)\n\tif manual then\n\t\tshowNotification("Spears disabled", "Auto spears removed; blades/ripper only.", "info")\n\tend\n\treturn false\nend\n\nfunction SpearSupport:RefillNow(manual)\n\tif manual then\n\t\tshowNotification("Spears disabled", "Use Auto Blade Refill on the Blades page.", "info")\n\tend\n\treturn false\nend\n\nfunction SpearSupport:ResetStuckSpear(manual)\n\tif manual then\n\t\tshowNotification("Spears disabled", "No spear automation is running in v105.", "info")\n\tend\n\treturn false\nend\n\nWeaponUI = {}\n\n\nReturnToLobby = {\n\tRunning = false,\n\tLastMessage = "Idle",\n\tLobbyPlaceId = LOBBY_PLACE_ID,\n}\n\n;(function() -- direct return-to-lobby teleport scoped to avoid Luau\'s 200 local-register limit\n\tlocal function stopFarmBeforeReturning()\n\t\tState.FarmEnabled = false\n\t\tState.IsGrabbed = false\n\t\tstatusText = "Returning to lobby..."\n\n\t\tif Controls and Controls.Farm and Controls.Farm.Set then\n\t\t\tpcall(function()\n\t\t\t\tControls.Farm:Set(false, true)\n\t\t\tend)\n\t\tend\n\n\t\tif humanoid and humanoid.Health > 0 then\n\t\t\tpcall(function()\n\t\t\t\thumanoid.PlatformStand = false\n\t\t\t\thumanoid.Sit = false\n\t\t\t\thumanoid:ChangeState(Enum.HumanoidStateType.Freefall)\n\t\t\tend)\n\t\tend\n\n\t\tif rootPart and rootPart.Parent then\n\t\t\tpcall(function()\n\t\t\t\trootPart.Anchored = false\n\t\t\t\trootPart.AssemblyAngularVelocity = Vector3.zero\n\t\t\t\trootPart.AssemblyLinearVelocity = Vector3.zero\n\t\t\tend)\n\t\tend\n\tend\n\n\tlocal function buildTeleportOptions()\n\t\tlocal options = nil\n\t\tpcall(function()\n\t\t\toptions = Instance.new("TeleportOptions")\n\t\t\toptions:SetTeleportData({\n\t\t\t\tSource = "TitanControl",\n\t\t\t\tAction = "ReturnToLobby",\n\t\t\t\tCreatedAt = os.time(),\n\t\t\t})\n\t\tend)\n\t\treturn options\n\tend\n\n\tlocal function tryTeleportToLobby()\n\t\tlocal placeId = tonumber(ReturnToLobby.LobbyPlaceId) or 14916516914\n\t\tlocal errors = {}\n\n\t\tlocal options = buildTeleportOptions()\n\t\tif options then\n\t\t\tlocal ok, err = pcall(function()\n\t\t\t\tTeleportService:TeleportAsync(placeId, {player}, options)\n\t\t\tend)\n\t\t\tif ok then\n\t\t\t\treturn true\n\t\t\tend\n\t\t\ttable.insert(errors, "TeleportAsync: " .. tostring(err))\n\t\tend\n\n\t\tlocal okWithPlayer, errWithPlayer = pcall(function()\n\t\t\tTeleportService:Teleport(placeId, player)\n\t\tend)\n\t\tif okWithPlayer then\n\t\t\treturn true\n\t\tend\n\t\ttable.insert(errors, "Teleport(placeId, player): " .. tostring(errWithPlayer))\n\n\t\tlocal okSelf, errSelf = pcall(function()\n\t\t\tTeleportService:Teleport(placeId)\n\t\tend)\n\t\tif okSelf then\n\t\t\treturn true\n\t\tend\n\t\ttable.insert(errors, "Teleport(placeId): " .. tostring(errSelf))\n\n\t\treturn false, table.concat(errors, " | ")\n\tend\n\n\tfunction ReturnToLobby.Run()\n\t\tif ReturnToLobby.Running then\n\t\t\tshowNotification("Already returning", "Lobby teleport is already running.", "info")\n\t\t\treturn\n\t\tend\n\n\t\tReturnToLobby.Running = true\n\t\ttask.spawn(function()\n\t\t\tlocal ok, err = pcall(function()\n\t\t\t\tstopFarmBeforeReturning()\n\t\t\t\tReturnToLobby.LastMessage = "Teleporting to lobby place " .. tostring(ReturnToLobby.LobbyPlaceId)\n\t\t\t\tshowNotification("Returning to lobby", "Teleporting to PlaceId " .. tostring(ReturnToLobby.LobbyPlaceId) .. ".", "info")\n\n\t\t\t\tlocal success, message = tryTeleportToLobby()\n\t\t\t\tif not success then\n\t\t\t\t\terror("Lobby teleport failed: " .. tostring(message))\n\t\t\t\tend\n\n\t\t\t\t-- If teleport starts successfully, this script will usually stop here because the place changes.\n\t\t\t\tshowNotification("Teleport started", "Leaving this mission and loading the lobby.", "success")\n\t\t\tend)\n\n\t\t\t-- Keep the guard up briefly after a successful teleport call so spam-clicks do not queue duplicates.\n\t\t\ttask.wait(ok and 4 or 0.2)\n\t\t\tReturnToLobby.Running = false\n\n\t\t\tif not ok then\n\t\t\t\tReturnToLobby.LastMessage = tostring(err)\n\t\t\t\twarn("[TitanControl] Return to lobby failed:", err)\n\t\t\t\tshowNotification("Return failed", tostring(err), "error")\n\t\t\tend\n\t\tend)\n\tend\nend)()\n\n\n;(function() -- Combat tab: Target Priority only\n    local priorityCard = Instance.new("Frame")\n    priorityCard.Name = "TargetPriorityCard"\n    priorityCard.LayoutOrder = 1\n    priorityCard.Size = UDim2.new(1, 0, 0, 132)\n    priorityCard.BackgroundColor3 = Theme.CardSoft\n    priorityCard.BorderSizePixel = 0\n    priorityCard.Parent = combatPage\n\n    local cardCorner = Instance.new("UICorner")\n    cardCorner.CornerRadius = UDim.new(0, 11)\n    cardCorner.Parent = priorityCard\n\n    local cardStroke = Instance.new("UIStroke")\n    cardStroke.Color = Theme.StrokeSoft\n    cardStroke.Transparency = 0.34\n    cardStroke.Parent = priorityCard\n\n    local title = Instance.new("TextLabel")\n    title.Position = UDim2.fromOffset(16, 9)\n    title.Size = UDim2.new(1, -32, 0, 20)\n    title.BackgroundTransparency = 1\n    title.Font = Enum.Font.GothamBold\n    title.Text = "TARGET PRIORITY"\n    title.TextColor3 = Theme.Text\n    title.TextSize = 12\n    title.TextXAlignment = Enum.TextXAlignment.Left\n    title.Parent = priorityCard\n\n    local hint = Instance.new("TextLabel")\n    hint.Position = UDim2.fromOffset(16, 30)\n    hint.Size = UDim2.new(1, -32, 0, 16)\n    hint.BackgroundTransparency = 1\n    hint.Font = Enum.Font.Gotham\n    hint.Text = "Raid-critical boss locks stay authoritative."\n    hint.TextColor3 = Theme.TextMuted\n    hint.TextSize = 10\n    hint.TextXAlignment = Enum.TextXAlignment.Left\n    hint.Parent = priorityCard\n\n    local priorityButtons = {}\n    local choices = {\n        {Name = "Balanced", X = 16, Y = 54, W = 112},\n        {Name = "Nearest", X = 140, Y = 54, W = 112},\n        {Name = "Objective", X = 264, Y = 54, W = 122},\n        {Name = "Boss", X = 16, Y = 92, W = 174},\n        {Name = "Abnormal", X = 202, Y = 92, W = 184},\n    }\n\n    refreshTargetPriorityUI = function()\n        State.TargetPriority = V9825NormalizeTargetPriority(State.TargetPriority)\n        for name, button in pairs(priorityButtons) do\n            local selected = name == State.TargetPriority\n            button.BackgroundColor3 = selected and Theme.Accent or Theme.ElementBg\n            button.TextColor3 = selected and Color3.fromRGB(255, 255, 255) or Theme.TextMuted\n            button.Text = string.upper(name) .. (selected and "  \u{2713}" or "")\n        end\n    end\n\n    for _, choice in ipairs(choices) do\n        local button = Instance.new("TextButton")\n        button.Position = UDim2.fromOffset(choice.X, choice.Y)\n        button.Size = UDim2.new(0, choice.W, 0, 28)\n        button.BackgroundColor3 = Theme.ElementBg\n        button.BorderSizePixel = 0\n        button.AutoButtonColor = false\n        button.Font = Enum.Font.GothamBold\n        button.Text = string.upper(choice.Name)\n        button.TextColor3 = Theme.TextMuted\n        button.TextSize = 10\n        button.Parent = priorityCard\n        local corner = Instance.new("UICorner")\n        corner.CornerRadius = UDim.new(0, 8)\n        corner.Parent = button\n        priorityButtons[choice.Name] = button\n\n        button.Activated:Connect(function()\n            State.TargetPriority = choice.Name\n            cachedTitanCandidatesAt = 0\n            if updateObjectiveBrain then pcall(updateObjectiveBrain, true) end\n            refreshTargetPriorityUI()\n            saveSettingsIfReady()\n            showNotification("Target priority", choice.Name .. " targeting enabled.", "success")\n        end)\n    end\n\n    refreshTargetPriorityUI()\nend)()\n\n;(function() -- Auto tab scoped to avoid Luau\'s 200 local-register limit\n\tControls.AutoRetry = createToggle(autoPage, 1, "Auto Retry", "Retries after any result screen: completed or failed.", State.AutoRetryEnabled, function(value)\n\t\tState.AutoRetryEnabled = value == true\n\t\trefreshAutoMissionStatus()\n\t\tsaveSettingsIfReady()\n\t\tif State.AutoRetryEnabled then\n\t\t\ttask.spawn(triggerAuto