\t\trefreshAutoMissionStatus()\n\t\tsaveSettingsIfReady()\n\t\tshowNotification("Auto cycle", "Mission count reset to 0.", "info")\n\tend)\n\n\trefreshAutoMissionStatus()\nend)()\n\n\n;(function() -- Stats tab: persistent run counters + reward totals\n\tlocal function makeCard(order, height, titleText)\n\t\tlocal card = Instance.new("Frame")\n\t\tcard.LayoutOrder = order\n\t\tcard.Size = UDim2.new(1, 0, 0, height)\n\t\tcard.BackgroundColor3 = Theme.CardSoft\n\t\tcard.BorderSizePixel = 0\n\t\tcard.Parent = statsPage\n\t\tlocal corner = Instance.new("UICorner"); corner.CornerRadius = UDim.new(0, 11); corner.Parent = card\n\t\tlocal stroke = Instance.new("UIStroke"); stroke.Color = Theme.StrokeSoft; stroke.Transparency = 0.34; stroke.Parent = card\n\t\tlocal title = Instance.new("TextLabel")\n\t\ttitle.Position = UDim2.fromOffset(16, 9)\n\t\ttitle.Size = UDim2.new(1, -32, 0, 20)\n\t\ttitle.BackgroundTransparency = 1\n\t\ttitle.Font = Enum.Font.GothamBold\n\t\ttitle.Text = titleText\n\t\ttitle.TextColor3 = Theme.Text\n\t\ttitle.TextSize = 12\n\t\ttitle.TextXAlignment = Enum.TextXAlignment.Left\n\t\ttitle.Parent = card\n\t\treturn card\n\tend\n\n\tlocal function statLabel(parent, key, y)\n\t\tlocal label = Instance.new("TextLabel")\n\t\tlabel.Position = UDim2.fromOffset(16, y)\n\t\tlabel.Size = UDim2.new(1, -32, 0, 18)\n\t\tlabel.BackgroundTransparency = 1\n\t\tlabel.Font = Enum.Font.GothamMedium\n\t\tlabel.TextColor3 = Theme.TextMuted\n\t\tlabel.TextSize = 11\n\t\tlabel.TextXAlignment = Enum.TextXAlignment.Left\n\t\tlabel.Parent = parent\n\t\tStatsTracker.Labels[key] = label\n\t\treturn label\n\tend\n\n\tlocal runCard = makeCard(1, 126, "RUN COUNTS")\n\tstatLabel(runCard, "MissionCompleted", 34)\n\tstatLabel(runCard, "RaidCompleted", 55)\n\tstatLabel(runCard, "MissionFailed", 76)\n\tstatLabel(runCard, "RaidFailed", 97)\n\n\tlocal rewardCard = makeCard(2, 110, "TOTAL REWARDS")\n\tstatLabel(rewardCard, "TotalXP", 34)\n\tstatLabel(rewardCard, "TotalGold", 55)\n\tstatLabel(