            BladeCoreUI.Ammo.Text = "Ammo: " .. segments .. "/6 \u{2022} " .. sets .. "/3"\n            end\n            if BladeCoreUI.Alive then\n                BladeCoreUI.Alive.Text = "Titans alive: " .. tostring(alive)\n            end\n            if BladeCoreUI.Anchor then\n                if Config.V6ExactBladeEnabled == true and V6ExactBlade then\n                    BladeCoreUI.Anchor.Text = "V9: " .. tostring(V9RaidCombat and V9RaidCombat.BladeMode or "QUEUE")\n                        .. " \u{2022} Reg " .. tostring(V6ExactBlade.LastCycleTargets or 0)\n                        .. " \u{2022} Slash x" .. tostring(V6ExactBlade.LastCycleSlashes or 0)\n                else\n                    BladeCoreUI.Anchor.Text = "Anchor pack: " .. tostring(anchorCount)\n                end\n            end\n            if BladeCoreUI.State then\n                local phase = V58BladeEngine and tostring(V58BladeEngine.Phase or "READY") or "READY"\n                local detail = V58BladeEngine and tostring(V58BladeEngine.PhaseDetail or "") or ""\n                local ammoDirector = Config.V93BladeAmmoDirectorEnabled == true\n                    and V93BladeAmmoDirector\n                    and tostring(V93BladeAmmoDirector.Status or "READY")\n                    or "LEGACY"\n                BladeCoreUI.State.Text = "State: " .. phase\n                    .. (detail ~= "" and (" \u{2022} " .. detail) or "")\n                    .. " \u{2022} Ammo: " .. ammoDirector\n            end\n            if BladeCoreUI.Burst then\n                BladeCoreUI.Burst.Text = "Last burst: " .. tostring(\n                    V58BladeEngine and V58BladeEngine.BurstSummary() or "no sample"\n                )\n            end\n        end\n    end)\nend)()\n\n;(function() -- Farm tab blades-only focus\n\tState.WeaponMode = "Auto"\n\n\tlocal card = Instance.new("Frame")\n\tcard.Name = "BladesFocusHeader"\n\tcard.LayoutOrder = 1\n\tcard.Size = UDim2.new(1, 0, 0, 54)\n\tcard.BackgroundColor3 =