e shots and fast stale-target rotation.\\n\u{2022} Boss Burst refreshes the exact live raid weak point every shot.\\n\u{2022} Infinite Spears keeps firing at 0 ammo; refill remains active for Titan Blaster recovery.\\n\u{2022} Colossal P1 stays cannon-owned except emergency Eren defense routing.\\n\u{2022} No predictive lead: every shot uses current live target positions."\n    rulesBody.TextColor3 = Theme.TextMuted\n    rulesBody.TextSize = 9\n    rulesBody.TextWrapped = true\n    rulesBody.TextXAlignment = Enum.TextXAlignment.Left\n    rulesBody.TextYAlignment = Enum.TextYAlignment.Top\n    rulesBody.Parent = rulesCard\n\n    print("[SliceHub V3.7][SPEARS-UI] build complete")\n\n    task.spawn(function()\n        while intro.Parent do\n            task.wait(0.20)\n\n            if V35Spears and V35Spears.Telemetry then\n                local ok, info = pcall(V35Spears.Telemetry)\n\n                if ok and type(info) == "table" and SpearStatusLabel then\n                    local refillSuffix = ""\n                    if StationRefill.Running and StationRefill.Mode == "Spears" then\n                        refillSuffix = "  \u{2022}  AUTO REFILLING"\n                    end\n\n                    SpearStatusLabel.Text = string.format(\n                        "Weapon: %s  \u{2022}  Ammo: %s  \u{2022}  Pack: %s  \u{2022}  Last Kills: %s  \u{2022}  Cap\u{2265}%s  \u{2022}  %s%s",\n                        tostring(info.Weapon or "?"),\n                        tostring(info.Ammo ~= nil and info.Ammo or "?"),\n                        tostring(info.Pack or 0),\n                        tostring(info.LastKills or 0),\n                        tostring(info.ObservedCap or 3),\n                        tostring(info.Status or "Idle"),\n                        refillSuffix\n                    )\n                end\n            end\n        end\n    end)\nend)()\n\n    -----------------------------------------------------------------\n    -- V5.7.7 STALL TAB\n    -----------