\n\t\tautoLoadProfileButton.Text = "AUTO LOAD: OFF"\n\t\tautoLoadProfileButton.BackgroundColor3 = Theme.CardActive\n\tend\nend\n\nfunction refreshProfileSelector(preferredName)\n\tprofileNames = getSortedProfileNames()\n\n\tif #profileNames == 0 then\n\t\tselectedProfileIndex = 0\n\t\tselectedProfileLabel.Text = "No saved profiles"\n\t\tselectedProfileLabel.TextColor3 = Theme.TextMuted\n\t\trefreshAutoLoadProfileButton()\n\t\treturn\n\tend\n\n\tlocal preferredKey = resolveProfileKey(preferredName)\n\tif preferredKey then\n\t\tfor index, name in ipairs(profileNames) do\n\t\t\tif name == preferredKey then\n\t\t\t\tselectedProfileIndex = index\n\t\t\t\tbreak\n\t\t\tend\n\t\tend\n\tend\n\n\tif selectedProfileIndex < 1 or selectedProfileIndex > #profileNames then\n\t\tselectedProfileIndex = 1\n\tend\n\n\tselectedProfileLabel.Text = profileNames[selectedProfileIndex]\n\tselectedProfileLabel.TextColor3 = Theme.Text\n\trefreshAutoLoadProfileButton()\nend\n\nfunction moveProfileSelection(direction)\n\tif #profileNames == 0 then return end\n\tselectedProfileIndex = ((selectedProfileIndex - 1 + direction) % #profileNames) + 1\n\tlocal selectedName = profileNames[selectedProfileIndex]\n\tselectedProfileLabel.Text = selectedName\n\tprofileNameBox.Text = selectedName\n\trefreshAutoLoadProfileButton()\nend\n\npreviousProfile.Activated:Connect(function()\n\tmoveProfileSelection(-1)\nend)\n\nnextProfile.Activated:Connect(function()\n\tmoveProfileSelection(1)\nend)\n\nselectedProfileLabel.Activated:Connect(function()\n\tif selectedProfileIndex >= 1 and profileNames[selectedProfileIndex] then\n\t\tprofileNameBox.Text = profileNames[selectedProfileIndex]\n\tend\nend)\n\nfunction applyProfile(profile, autoLoadMode)\n\tif not profile then return false end\n\n\tControls.TitansPerHit:Set(SliceHubMissionClampTPS(profile.TitansPerHit, Config.TitansPerHit), true)\n\tControls.TitanRipper:Set(profile.TitanRipperEnabled, true)\n    if Controls.SpearSupport then Controls.SpearSupport:Set(profile.SpearSupportEnabled == true, true) end\n    if Controls.SpearAutoFire then Controls.SpearAutoFire:Set(profile.SpearAutoFireEnabled ~= false, true) end\n    if Controls.SpearAutoRefill then Controls.SpearAutoRefill:Set(profile.SpearAutoRefillEnabled == true, true) end\n    if Controls.SpearInfinite then Controls.SpearInfinite:Set(profile.SpearInfiniteEnabled == true, true) end\n    if Controls.AutoUseBuffs then Controls.AutoUseBuffs:Set(profile.AutoUseBuffsEnabled == true, true) end\n    if Controls.BuffOrderAdvance then Controls.BuffOrderAdvance:Set(profile.BuffOrderAdvanceEnabled ~= false, true) end\n    if Controls.BuffBlackFlare then Controls.BuffBlackFlare:Set(profile.BuffBlackFlareEnabled ~= false, true) end\n    if Controls.BuffOrderRage then Controls.BuffOrderRage:Set(profile.BuffOrderRageEnabled ~= false, true) end\n    if Controls.BuffFoundersOrder then Controls.BuffFoundersOrder:Set(profile.BuffFoundersOrderEnabled ~= false, true) end\n    if Controls.BuffOrderRevolution then Controls.BuffOrderRevolution:Set(profile.BuffOrderRevolutionEnabled ~= false, true) end\n    if Controls.RaidAutoOpenChests then Controls.RaidAutoOpenChests:Set(profile.RaidAutoOpenChestsEnabled == true, true) end\n\tState.TargetPriority = ({Balanced=true, Nearest=true, Objective=true, Boss=true, Abnormal=true})[tostring(profile.TargetPriority or "Balanced")] and tostring(profile.TargetPriority or "Balanced") or "Balanced"\n\tif refreshTargetPriorityUI then refreshTargetPriorityUI() end\n\tcachedTitanCandidatesAt = 0\n\tControls.AutoRefill:Set(profile.AutoRefillEnabled, true)\n\tif Controls.AutoSkipCutscene then\n\t\tControls.AutoSkipCutscene:Set(SliceHubClampAutoSkipCutscene(profile.AutoSkipCutsceneEnabled), true)\n\tend\n\tif Controls.LowGraphics then\n\t\tControls.LowGraphics:Set(profile.PerformanceModeEnabled, true)\n\tend\n\tif Controls.NoEffects then\n\t\tControls.NoEffects:Set(profile.DisableEffectsEnabled, true)\n\tend\n\tif Controls.EcoLoops then\n\t\tControls.EcoLoops:Set(profile.EcoLoopModeEnabled, true)\n\tend\n\tif Controls.MapProps then\n\t\tControls.MapProps:Set(profile.MapPropsHiddenEnabled, true)\n\tend\n\tif Controls.RemoveInjuryKillFlash then\n\t\tControls.RemoveInjuryKillFlash:Set(profile.RemoveInjuryKillFlashEnabled == true, true)\n\tend\n\tif Controls.RemoveDamageText then\n\t\tControls.RemoveDamageText:Set(profile.RemoveDamageTextEnabled == true, true)\n\tend\n    State.OptimizationPreset = tostring(profile.OptimizationPreset or "Default")\n    if Controls.CleanupDeadTitans then Controls.CleanupDeadTitans:Set(profile.CleanupDeadTitansEnabled == true, true) end\n    if Controls.RemoveFog then Controls.RemoveFog:Set(profile.RemoveFogEnabled == true, true) end\n    if Controls.DisablePostProcessing then Controls.DisablePostProcessing:Set(profile.DisablePostProcessingEnabled == true, true) end\n    if Controls.Disable3DRendering then Controls.Disable3DRendering:Set(profile.Disable3DRenderingEnabled == true, true) end\n    State.FPSCap = math.clamp(math.floor((tonumber(profile.FPSCap) or 60) + 0.5), 30, 999)\n    Performance:SetFPSCap(State.FPSCap)\n\tif Controls.AutoMissionLimit then\n\t\tControls.AutoMissionLimit:Set(profile.AutoMissionLimit or 0, true)\n\tend\n\tif Controls.AutoRetry then\n\t\tControls.AutoRetry:Set(profile.AutoRetryEnabled == true, true)\n\tend\n\t-- Apply Farm last so all support settings are ready before movement begins.\n\tif autoLoadMode and PersistentSettings.RestoreFarmOnStart ~= true then\n\t\tControls.Farm:Set(false, true)\n\telse\n\t\tControls.Farm:Set(profile.BladesEnabled == true or profile.FarmEnabled == true, true)\n\tend\n\treturn true\nend\n\nautoLoadProfileButton.Activated:Connect(function()\n\tlocal requestedName = getProfileNameFromUi()\n\tlocal profile, resolvedName = getNamedProfile(requestedName)\n\tif PersistentSettings.AutoLoadProfile == true and resolvedName and resolvedName == PersistentSettings.AutoLoadProfileName then\n\t\tPersistentSettings.AutoLoadProfile = false\n\t\tPersistentSettings.AutoLoadProfileName = ""\n\t\trefreshAutoLoadProfileButton()\n\t\tlocal ok, message = saveAllSettings(true)\n\t\tsetProfileMessage(ok and "Auto-load disabled" or tostring(message), ok)\n\t\tshowNotification(ok and "Auto-load off" or "Save failed", ok and "No profile will auto-load on next run." or tostring(message), ok and "info" or "error")\n\t\treturn\n\tend\n\tif not profile then\n\t\tsetProfileMessage("Select or save a profile first", false)\n\t\tshowNotification("Auto-load failed", "Select or save a config profile first.", "error")\n\t\treturn\n\tend\n\tPersistentSettings.AutoLoadProfile = true\n\tPersistentSettings.AutoLoadProfileName = resolvedName\n\tprofileNameBox.Text = resolvedName\n\trefreshProfileSelector(resolvedName)\n\tlocal ok, message = saveAllSettings(true)\n\tsetProfileMessage(ok and ("Auto-load set: " .. resolvedName) or tostring(message), ok)\n\tshowNotification(ok and "Auto-load set" or "Save failed", ok and (resolvedName .. " loads on startup.") or tostring(message), ok and "success" or "error")\nend)\n\nsaveProfileButton.Activated:Connect(function()\n\tlocal success, message, savedName = saveNamedProfile(profileNameBox.Text)\n\tif savedName then\n\t\tprofileNameBox.Text = savedName\n\t\trefreshProfileSelector(savedName)\n\tend\n\tsetProfileMessage(message, success)\n\tif success then\n\t\tshowNotification("Config saved", savedName or "Profile", "success")\n\telse\n\t\tshowNotification("Save failed", message, "error")\n\tend\nend)\n\nloadProfileButton.Activated:Connect(function()\n\tlocal requestedName = sanitizeProfileName(profileNameBox.Text)\n\tif requestedName == "" and selectedProfileIndex >= 1 then\n\t\trequestedName = profileNames[selectedProfileIndex]\n\tend\n\n\tlocal profile, resolvedName = getNamedProfile(requestedName)\n\tif not profile then\n\t\tsetProfileMessage("Profile not found", false)\n\t\tshowNotification("Load failed", "Profile not found", "error")\n\t\treturn\n\tend\n\n\tapplyProfile(profile)\n\tprofileNameBox.Text = resolvedName\n\trefreshProfileSelector(resolvedName)\n\tsetProfileMessage("Loaded " .. resolvedName, true)\n\tshowNotification("Config loaded", resolvedName, "success")\nend)\n\ndeleteProfileButton.Activated:Connect(function()\n\tlocal requestedName = sanitizeProfileName(profileNameBox.Text)\n\tif requestedName == "" and selectedProfileIndex >= 1 then\n\t\trequestedName = profileNames[selectedProfileIndex]\n\tend\n\n\tlocal success, message = deleteNamedProfile(requestedName)\n\tif success then\n\t\tif PersistentSettings.AutoLoadProfileName == requestedName then\n\t\t\tPersistentSettings.AutoLoadProfile = false\n\t\t\tPersistentSettings.AutoLoadProfileName = ""\n\t\t\tsaveAllSettings(true)\n\t\tend\n\t\tprofileNameBox.Text = ""\n\t\trefreshProfileSelector()\n\tend\n\tsetProfileMessage(message, success)\n\tif success then\n\t\tshowNotification("Config deleted", requestedName, "success")\n\telse\n\t\tshowNotification("Delete failed", message, "error")\n\tend\nend)\n\nprofileNameBox.FocusLost:Connect(function()\n\tprofileNameBox.Text = sanitizeProfileName(profileNameBox.Text)\nend)\n\nrefreshProfileSelector()\nrefreshAutoLoadProfileButton()\ntask.defer(function()\n\tif PersistentSettings.AutoLoadProfile ~= true then return end\n\tlocal autoName = tostring(PersistentSettings.AutoLoadProfileName or "")\n\tif autoName == "" then return end\n\tlocal profile, resolvedName = getNamedProfile(autoName)\n\tif not profile then\n\t\tsetProfileMessage("Auto-load profile missing: " .. autoName, false)\n\t\tshowNotification("Auto-load missing", autoName .. " was not found.", "error")\n\t\treturn\n\tend\n\tapplyProfile(profile, true)\n\tprofileNameBox.Text = resolvedName\n\trefreshProfileSelector(resolvedName)\n\tsetProfileMessage("Auto-loaded " .. resolvedName, true)\n\tshowNotification("Config auto-loaded", resolvedName, "success")\nend)\nend)()\n\n;(function() -- config info/status UI scoped to avoid Luau\'s 200 local-register limit\nconfigInfo = Instance.new("Frame")\nconfigInfo.LayoutOrder = 4\nconfigInfo.Size = UDim2.new(1, 0, 0, 64)\nconfigInfo.BackgroundColor3 = Theme.CardSoft\nconfigInfo.BackgroundTransparency = 0\nconfigInfo.BorderSizePixel = 0\nconfigInfo.Parent = configPage\n\nconfigInfoCorner = Instance.new("UICorner")\nconfigInfoCorner.CornerRadius = UDim.new(0, 11)\nconfigInfoCorner.Parent = configInfo\n\nconfigInfoStroke = Instance.new("UIStroke")\nconfigInfoStroke.Color = Theme.StrokeSoft\nconfigInfoStroke.Transparency = 0.36\nconfigInfoStroke.Parent = configInfo\n\nconfigInfoTitle = Instance.new("TextLabel")\nconfigInfoTitle.Position = UDim2.fromOffset(16, 9)\nconfigInfoTitle.Size = UDim2.new(1, -32, 0, 20)\nconfigInfoTitle.BackgroundTransparency = 1\nconfigInfoTitle.Font = Enum.Font.GothamBold\nconfigInfoTitle.Text = "CURRENT VALUES"\nconfigInfoTitle.TextColor3 = Theme.Text\nconfigInfoTitle.TextSize = 11\nconfigInfoTitle.TextXAlignment = Enum.TextXAlignment.Left\nconfigInfoTitle.Parent = configInfo\n\nconfigInfoText = Instance.new("TextLabel")\nconfigInfoText.Position = UDim2.fromOffset(16, 31)\nconfigInfoText.Size = UDim2.new(1, -32, 0, 23)\nconfigInfoText.BackgroundTransparency = 1\nconfigInfoText.Font = Enum.Font.Gotham\nconfigInfoText.Text = string.format("Speed %d  \u{2022}  Height %d  \u{2022}  Range %d  \u{2022}  Paced burst %.3fs", Config.KillSpeed, Config.SkyHeight, Config.AttackRange, Config.MultiTargetRemoteSpacing)\nconfigInfoText.TextColor3 = Theme.TextMuted\nconfigInfoText.TextSize = 10\nconfigInfoText.TextXAlignment = Enum.TextXAlignment.Left\nconfigInfoText.Parent = configInfo\n\nstatusCard = Instance.new("Frame")\nstatusCard.Name = "StatusCard"\nstatusCard.Position = UDim2.new(0, 226, 1, -38)\nstatusCard.Size = UDim2.new(1, -242, 0, 30)\nstatusCard.BackgroundColor3 = Theme.CardSoft\nstatusCard.BackgroundTransparency = 0\nstatusCard.BorderSizePixel = 0\nstatusCard.Parent = window\n\nstatusCorner = Instance.new("UICorner")\nstatusCorner.CornerRadius = UDim.new(0, 3)\nstatusCorner.Parent = statusCard\n\nstatusStroke = Instance.new("UIStroke")\nstatusStroke.Color = Theme.StrokeSoft\nstatusStroke.Transparency = 0.32\nstatusStroke.Parent = statusCard\n\nstatusDot = Instance.new("Frame")\nstatusDot.AnchorPoint = Vector2.new(0, 0.5)\nstatusDot.Position = UDim2.new(0, 10, 0.5, 0)\nstatusDot.Size = UDim2.fromOffset(7, 7)\nstatusDot.BackgroundColor3 = Theme.AccentLight\nstatusDot.BorderSizePixel = 0\nstatusDot.Parent = statusCard\n\nstatusDotCorner = Instance.new("UICorner")\nstatusDotCorner.CornerRadius = UDim.new(1, 0)\nstatusDotCorner.Parent = statusDot\n\nstatusLabel = Instance.new("TextLabel")\nstatusLabel.Position = UDim2.fromOffset(24, 4)\nstatusLabel.Size = UDim2.new(0.56, -24, 0, 22)\nstatusLabel.BackgroundTransparency = 1\nstatusLabel.Font = Enum.Font.GothamMedium\nstatusLabel.Text = "Status: Disabled"\nstatusLabel.TextColor3 = Theme.TextMuted\nstatusLabel.TextSize = 10\nstatusLabel.TextTruncate = Enum.TextTruncate.AtEnd\nstatusLabel.TextXAlignment = Enum.TextXAlignment.Left\nstatusLabel.Parent = statusCard\n\nstatusDetailLabel = Instance.new("TextLabel")\nstatusDetailLabel.Position = UDim2.new(0.56, 0, 0, 4)\nstatusDetailLabel.Size = UDim2.new(0.44, -10, 0, 22)\nstatusDetailLabel.BackgroundTransparency = 1\nstatusDetailLabel.Font = Enum.Font.GothamMedium\nstatusDetailLabel.Text = "Farm OFF  \u{2022}  Weapon Blades  \u{2022}  Segments ?/6"\nstatusDetailLabel.TextColor3 = Theme.TextDim\nstatusDetailLabel.TextSize = 9\nstatusDetailLabel.TextTruncate = Enum.TextTruncate.AtEnd\nstatusDetailLabel.TextXAlignment = Enum.TextXAlignment.Left\nstatusDetailLabel.Parent = statusCard\nend)()\n\n\napplyThemeToUi = function()\n\tapplyThemePresetValues(PersistentSettings.ThemeName)\n\n\tpcall(function()\n\t\twindow.BackgroundColor3 = Theme.WindowBottom\n\t\ttitleBar.BackgroundColor3 = Theme.Title\n\t\ttabBar.BackgroundColor3 = Theme.TabBar\n\t\ttabSelection.BackgroundColor3 = Theme.TabSelectedA\n\t\twindowStroke.Color = Theme.AccentLight\n\t\ttabBarStroke.Color = Theme.StrokeSoft\n\t\tstatusCard.BackgroundColor3 = Theme.CardSoft\n\t\tstatusDot.BackgroundColor3 = Theme.Accent\n\t\tstatusLabel.TextColor3 = Theme.TextMuted\n\t\tif statusDetailLabel then statusDetailLabel.TextColor3 = Theme.TextDim end\n\t\taccentLine.BackgroundColor3 = Theme.Accent\n\t\tif settingsPage:IsA("ScrollingFrame") then settingsPage.ScrollBarImageColor3 = Theme.AccentLight end\n\n\t\twindowGradient.Color = ColorSequence.new({\n\t\t\tColorSequenceKeypoint.new(0, Theme.WindowTop),\n\t\t\tColorSequenceKeypoint.new(1, Theme.WindowBottom),\n\t\t})\n\t\ttitleGradient.Color = ColorSequence.new({\n\t\t\tColorSequenceKeypoint.new(0, Theme.WindowTop),\n\t\t\tColorSequenceKeypoint.new(1, Theme.Title),\n\t\t})\n\t\ttabSelectionGradient.Color = ColorSequence.new({\n\t\t\tColorSequenceKeypoint.new(0, Theme.TabSelectedA),\n\t\t\tColorSequenceKeypoint.new(1, Theme.TabSelectedB),\n\t\t})\n\t\taccentGradient.Color = ColorSequence.new({\n\t\t\tColorSequenceKeypoint.new(0, Theme.AccentLight),\n\t\t\tColorSequenceKeypoint.new(0.5, Theme.Accent),\n\t\t\tColorSequenceKeypoint.new(1, Theme.TabSelectedA),\n\t\t})\n\tend)\nend\n\n---------------------------------------------------------------------\n-- SETTINGS PAGE UI\n---------------------------------------------------------------------\n\n;(function() -- settings page scoped to avoid Luau\'s 200 local-register limit\n\tlocal settingsUiReady = false\n\n\n\tControls.AutoSaveSettings = createToggle(settingsPage, 1, "Auto Save Settings", "Saves webhook, performance, toggles, and slider changes automatically.", PersistentSettings.AutoSave, function(value)\n\t\tPersistentSettings.AutoSave = value == true\n\t\tif settingsUiReady and settingsSaveReady then\n\t\t\tlocal ok, message = saveAllSettings(true)\n\t\t\tshowNotification(ok and "Settings saved" or "Save failed", tostring(message), ok and "success" or "error")\n\t\tend\n\tend)\n\n\tControls.RestoreFarmStartup = createToggle(settingsPage, 2, "Restore Farm On Startup", "Keeps Farm off by default unless you turn this on.", PersistentSettings.RestoreFarmOnStart, function(value)\n\t\tPersistentSettings.RestoreFarmOnStart = value == true\n\t\tif settingsUiReady and settingsSaveReady then\n\t\t\tlocal ok, message = saveAllSettings(true)\n\t\t\tshowNotification(ok and "Startup setting saved" or "Save failed", tostring(message), ok and "success" or "error")\n\t\tend\n\tend)\n\n\tControls.AutoExecuteTeleport = createToggle(settingsPage, 3, "Auto Execute On Teleport", "Queues the encrypted SH cache before mission/raid retry or any server teleport, then reloads saved settings.", PersistentSettings.AutoExecuteOnTeleport == true, function(value)\n        PersistentSettings.AutoExecuteOnTeleport = value == true\n        if settingsUiReady and settingsSaveReady then\n            local ok, message = saveAllSettings(true)\n            showNotification(ok and "Auto execute saved" or "Save failed", ok and (value and "V5 will queue itself on the next teleport." or "Auto execute disabled.") or tostring(message), ok and "success" or "error")\n        end\n    end)\n\n\tControls.AutoHideGuiLaunch = createToggle(settingsPage, 4, "Auto Hide GUI On Launch", "Starts the mission hub closed so the overlay never steals input from Farm. Use the menu key to reopen it.", PersistentSettings.AutoHideGuiOnLaunch ~= false, function(value)\n\t\tPersistentSettings.AutoHideGuiOnLaunch = value == true\n\t\tif settingsUiReady and settingsSaveReady then\n\t\t\tlocal ok, message = saveAllSettings(true)\n\t\t\tshowNotification(ok and "Auto hide saved" or "Save failed", ok and (value and "Mission GUI will start closed." or "Mission GUI will start open.") or tostring(message), ok and "success" or "error")\n\t\tend\n\tend)\n\n\tControls.MenuScale = createIntegerSlider(settingsPage, 5, "Menu Scale", "Changes the menu size without touching game resolution.", 80, 120, PersistentSettings.MenuScale or 100, function(value)\n\t\tPersistentSettings.MenuScale = math.clamp(math.floor((tonumber(value) or 100) + 0.5), 80, 120)\n\t\twindowScale.Scale = PersistentSettings.MenuScale / 100\n\t\tshadowScale.Scale = windowScale.Scale\n\t\tif settingsUiReady and settingsSaveReady then\n\t\t\tsaveAllSettings(false)\n\t\tend\n\tend)\n\n\n\t-- Laptop-safe menu key rebinding.\n\tlocal menuKeyCard = Instance.new("Frame")\n\tmenuKeyCard.LayoutOrder = 6\n\tmenuKeyCard.Size = UDim2.new(1, 0, 0, 86)\n\tmenuKeyCard.BackgroundColor3 = Theme.Card\n\tmenuKeyCard.BackgroundTransparency = 0\n\tmenuKeyCard.BorderSizePixel = 0\n\tmenuKeyCard.Parent = settingsPage\n\n\tlocal menuKeyCorner = Instance.new("UICorner")\n\tmenuKeyCorner.CornerRadius = UDim.new(0, 11)\n\tmenuKeyCorner.Parent = menuKeyCard\n\n\tlocal menuKeyStroke = Instance.new("UIStroke")\n\tmenuKeyStroke.Color = Theme.StrokeSoft\n\tmenuKeyStroke.Transparency = 0.34\n\tmenuKeyStroke.Parent = menuKeyCard\n\n\tlocal menuKeyTitle = Instance.new("TextLabel")\n\tmenuKeyTitle.Position = UDim2.fromOffset(16, 8)\n\tmenuKeyTitle.Size = UDim2.new(1, -32, 0, 20)\n\tmenuKeyTitle.BackgroundTransparency = 1\n\tmenuKeyTitle.Font = Enum.Font.GothamBold\n\tmenuKeyTitle.Text = "MENU TOGGLE KEY"\n\tmenuKeyTitle.TextColor3 = Theme.Text\n\tmenuKeyTitle.TextSize = 12\n\tmenuKeyTitle.TextXAlignment = Enum.TextXAlignment.Left\n\tmenuKeyTitle.Parent = menuKeyCard\n\n\tlocal menuKeyInfo = Instance.new("TextLabel")\n\tmenuKeyInfo.Position = UDim2.fromOffset(16, 30)\n\tmenuKeyInfo.Size = UDim2.new(1, -32, 0, 18)\n\tmenuKeyInfo.BackgroundTransparency = 1\n\tmenuKeyInfo.Font = Enum.Font.Gotham\n\tmenuKeyInfo.TextColor3 = Theme.TextMuted\n\tmenuKeyInfo.TextSize = 10\n\tmenuKeyInfo.TextXAlignment = Enum.TextXAlignment.Left\n\tmenuKeyInfo.Parent = menuKeyCard\n\n\tlocal changeKeyButton = Instance.new("TextButton")\n\tchangeKeyButton.Position = UDim2.fromOffset(16, 52)\n\tchangeKeyButton.Size = UDim2.new(0, 170, 0, 28)\n\tchangeKeyButton.BackgroundColor3 = Theme.Button\n\tchangeKeyButton.AutoButtonColor = false\n\tchangeKeyButton.Font = Enum.Font.GothamBold\n\tchangeKeyButton.Text = "CHANGE KEY"\n\tchangeKeyButton.TextColor3 = Theme.Text\n\tchangeKeyButton.TextSize = 10\n\tchangeKeyButton.Parent = menuKeyCard\n\n\tlocal changeKeyCorner = Instance.new("UICorner")\n\tchangeKeyCorner.CornerRadius = UDim.new(0, 8)\n\tchangeKeyCorner.Parent = changeKeyButton\n\n\tlocal resetKeyButton = Instance.new("TextButton")\n\tresetKeyButton.Position = UDim2.fromOffset(196, 52)\n\tresetKeyButton.Size = UDim2.new(0, 150, 0, 28)\n\tresetKeyButton.BackgroundColor3 = Theme.CardActive\n\tresetKeyButton.AutoButtonColor = false\n\tresetKeyButton.Font = Enum.Font.GothamBold\n\tresetKeyButton.Text = "RESET RIGHTSHIFT"\n\tresetKeyButton.TextColor3 = Theme.Text\n\tresetKeyButton.TextSize = 10\n\tresetKeyButton.Parent = menuKeyCard\n\n\tlocal resetKeyCorner = Instance.new("UICorner")\n\tresetKeyCorner.CornerRadius = UDim.new(0, 8)\n\tresetKeyCorner.Parent = resetKeyButton\n\n\trefreshMenuKeyCard = function()\n\t\tlocal keyName = tostring(PersistentSettings.MenuToggleKeyName or "RightShift")\n\t\tkeyHint.Text = keyName\n\t\tmenuKeyInfo.Text = "Current toggle: " .. keyName .. "  \u{2022}  Click Change, then press a keyboard key."\n\t\tchangeKeyButton.Text = MenuKeyBindingActive and "PRESS A KEY..." or "CHANGE KEY"\n\tend\n\n\tchangeKeyButton.Activated:Connect(function()\n\t\tMenuKeyBindingActive = true\n\t\trefreshMenuKeyCard()\n\t\tshowNotification("Keybind", "Press the key you want for opening/closing the menu. Esc cancels.", "info")\n\tend)\n\n\tresetKeyButton.Activated:Connect(function()\n\t\tMenuKeyBindingActive = false\n\t\tPersistentSettings.MenuToggleKeyName = "RightShift"\n\t\trefreshMenuKeyCard()\n\t\tlocal ok, message = saveAllSettings(true)\n\t\tshowNotification(ok and "Key reset" or "Save failed", ok and "Menu toggle is now RightShift." or tostring(message), ok and "success" or "error")\n\tend)\n\n\trefreshMenuKeyCard()\n\n\tControls.GuiCursor = createToggle(settingsPage, 7, "GUI Cursor", "Shows a small cursor and unlocks mouse while the menu is open.", PersistentSettings.GuiCursorEnabled ~= false, function(value)\n\t\tPersistentSettings.GuiCursorEnabled = value == true\n\t\tupdateGuiCursor()\n\t\tif settingsUiReady and settingsSaveReady then\n\t\t\tsaveAllSettings(false)\n\t\tend\n\tend)\n\n\tlocal themeCard = Instance.new("Frame")\n\tthemeCard.LayoutOrder = 8\n\tthemeCard.Size = UDim2.new(1, 0, 0, 82)\n\tthemeCard.BackgroundColor3 = Theme.Card\n\tthemeCard.BackgroundTransparency = 0\n\tthemeCard.BorderSizePixel = 0\n\tthemeCard.Parent = settingsPage\n\n\tlocal themeCardCorner = Instance.new("UICorner")\n\tthemeCardCorner.CornerRadius = UDim.new(0, 11)\n\tthemeCardCorner.Parent = themeCard\n\n\tlocal themeCardStroke = Instance.new("UIStroke")\n\tthemeCardStroke.Color = Theme.StrokeSoft\n\tthemeCardStroke.Transparency = 0.38\n\tthemeCardStroke.Parent = themeCard\n\n\tlocal themeTitle = Instance.new("TextLabel")\n\tthemeTitle.Position = UDim2.fromOffset(16, 10)\n\tthemeTitle.Size = UDim2.new(1, -32, 0, 20)\n\tthemeTitle.BackgroundTransparency = 1\n\tthemeTitle.Font = Enum.Font.GothamBold\n\tthemeTitle.Text = "UI Theme"\n\tthemeTitle.TextColor3 = Theme.Text\n\tthemeTitle.TextSize = 13\n\tthemeTitle.TextXAlignment = Enum.TextXAlignment.Left\n\tthemeTitle.Parent = themeCard\n\n\tlocal themeHint = Instance.new("TextLabel")\n\tthemeHint.Position = UDim2.fromOffset(16, 30)\n\tthemeHint.Size = UDim2.new(1, -32, 0, 16)\n\tthemeHint.BackgroundTransparency = 1\n\tthemeHint.Font = Enum.Font.Gotham\n\tthemeHint.Text = "Changes main menu accent colors and saves automatically."\n\tthemeHint.TextColor3 = Theme.TextMuted\n\tthemeHint.TextSize = 9\n\tthemeHint.TextXAlignment = Enum.TextXAlignment.Left\n\tthemeHint.Parent = themeCard\n\n\tlocal themeNames = {"Blue", "Purple", "Dark", "Green"}\n\tlocal themeButtons = {}\n\n\tlocal function renderThemeButtons()\n\t\tfor name, button in pairs(themeButtons) do\n\t\t\tlocal selected = tostring(PersistentSettings.ThemeName or "Blue") == name\n\t\t\tbutton.BackgroundColor3 = selected and Theme.Accent or Theme.Button\n\t\t\tbutton.TextColor3 = selected and Theme.Text or Theme.TextMuted\n\t\tend\n\tend\n\n\tfor index, name in ipairs(themeNames) do\n\t\tlocal button = Instance.new("TextButton")\n\t\tbutton.Name = name .. "ThemeButton"\n\t\tbutton.Position = UDim2.new((index - 1) / 4, 16 - ((index - 1) * 2), 0, 52)\n\t\tbutton.Size = UDim2.new(0.25, -14, 0, 22)\n\t\tbutton.BackgroundColor3 = Theme.Button\n\t\tbutton.AutoButtonColor = false\n\t\tbutton.Font = Enum.Font.GothamBold\n\t\tbutton.Text = name\n\t\tbutton.TextColor3 = Theme.TextMuted\n\t\tbutton.TextSize = 9\n\t\tbutton.Parent = themeCard\n\t\tthemeButtons[name] = button\n\n\t\tlocal buttonCorner = Instance.new("UICorner")\n\t\tbuttonCorner.CornerRadius = UDim.new(0, 7)\n\t\tbuttonCorner.Parent = button\n\n\t\tbutton.Activated:Connect(function()\n\t\t\tPersistentSettings.ThemeName = name\n\t\t\tapplyThemeToUi()\n\t\t\trenderThemeButtons()\n\t\t\tif settingsUiReady and settingsSaveReady then\n\t\t\t\tsaveAllSettings(false)\n\t\t\tend\n\t\t\tshowNotification("Theme changed", name .. " theme applied.", "success")\n\t\tend)\n\tend\n\n\trenderThemeButtons()\n\n\tlocal settingsCard = Instance.new("Frame")\n\tsettingsCard.LayoutOrder = 6\n\tsettingsCard.Size = UDim2.new(1, 0, 0, 156)\n\tsettingsCard.BackgroundColor3 = Theme.CardSoft\n\tsettingsCard.BackgroundTransparency = 0\n\tsettingsCard.BorderSizePixel = 0\n\tsettingsCard.Parent = settingsPage\n\n\tlocal settingsCardCorner = Instance.new("UICorner")\n\tsettingsCardCorner.CornerRadius = UDim.new(0, 11)\n\tsettingsCardCorner.Parent = settingsCard\n\n\tlocal settingsCardStroke = Instance.new("UIStroke")\n\tsettingsCardStroke.Color = Theme.StrokeSoft\n\tsettingsCardStroke.Transparency = 0.34\n\tsettingsCardStroke.Parent = settingsCard\n\n\tlocal settingsTitle = Instance.new("TextLabel")\n\tsettingsTitle.Position = UDim2.fromOffset(16, 10)\n\tsettingsTitle.Size = UDim2.new(1, -32, 0, 20)\n\tsettingsTitle.BackgroundTransparency = 1\n\tsettingsTitle.Font = Enum.Font.GothamBold\n\tsettingsTitle.Text = "SAVE SYSTEM"\n\tsettingsTitle.TextColor3 = Theme.Text\n\tsettingsTitle.TextSize = 12\n\tsettingsTitle.TextXAlignment = Enum.TextXAlignment.Left\n\tsettingsTitle.Parent = settingsCard\n\n\tlocal settingsStorage = Instance.new("TextLabel")\n\tsettingsStorage.Position = UDim2.fromOffset(16, 34)\n\tsettingsStorage.Size = UDim2.new(1, -32, 0, 36)\n\tsettingsStorage.BackgroundTransparency = 1\n\tsettingsStorage.Font = Enum.Font.Gotham\n\tsettingsStorage.Text = "Storage: " .. PersistentSettings.StorageMode .. "\\n" .. PersistentSettings.StorageDetail\n\tsettingsStorage.TextColor3 = Theme.TextMuted\n\tsettingsStorage.TextSize = 10\n\tsettingsStorage.TextWrapped = true\n\tsettingsStorage.TextXAlignment = Enum.TextXAlignment.Left\n\tsettingsStorage.TextYAlignment = Enum.TextYAlignment.Top\n\tsettingsStorage.Parent = settingsCard\n\n\tlocal function createSettingsButton(text, xScale, xOffset, widthScale, color)\n\t\tlocal button = Instance.new("TextButton")\n\t\tbutton.Position = UDim2.new(xScale, xOffset, 0, 82)\n\t\tbutton.Size = UDim2.new(widthScale, -22, 0, 36)\n\t\tbutton.BackgroundColor3 = color\n\t\tbutton.AutoButtonColor = false\n\t\tbutton.Font = Enum.Font.GothamBold\n\t\tbutton.Text = text\n\t\tbutton.TextColor3 = Theme.Text\n\t\tbutton.TextSize = 11\n\t\tbutton.Parent = settingsCard\n\n\t\tlocal corner = Instance.new("UICorner")\n\t\tcorner.CornerRadius = UDim.new(0, 8)\n\t\tcorner.Parent = button\n\n\t\tlocal stroke = Instance.new("UIStroke")\n\t\tstroke.Color = Color3.fromRGB(194, 204, 238)\n\t\tstroke.Transparency = 0.42\n\t\tstroke.Parent = button\n\t\treturn button\n\tend\n\n\tlocal saveNowButton = createSettingsButton("SAVE NOW", 0, 16, 0.5, Color3.fromRGB(77, 139, 125))\n\tlocal testSaveButton = createSettingsButton("TEST SAVE", 0.5, 6, 0.5, Theme.Button)\n\n\tlocal settingsHint = Instance.new("TextLabel")\n\tsettingsHint.Position = UDim2.fromOffset(16, 126)\n\tsettingsHint.Size = UDim2.new(1, -32, 0, 20)\n\tsettingsHint.BackgroundTransparency = 1\n\tsettingsHint.Font = Enum.Font.Gotham\n\tsettingsHint.Text = "Performance and general settings reload automatically on next execute when file storage is available."\n\tsettingsHint.TextColor3 = Theme.TextDim\n\tsettingsHint.TextSize = 9\n\tsettingsHint.TextWrapped = true\n\tsettingsHint.TextXAlignment = Enum.TextXAlignment.Left\n\tsettingsHint.Parent = settingsCard\n\n\tsaveNowButton.Activated:Connect(function()\n\t\tlocal ok, message = saveAllSettings(true)\n\t\tshowNotification(ok and "Settings saved" or "Save failed", tostring(message), ok and "success" or "error")\n\tend)\n\n\ttestSaveButton.Activated:Connect(function()\n\t\tlocal ok, message = saveAllSettings(true)\n\t\tif ok then\n\t\t\tshowNotification("Save test passed", tostring(message), "success")\n\t\telse\n\t\t\tshowNotification("Save test failed", tostring(message), "error")\n\t\tend\n\tend)\n\n\tsettingsUiReady = true\nend)()\n\n---------------------------------------------------------------------\n---------------------------------------------------------------------\n-- BUILD WEBHOOK PAGE UI\n---------------------------------------------------------------------\n\n-- Keep these many temporary UI locals inside their own scope so the main\n-- script does not hit Luau\'s 200 local-register limit near missionCompletionData.\n;(function()\nwebhookTitle = Instance.new("TextLabel")\nwebhookTitle.Size = UDim2.new(1, -30, 0, 32)\nwebhookTitle.Position = UDim2.fromOffset(15, 18)\nwebhookTitle.BackgroundTransparency = 1\nwebhookTitle.Font = Enum.Font.GothamBold\nwebhookTitle.Text = "Webhook V2 \u{2022} Verified Results"\nwebhookTitle.TextColor3 = Theme.Text\nwebhookTitle.TextSize = 16\nwebhookTitle.TextXAlignment = Enum.TextXAlignment.Left\nwebhookTitle.Parent = webhookPage\n\nfunction createWebhookInput(parent, y, label, placeholder, onChanged)\n\tlocal container = Instance.new("Frame")\n\tcontainer.Size = UDim2.new(1, -30, 0, 44)\n\tcontainer.Position = UDim2.fromOffset(15, y)\n\tcontainer.BackgroundTransparency = 1\n\tcontainer.Parent = parent\n\n\tlocal labelText = Instance.new("TextLabel")\n\tlabelText.Size = UDim2.new(1, 0, 0, 18)\n\tlabelText.BackgroundTransparency = 1\n\tlabelText.Font = Enum.Font.GothamSemibold\n\tlabelText.Text = label\n\tlabelText.TextColor3 = Theme.TextDim\n\tlabelText.TextSize = 11\n\tlabelText.TextXAlignment = Enum.TextXAlignment.Left\n\tlabelText.Parent = container\n\n\tlocal inputBox = Instance.new("TextBox")\n\tinputBox.Size = UDim2.new(1, 0, 0, 22)\n\tinputBox.Position = UDim2.fromOffset(0, 20)\n\tinputBox.BackgroundColor3 = Theme.ElementBg\n\tinputBox.BorderSizePixel = 0\n\tinputBox.Font = Enum.Font.Gotham\n\tinputBox.PlaceholderText = placeholder\n\tinputBox.Text = ""\n\tinputBox.TextColor3 = Theme.Text\n\tinputBox.TextSize = 11\n\tinputBox.Parent = container\n\n\tlocal corner = Instance.new("UICorner")\n\tcorner.CornerRadius = UDim.new(0, 6)\n\tcorner.Parent = inputBox\n\n\tinputBox.FocusLost:Connect(function()\n\t\tonChanged(inputBox.Text)\n\tend)\n\n\treturn inputBox\nend\n\nwebhookUrlInput = createWebhookInput(webhookPage, 60, "Webhook URL", "https://discord.com/api/webhooks/...", function(value)\n\tWebhookConfig.url = value\n\tsaveWebhookConfig()\nend)\nwebhookUrlInput.Text = WebhookConfig.url\n\nuserIdInput = createWebhookInput(webhookPage, 120, "Discord User ID", "Your user ID (for pings)", function(value)\n\tWebhookConfig.userID = value\n\tsaveWebhookConfig()\nend)\nuserIdInput.Text = WebhookConfig.userID\n\nfunction createWebhookCheckbox(parent, y, label, description, initialValue, onToggle)\n\tlocal container = Instance.new("Frame")\n\tcontainer.Size = UDim2.new(1, -30, 0, 50)\n\tcontainer.Position = UDim2.fromOffset(15, y)\n\tcontainer.BackgroundColor3 = Theme.ElementBg\n\tcontainer.BorderSizePixel = 0\n\tcontainer.Parent = parent\n\n\tlocal corner = Instance.new("UICorner")\n\tcorner.CornerRadius = UDim.new(0, 8)\n\tcorner.Parent = container\n\n\tlocal checkbox = Instance.new("TextButton")\n\tcheckbox.Size = UDim2.fromOffset(20, 20)\n\tcheckbox.Position = UDim2.fromOffset(12, 15)\n\tcheckbox.BackgroundColor3 = initialValue and Theme.AccentColor or Theme.TextMuted\n\tcheckbox.TextTransparency = 1\n\tcheckbox.Parent = container\n\n\tlocal checkCorner = Instance.new("UICorner")\n\tcheckCorner.CornerRadius = UDim.new(0, 4)\n\tcheckCorner.Parent = checkbox\n\n\tlocal checkmark = Instance.new("TextLabel")\n\tcheckmark.Size = UDim2.fromScale(1, 1)\n\tcheckmark.BackgroundTransparency = 1\n\tcheckmark.Font = Enum.Font.GothamBold\n\tcheckmark.Text = initialValue and "\u{2713}" or ""\n\tcheckmark.TextColor3 = Color3.fromRGB(255, 255, 255)\n\tcheckmark.TextSize = 14\n\tcheckmark.Parent = checkbox\n\n\tlocal labelText = Instance.new("TextLabel")\n\tlabelText.Size = UDim2.new(1, -45, 0, 18)\n\tlabelText.Position = UDim2.fromOffset(38, 8)\n\tlabelText.BackgroundTransparency = 1\n\tlabelText.Font = Enum.Font.GothamSemibold\n\tlabelText.Text = label\n\tlabelText.TextColor3 = Theme.Text\n\tlabelText.TextSize = 12\n\tlabelText.TextXAlignment = Enum.TextXAlignment.Left\n\tlabelText.Parent = container\n\n\tlocal descText = Instance.new("TextLabel")\n\tdescText.Size = UDim2.new(1, -45, 0, 16)\n\tdescText.Position = UDim2.fromOffset(38, 26)\n\tdescText.BackgroundTransparency = 1\n\tdescText.Font = Enum.Font.Gotham\n\tdescText.Text = description\n\tdescText.TextColor3 = Theme.TextMuted\n\tdescText.TextSize = 10\n\tdescText.TextXAlignment = Enum.TextXAlignment.Left\n\tdescText.TextWrapped = true\n\tdescText.Parent = container\n\n\tlocal state = initialValue\n\tcheckbox.Activated:Connect(function()\n\t\tstate = not state\n\t\ttween(checkbox, 0.16, Enum.EasingStyle.Quad, Enum.EasingDirection.Out, {\n\t\t\tBackgroundColor3 = state and Theme.AccentColor or Theme.TextMuted\n\t\t})\n\t\tcheckmark.Text = state and "\u{2713}" or ""\n\t\tonToggle(state)\n\tend)\n\n\treturn checkbox\nend\n\ncreateWebhookCheckbox(webhookPage, 170, "Include Player Stats", "Tries to read current gold, gems, level, and prestige", WebhookConfig.enableStats, function(value)\n\tWebhookConfig.enableStats = value\n\tsaveWebhookConfig()\nend)\n\ncreateWebhookCheckbox(webhookPage, 225, "Ping on Rare Drop", "Mentions you when a mythic/serum drops", WebhookConfig.enableRarePing, function(value)\n\tWebhookConfig.enableRarePing = value\n\tsaveWebhookConfig()\nend)\n\ncreateWebhookCheckbox(webhookPage, 280, "Send Completed Missions", "Sends webhook when the result screen says mission completed", WebhookConfig.sendCompleted ~= false, function(value)\n\tWebhookConfig.sendCompleted = value\n\tsaveWebhookConfig()\nend)\n\ncreateWebhookCheckbox(webhookPage, 335, "Send Failed Missions", "Sends webhook when the result screen says mission failed", WebhookConfig.sendFailed ~= false, function(value)\n\tWebhookConfig.sendFailed = value\n\tsaveWebhookConfig()\nend)\n\nwebhookNote = Instance.new("TextLabel")\nwebhookNote.Size = UDim2.new(1, -30, 0, 36)\nwebhookNote.Position = UDim2.fromOffset(15, 390)\nwebhookNote.BackgroundColor3 = Theme.ElementBg\nwebhookNote.BorderSizePixel = 0\nwebhookNote.Parent = webhookPage\n\nnoteCorner = Instance.new("UICorner")\nnoteCorner.CornerRadius = UDim.new(0, 8)\nnoteCorner.Parent = webhookNote\n\nnotePad = Instance.new("UIPadding")\nnotePad.PaddingLeft = UDim.new(0, 12)\nnotePad.PaddingRight = UDim.new(0, 12)\nnotePad.PaddingTop = UDim.new(0, 10)\nnotePad.PaddingBottom = UDim.new(0, 10)\nnotePad.Parent = webhookNote\n\nnoteText = Instance.new("TextLabel")\nnoteText.Size = UDim2.fromScale(1, 1)\nnoteText.BackgroundTransparency = 1\nnoteText.Font = Enum.Font.Gotham\nnoteText.Text = "Stable result snapshots only. Unknown reward guesses are omitted; raw GUI + Run Recorder diagnostics remain optional."\nnoteText.TextColor3 = Theme.TextMuted\nnoteText.TextSize = 10\nnoteText.TextWrapped = true\nnoteText.TextXAlignment = Enum.TextXAlignment.Left\nnoteText.Parent = webhookNote\nend)()\n\n---------------------------------------------------------------------\n-- MISSION COMPLETION & WEBHOOK DETECTION\n---------------------------------------------------------------------\n\n;(function() -- webhook mission monitor scoped to avoid Luau\'s 200 local-register limit\n\tlocal function startMissionWebhookMonitor()\n\tlocal resultScreenActive = false\n\tlocal lastWebhookSignature = ""\n\tlocal lastWebhookSentAt = 0\n\tlocal lastAutoRetryAt = 0\n\n    V3ResultGuard = {\n        Armed = false,\n        Processing = false,\n        ResultSeenSince = nil,\n        ActiveEvidenceSince = nil,\n        LastAcceptedAt = 0,\n    }\n\n\tlocal function getPlayerStats()\n\t\t-- v114: safe account-stat scan. No result GUI guessing; only exact ValueBase/Attribute names\n\t\t-- under player/player-data containers are accepted. Unknown fields are omitted in the embed.\n\t\tlocal stats = {\n\t\t\tlevel = nil,\n\t\t\tprestige = nil,\n\t\t\tgold = nil,\n\t\t\tgems = nil,\n\t\t\ttrusted = false,\n\t\t}\n\n\t\tlocal function fmt(value)\n\t\t\tlocal number = tonumber(value)\n\t\t\tif not number then return nil end\n\t\t\tlocal text = tostring(math.floor(number))\n\t\t\tlocal sign = ""\n\t\t\tif string.sub(text, 1, 1) == "-" then\n\t\t\t\tsign = "-"\n\t\t\t\ttext = string.sub(text, 2)\n\t\t\tend\n\t\t\tlocal result = text\n\t\t\twhile true do\n\t\t\t\tlocal nextText, replaced = string.gsub(result, "^(%d+)(%d%d%d)", "%1,%2")\n\t\t\t\tresult = nextText\n\t\t\t\tif replaced == 0 then break end\n\t\t\tend\n\t\t\treturn sign .. result\n\t\tend\n\n\t\tlocal function canonicalName(name)\n\t\t\tlocal lower = string.lower(tostring(name or ""))\n\t\t\tlower = string.gsub(lower, "[^%w]", "")\n\t\t\tif lower == "level" or lower == "lvl" or lower == "playerlevel" or lower == "currentlevel" then return "level" end\n\t\t\tif lower == "prestige" or lower == "prestiges" or lower == "prestigelevel" or lower == "prestigelvl" or lower == "p" then return "prestige" end\n\t\t\tif lower == "gold" or lower == "coins" or lower == "coin" or lower == "money" or lower == "cash" or lower == "currency" then return "gold" end\n\t\t\tif lower == "gems" or lower == "gem" or lower == "crystals" or lower == "crystal" or lower == "shards" then return "gems" end\n\t\t\treturn nil\n\t\tend\n\n\t\tlocal function betterNumber(currentText, newValue)\n\t\t\tlocal current = tonumber(string.gsub(tostring(currentText or ""), ",", ""))\n\t\t\tlocal newNumber = tonumber(newValue)\n\t\t\tif not newNumber then return false end\n\t\t\tif current == nil then return true end\n\t\t\t-- Prefer non-zero if a previous weak scan found zero.\n\t\t\tif current == 0 and newNumber > 0 then return true end\n\t\t\treturn false\n\t\tend\n\n\t\tlocal function applyStat(name, value)\n\t\t\tlocal key = canonicalName(name)\n\t\t\tif not key then return end\n\t\t\tlocal text = fmt(value)\n\t\t\tif not text then return end\n\t\t\tif key == "level" then\n\t\t\t\tif betterNumber(stats.level, value) then stats.level = text; stats.trusted = true end\n\t\t\telseif key == "prestige" then\n\t\t\t\tif betterNumber(stats.prestige, value) then stats.prestige = text; stats.trusted = true end\n\t\t\telseif key == "gold" then\n\t\t\t\tif betterNumber(stats.gold, value) then stats.gold = text; stats.trusted = true end\n\t\t\telseif key == "gems" then\n\t\t\t\tif betterNumber(stats.gems, value) then stats.gems = text; stats.trusted = true end\n\t\t\tend\n\t\tend\n\n\t\tlocal function scanAttributes(object)\n\t\t\tif not object or type(object.GetAttributes) ~= "function" then return end\n\t\t\tlocal ok, attributes = pcall(function() return object:GetAttributes() end)\n\t\t\tif ok and type(attributes) == "table" then\n\t\t\t\tfor name, value in pairs(attributes) do applyStat(name, value) end\n\t\t\tend\n\t\tend\n\n\t\tlocal function scanValues(root, depthLimit)\n\t\t\tif not root then return end\n\t\t\tscanAttributes(root)\n\t\t\tlocal rootDepth = 0\n\t\t\tlocal rootPath = root:GetFullName()\n\t\t\tfor _, object in ipairs(root:GetDescendants()) do\n\t\t\t\tlocal full = object:GetFullName()\n\t\t\t\tif not string.find(full, "PlayerGui", 1, true) and not string.find(full, "TitanControlMenu", 1, true) then\n\t\t\t\t\tif object:IsA("IntValue") or object:IsA("NumberValue") or object:IsA("StringValue") then\n\t\t\t\t\t\tapplyStat(object.Name, object.Value)\n\t\t\t\t\tend\n\t\t\t\t\tscanAttributes(object)\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\n\t\tscanValues(player)\n\n\t\t-- Some games replicate account stats in ReplicatedStorage.PlayerData/<UserId or Name>.\n\t\tlocal dataRoots = {"PlayerData", "Players", "Profiles", "Data", "Stats", "PlayerStats"}\n\t\tfor _, rootName in ipairs(dataRoots) do\n\t\t\tlocal root = ReplicatedStorage:FindFirstChild(rootName)\n\t\t\tif root then\n\t\t\t\tlocal userFolder = root:FindFirstChild(tostring(player.UserId)) or root:FindFirstChild(player.Name)\n\t\t\t\tif userFolder then scanValues(userFolder) end\n\t\t\tend\n\t\tend\n\n\t\treturn stats\n\tend\n\n\tlocal ResultKeywords = {\n\t\t"mission failed",\n\t\t"mission fail",\n\t\t"mission complete",\n\t\t"mission completed",\n        "raid failed",\n        "raid fail",\n        "raid complete",\n        "raid completed",\n\t\t"victory",\n\t\t"defeat",\n\t}\n\n\tlocal function cleanGuiText(value)\n\t\tlocal raw = tostring(value or "")\n\t\tlocal out = {}\n\t\tlocal inTag = false\n\t\tlocal lastWasSpace = false\n\n\t\tfor index = 1, #raw do\n\t\t\tlocal ch = string.sub(raw, index, index)\n\t\t\tlocal byte = string.byte(ch)\n\n\t\t\tif ch == "<" then\n\t\t\t\tinTag = true\n\t\t\telseif ch == ">" then\n\t\t\t\tinTag = false\n\t\t\telseif not inTag then\n\t\t\t\tlocal isSpace = byte == 9 or byte == 10 or byte == 13 or byte == 32\n\t\t\t\tif isSpace then\n\t\t\t\t\tif not lastWasSpace and #out > 0 then\n\t\t\t\t\t\tout[#out + 1] = " "\n\t\t\t\t\t\tlastWasSpace = true\n\t\t\t\t\tend\n\t\t\t\telse\n\t\t\t\t\tout[#out + 1] = ch\n\t\t\t\t\tlastWasSpace = false\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\n\t\tlocal text = table.concat(out)\n\t\twhile #text > 0 and string.sub(text, -1) == " " do\n\t\t\ttext = string.sub(text, 1, #text - 1)\n\t\tend\n\t\treturn text\n\tend\n\n\tlocal function hasAnyKeyword(lowerText, keywords)\n\t\tfor _, keyword in ipairs(keywords) do\n\t\t\tif string.find(lowerText, keyword, 1, true) then\n\t\t\t\treturn true\n\t\t\tend\n\t\tend\n\t\treturn false\n\tend\n\n\tlocal function getTextFromObject(object)\n\t\tif object:IsA("TextLabel") or object:IsA("TextButton") or object:IsA("TextBox") then\n\t\t\treturn cleanGuiText(object.Text)\n\t\tend\n\t\treturn nil\n\tend\n\n\tlocal function isVisibleTextObject(object)\n\t\tif not object:IsA("GuiObject") then return false end\n\t\tlocal ok, visible = pcall(guiObjectIsActuallyVisible, object)\n\t\treturn ok and visible == true\n\tend\n\n\tlocal function guiTextDescendantHas(root, keywords)\n\t\tif not root then return false end\n\n\t\tfor _, descendant in ipairs(root:GetDescendants()) do\n\t\t\tlocal text = getTextFromObject(descendant)\n\t\t\tif text and text ~= "" and isVisibleTextObject(descendant) then\n\t\t\t\tif hasAnyKeyword(string.lower(text), keywords) then\n\t\t\t\t\treturn true\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\n\t\treturn false\n\tend\n\n\tlocal function findMissionResultRoot()\n\t\tfor _, object in ipairs(playerGui:GetDescendants()) do\n\t\t\tlocal text = getTextFromObject(object)\n\t\t\tif text and text ~= "" and isVisibleTextObject(object) then\n\t\t\t\tlocal lower = string.lower(text)\n\t\t\t\tif hasAnyKeyword(lower, ResultKeywords) then\n\t\t\t\t\tlocal node = object\n\t\t\t\t\tfor _ = 1, 10 do\n\t\t\t\t\t\tif not node or node == playerGui then break end\n\n\t\t\t\t\t\tif node:IsA("GuiObject") then\n\t\t\t\t\t\t\tlocal hasStats = guiTextDescendantHas(node, {"stats"})\n\t\t\t\t\t\t\tlocal hasObtained = guiTextDescendantHas(node, {"obtained"})\n\t\t\t\t\t\t\tlocal hasButtons = guiTextDescendantHas(node, {"leave", "modifiers", "retry"})\n\t\t\t\t\t\t\tif hasStats and (hasObtained or hasButtons) then\n\t\t\t\t\t\t\t\treturn node, lower\n\t\t\t\t\t\t\tend\n\t\t\t\t\t\tend\n\n\t\t\t\t\t\tnode = node.Parent\n\t\t\t\t\tend\n\n\t\t\t\t\treturn object.Parent, lower\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\t\treturn nil, nil\n\tend\n\n\n\tlocal function findGuiButtonAncestor(object)\n\t\tlocal node = object\n\t\tfor _ = 1, 8 do\n\t\t\tif not node or node == playerGui then break end\n\t\t\tif node:IsA("GuiButton") then\n\t\t\t\treturn node\n\t\t\tend\n\t\t\tnode = node.Parent\n\t\tend\n\t\treturn nil\n\tend\n\n\tlocal function clickVisibleGuiObject(object)\n\t\tif not object or not object:IsA("GuiObject") then return false end\n\t\tlocal target = findGuiButtonAncestor(object) or object\n\t\tif not target:IsA("GuiObject") then return false end\n\n\t\t-- v111: first try the signal route. Some result buttons accept Activate even when mouse click is blocked.\n\t\tif target:IsA("GuiButton") then\n\t\t\tpcall(function() target:Activate() end)\n\t\t\tif type(firesignal) == "function" then\n\t\t\t\tpcall(function() firesignal(target.MouseButton1Down) end)\n\t\t\t\tpcall(function() firesignal(target.MouseButton1Click) end)\n\t\t\t\tpcall(function() firesignal(target.Activated) end)\n\t\t\tend\n\t\tend\n\n\t\tlocal oldWindowVisible = window and window.Visible\n\t\tlocal oldShadowVisible = shadow and shadow.Visible\n\t\tlocal oldCursorVisible = guiCursor and guiCursor.Visible\n\t\tlocal hideOwnGui = screenGui and not target:IsDescendantOf(screenGui)\n\n\t\tif hideOwnGui then\n\t\t\t-- The control window sits above Roblox UI. Hide it for the click so RETRY is not covered.\n\t\t\tif window then window.Visible = false end\n\t\t\tif shadow then shadow.Visible = false end\n\t\t\tif guiCursor then guiCursor.Visible = false end\n\t\t\ttask.wait(0.08)\n\t\tend\n\n\t\tlocal pos = target.AbsolutePosition\n\t\tlocal size = target.AbsoluteSize\n\t\tlocal x = math.floor(pos.X + size.X / 2 + 0.5)\n\t\tlocal y = math.floor(pos.Y + size.Y / 2 + 0.5)\n\t\tlocal inset = Vector2.new(0, 0)\n\t\tpcall(function()\n\t\t\tinset = GuiService:GetGuiInset()\n\t\tend)\n\t\tpcall(function()\n\t\t\tVirtualInputManager:SendMouseMoveEvent(x + inset.X, y + inset.Y, game)\n\t\tend)\n\t\ttask.wait(0.035)\n\t\tpcall(function()\n\t\t\tVirtualInputManager:SendMouseButtonEvent(x + inset.X, y + inset.Y, 0, true, game, 0)\n\t\t\ttask.wait(0.07)\n\t\t\tVirtualInputManager:SendMouseButtonEvent(x + inset.X, y + inset.Y, 0, false, game, 0)\n\t\tend)\n\n\t\tif hideOwnGui then\n\t\t\ttask.wait(0.18)\n\t\t\tif window then window.Visible = oldWindowVisible end\n\t\t\tif shadow then shadow.Visible = oldShadowVisible end\n\t\t\tif guiCursor then guiCursor.Visible = oldCursorVisible end\n\t\tend\n\n\t\treturn true\n\tend\n\n\tlocal function findRetryButton(root)\n\t\tlocal bestObject = nil\n\t\tlocal bestY = -math.huge\n\n\t\tlocal function scanRetryText(scanRoot)\n\t\t\tif not scanRoot then return end\n\t\t\tfor _, object in ipairs(scanRoot:GetDescendants()) do\n\t\t\t\tif screenGui and object:IsDescendantOf(screenGui) then\n\t\t\t\t\tcontinue\n\t\t\t\tend\n\t\t\t\tlocal text = getTextFromObject(object)\n\t\t\t\tif text and text ~= "" and isVisibleTextObject(object) then\n\t\t\t\t\tlocal lower = string.lower(text)\n\t\t\t\t\tif string.find(lower, "retry", 1, true) then\n\t\t\t\t\t\tlocal candidate = findGuiButtonAncestor(object) or object\n\t\t\t\t\t\tif candidate:IsA("GuiObject") and candidate.AbsolutePosition.Y > bestY then\n\t\t\t\t\t\t\tbestY = candidate.AbsolutePosition.Y\n\t\t\t\t\t\t\tbestObject = candidate\n\t\t\t\t\t\tend\n\t\t\t\t\tend\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\n\t\tscanRetryText(root)\n\t\tif not bestObject then\n\t\t\tscanRetryText(playerGui)\n\t\tend\n\t\treturn bestObject\n\tend\n\n\tlocal function autoRetryFromResultGui(root)\n\t\tif not State.AutoRetryEnabled then return end\n\t\tlocal now = tick()\n\t\tif now - lastAutoRetryAt < 6 then return end\n\t\tlastAutoRetryAt = now\n\t\ttask.wait(1.05)\n\t\tlocal refreshedRoot = findMissionResultRoot()\n\t\troot = refreshedRoot or root\n\t\tlocal retryButton = findRetryButton(root)\n\t\tif retryButton then\n\t\t\tshowNotification("Auto retry", "Result screen detected; clicking RETRY.", "info")\n\t\t\tclickVisibleGuiObject(retryButton)\n\t\telse\n\t\t\tshowNotification("Auto retry", "Result screen detected, but RETRY was not visible.", "error")\n\t\tend\n\tend\n\n\tlocal function handleAutoCycleFromResultGui(root)\n\t\tif not State.AutoRetryEnabled then return end\n\t\tlocal now = tick()\n\t\tif now - lastAutoRetryAt < 6 then return end\n\t\tlastAutoRetryAt = now\n\n\t\tState.AutoMissionCount = math.clamp(math.floor((tonumber(State.AutoMissionCount) or 0) + 1.5), 0, 99)\n\t\trefreshAutoMissionStatus()\n\t\tsaveSettingsIfReady()\n\n\t\ttask.wait(1.05)\n\n\t\tlocal limit = math.clamp(math.floor((tonumber(State.AutoMissionLimit) or 0) + 0.5), 0, 10)\n\t\tif limit > 0 and State.AutoMissionCount >= limit then\n\t\t\tshowNotification("Auto cycle complete", "Mission limit reached; returning to lobby.", "success")\n\t\t\tState.AutoMissionCount = 0\n\t\t\trefreshAutoMissionStatus()\n\t\t\tsaveSettingsIfReady()\n\t\t\tReturnToLobby.Run()\n\t\t\treturn\n\t\tend\n\n\t\tlocal refreshedRoot = findMissionResultRoot()\n\t\troot = refreshedRoot or root\n\t\tlocal retryButton = findRetryButton(root)\n\t\tif retryButton then\n\t\t\tshowNotification("Auto retry", string.format("Mission %d/%s done; clicking RETRY.", tonumber(State.AutoMissionCount) or 0, limit > 0 and tostring(limit) or "\u{221e}"), "info")\n\t\t\tclickVisibleGuiObject(retryButton)\n\t\telse\n\t\t\tshowNotification("Auto retry", "Result screen detected, but RETRY was not visible.", "error")\n\t\tend\n\tend\n\n\ttriggerAutoRetryNow = function()\n\t\tif not State.AutoRetryEnabled then return end\n\t\tlocal root = findMissionResultRoot()\n\t\tif root then\n\t\t\thandleAutoCycleFromResultGui(root)\n\t\tend\n\tend\n\n\tlocal function parseNumber(text)\n\t\tlocal compact = string.gsub(tostring(text or ""), ",", "")\n\t\tlocal numberText = string.match(compact, "%d+")\n\t\treturn numberText and tonumber(numberText) or nil\n\tend\n\n\tlocal function parseClock(text)\n\t\treturn string.match(tostring(text or ""), "%d+:%d+")\n\tend\n\n\tlocal function getVisibleTextItems(root)\n\t\tlocal items = {}\n\t\tif not root then return items end\n\n\t\tfor _, object in ipairs(root:GetDescendants()) do\n\t\t\tlocal text = getTextFromObject(object)\n\t\t\tif text and text ~= "" and isVisibleTextObject(object) then\n\t\t\t\tlocal position = object.AbsolutePosition\n\t\t\t\ttable.insert(items, {\n\t\t\t\t\ttext = text,\n\t\t\t\t\tlower = string.lower(text),\n\t\t\t\t\tnumber = parseNumber(text),\n\t\t\t\t\tclock = parseClock(text),\n\t\t\t\t\tx = position.X,\n\t\t\t\t\ty = position.Y,\n\t\t\t\t\tobject = object,\n\t\t\t\t})\n\t\t\tend\n\t\tend\n\n\t\ttable.sort(items, function(a, b)\n\t\t\tif math.abs(a.y - b.y) > 8 then\n\t\t\t\treturn a.y < b.y\n\t\t\tend\n\t\t\treturn a.x < b.x\n\t\tend)\n\n\t\treturn items\n\tend\n\n\tlocal function findClockValue(items)\n\t\tfor _, item in ipairs(items) do\n\t\t\tif item.clock and item.clock ~= "" then\n\t\t\t\treturn item.clock\n\t\t\tend\n\t\tend\n\t\treturn "Unknown"\n\tend\n\n\tlocal function findMetricValue(items, keywords)\n\t\tfor index, item in ipairs(items) do\n\t\t\tif hasAnyKeyword(item.lower, keywords) then\n\t\t\t\tif item.number then\n\t\t\t\t\treturn item.number\n\t\t\t\tend\n\n\t\t\t\tfor lookAhead = index + 1, math.min(#items, index + 12) do\n\t\t\t\t\tlocal candidate = items[lookAhead]\n\t\t\t\t\tif candidate.number then\n\t\t\t\t\t\tlocal sameRow = math.abs(candidate.y - item.y) <= 34 and candidate.x >= item.x\n\t\t\t\t\t\tlocal nearbyBelow = candidate.y >= item.y and candidate.y - item.y <= 90\n\t\t\t\t\t\tif sameRow or nearbyBelow then\n\t\t\t\t\t\t\treturn candidate.number\n\t\t\t\t\t\tend\n\t\t\t\t\tend\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\t\treturn 0\n\tend\n\n\tlocal function formatNumber(value)\n\t\tlocal number = tonumber(value)\n\t\tif not number then return "Unknown" end\n\n\t\tlocal text = tostring(math.floor(number))\n\t\tlocal sign = ""\n\t\tif string.sub(text, 1, 1) == "-" then\n\t\t\tsign = "-"\n\t\t\ttext = string.sub(text, 2)\n\t\tend\n\n\t\tlocal result = text\n\t\twhile true do\n\t\t\tlocal replaced\n\t\t\tresult, replaced = string.gsub(result, "^(%d+)(%d%d%d)", "%1,%2")\n\t\t\tif replaced == 0 then break end\n\t\tend\n\n\t\treturn sign .. result\n\tend\n\n\tlocal function isOnlyNumberText(text)\n\t\tlocal compact = string.gsub(tostring(text or ""), ",", "")\n\t\tcompact = string.gsub(compact, "%s+", "")\n\t\treturn string.match(compact, "^%d+$") ~= nil\n\tend\n\n\tlocal function isStandardResultText(lowerText)\n\t\tlocal textValue = tostring(lowerText or "")\n\t\tif textValue == "" then return true end\n\t\tif isOnlyNumberText(textValue) then return true end\n\n\t\tlocal exactIgnored = {\n\t\t\t["mission completed"] = true,\n\t\t\t["mission complete"] = true,\n\t\t\t["mission failed"] = true,\n\t\t\t["mission fail"] = true,\n\t\t\t["stats"] = true,\n\t\t\t["time taken"] = true,\n\t\t\t["damage dealt"] = true,\n\t\t\t["titans killed"] = true,\n\t\t\t["critical hits"] = true,\n\t\t\t["obtained"] = true,\n\t\t\t["leave"] = true,\n\t\t\t["modifiers"] = true,\n\t\t\t["retry"] = true,\n\t\t\t[">"] = true,\n\t\t\t["<"] = true,\n\t\t\t["exp"] = true,\n\t\t\t["xp"] = true,\n\t\t\t["gold"] = true,\n\t\t\t["gems"] = true,\n\t\t\t["gem"] = true,\n\t\t\t["achievement"] = true,\n\t\t}\n\n\t\tif exactIgnored[textValue] then return true end\n\t\tif string.find(textValue, "retry", 1, true) then return true end\n\t\tif string.find(textValue, "your streak", 1, true) then return true end\n\t\treturn false\n\tend\n\n\tlocal function findFirstItemWithKeyword(items, keywords)\n\t\tfor _, item in ipairs(items) do\n\t\t\tif hasAnyKeyword(item.lower, keywords) then\n\t\t\t\treturn item\n\t\t\tend\n\t\tend\n\t\treturn nil\n\tend\n\n\tlocal function findButtonStartY(items)\n\t\tlocal lowest = math.huge\n\t\tfor _, item in ipairs(items) do\n\t\t\tif item.lower == "leave" or item.lower == "modifiers" or string.find(item.lower, "retry", 1, true) then\n\t\t\t\tif item.y < lowest then\n\t\t\t\t\tlowest = item.y\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\t\treturn lowest ~= math.huge and lowest or nil\n\tend\n\n\tlocal function collectRewardNumberItems(items)\n\t\tlocal obtainedItem = findFirstItemWithKeyword(items, {"obtained"})\n\t\tif not obtainedItem then return {} end\n\n\t\tlocal buttonY = findButtonStartY(items) or math.huge\n\t\tlocal rewardItems = {}\n\n\t\tfor _, item in ipairs(items) do\n\t\t\tif item.number and item.y > obtainedItem.y + 6 and item.y < buttonY - 3 then\n\t\t\t\tif item.lower ~= ">" and item.lower ~= "<" and not string.find(item.lower, "retry", 1, true) then\n\t\t\t\t\ttable.insert(rewardItems, item)\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\n\t\ttable.sort(rewardItems, function(a, b)\n\t\t\tif math.abs(a.y - b.y) > 10 then\n\t\t\t\treturn a.y < b.y\n\t\t\tend\n\t\t\treturn a.x < b.x\n\t\tend)\n\n\t\t-- Some result screens expose a tiny hidden/count label right after "OBTAINED".\n\t\t-- If it appears before the real reward row, drop it so EXP/Gold/Gems line up correctly.\n\t\twhile #rewardItems >= 4\n\t\t\tand (rewardItems[1].number or 0) < 1000\n\t\t\tand (rewardItems[2].number or 0) >= 1000\n\t\t\tand (rewardItems[3].number or 0) >= 1000 do\n\t\t\ttable.remove(rewardItems, 1)\n\t\tend\n\n\t\treturn rewardItems\n\tend\n\n\tlocal function cleanCandidateName(value)\n\t\tlocal name = cleanGuiText(value)\n\t\tif name == "" then return nil end\n\n\t\tlocal lower = string.lower(name)\n\t\tlocal genericNames = {\n\t\t\t["frame"] = true,\n\t\t\t["imagelabel"] = true,\n\t\t\t["imagebutton"] = true,\n\t\t\t["textlabel"] = true,\n\t\t\t["textbutton"] = true,\n\t\t\t["textbox"] = true,\n\t\t\t["uicorner"] = true,\n\t\t\t["uistroke"] = true,\n\t\t\t["reward"] = true,\n\t\t\t["rewards"] = true,\n\t\t\t["item"] = true,\n\t\t\t["icon"] = true,\n\t\t\t["amount"] = true,\n\t\t\t["quantity"] = true,\n\t\t\t["count"] = true,\n\t\t\t["label"] = true,\n\t\t\t["background"] = true,\n\t\t\t["container"] = true,\n\t\t\t["slot"] = true,\n\t\t\t["inner"] = true,\n\t\t\t["outer"] = true,\n\t\t\t["border"] = true,\n\t\t\t["outline"] = true,\n\t\t\t["shadow"] = true,\n\t\t\t["glow"] = true,\n\t\t\t["stroke"] = true,\n\t\t\t["gradient"] = true,\n\t\t\t["star"] = true,\n\t\t\t["rarity"] = true,\n\t\t\t["check"] = true,\n\t\t\t["checkmark"] = true,\n\t\t\t["tick"] = true,\n\t\t\t["mark"] = true,\n\t\t\t["selected"] = true,\n\t\t\t["enabled"] = true,\n\t\t\t["disabled"] = true,\n\t\t\t["button"] = true,\n\t\t\t["hover"] = true,\n            ["main"] = true,\n            ["root"] = true,\n            ["content"] = true,\n            ["holder"] = true,\n            ["perk"] = true,\n            ["drop"] = true,\n            ["common perk"] = true,\n            ["rare perk"] = true,\n            ["epic perk"] = true,\n            ["legendary perk"] = true,\n            ["mythic perk"] = true,\n            ["inventory"] = true,\n            ["equipment"] = true,\n            ["market"] = true,\n            ["rankings"] = true,\n            ["regiment"] = true,\n            ["battlepass"] = true,\n            ["missions"] = true,\n            ["quests"] = true,\n\t\t\t["shine"] = true,\n\t\t\t["sparkle"] = true,\n\t\t}\n\n\t\tif genericNames[lower] or isStandardResultText(lower) then\n\t\t\treturn nil\n\t\tend\n\n        -- Reject structural GUI/object ids such as "2_1", "3-2", "1_4".\n        if string.match(lower, "^%d+[_%-]%d+$")\n            or string.match(lower, "^%d+[_%-]%d+[_%-]%d+$")\n            or string.match(lower, "^slot[_%-]?%d+$")\n            or string.match(lower, "^item[_%-]?%d+$") then\n            return nil\n        end\n\n        -- Names made mostly from digits/underscores are never useful reward names.\n        local strippedStructure = string.gsub(lower, "[%d_%-%s]", "")\n        if strippedStructure == "" then\n            return nil\n        end\n\t\tif string.len(name) <= 1 then\n\t\t\treturn nil\n\t\tend\n\t\tif string.find(lower, "roblox", 1, true) or string.find(lower, "rbxasset", 1, true) then\n\t\t\treturn nil\n\t\tend\n\n\t\treturn name\n\tend\n\n\tlocal function rarityNameFromText(value)\n\t\tlocal lower = string.lower(tostring(value or ""))\n\t\tif string.find(lower, "mythic", 1, true) then return "Mythic" end\n\t\tif string.find(lower, "legendary", 1, true) then return "Legendary" end\n\t\tif string.find(lower, "epic", 1, true) then return "Epic" end\n\t\tif string.find(lower, "rare", 1, true) then return "Rare" end\n\t\tif string.find(lower, "common", 1, true) then return "Common" end\n\t\treturn nil\n\tend\n\n\tlocal function rarityNameFromColor(color)\n\t\tif typeof(color) ~= "Color3" then return nil end\n\n\t\tlocal h, s, v = Color3.toHSV(color)\n\t\tif v < 0.18 then return nil end\n\n\t\t-- Low-saturation white/gray icons are usually common/basic rewards.\n\t\tif s < 0.18 then\n\t\t\treturn "Common"\n\t\tend\n\n\t\t-- Roblox Color3.toHSV hue is 0-1. These ranges are intentionally broad\n\t\t-- because different result screens use slightly different border/icon colors.\n\t\tif h <= 0.04 or h >= 0.93 then\n\t\t\treturn "Mythic"\n\t\telseif h >= 0.05 and h <= 0.15 then\n\t\t\treturn "Legendary"\n\t\telseif h >= 0.70 and h <= 0.88 then\n\t\t\treturn "Epic"\n\t\telseif h >= 0.48 and h <= 0.65 then\n\t\t\treturn "Rare"\n\t\tend\n\n\t\treturn nil\n\tend\n\n\tlocal function inspectRewardRarity(numberItem)\n\t\tlocal object = numberItem.object\n\t\tif not object then return nil end\n\n\t\tlocal container = object.Parent\n\t\tfor _ = 1, 5 do\n\t\t\tif not container then break end\n\n\t\t\tlocal fromName = rarityNameFromText(container.Name)\n\t\t\tif fromName then return fromName end\n\n\t\t\tfor _, descendant in ipairs(container:GetDescendants()) do\n\t\t\t\tlocal nameRarity = rarityNameFromText(descendant.Name)\n\t\t\t\tif nameRarity then return nameRarity end\n\t\t\tend\n\n\t\t\t-- Prefer the item icon/text color. Borders are often just the result-card gold trim,\n\t\t\t-- so border/background color is only used as a fallback.\n\t\t\tlocal fallbackRarity = nil\n\t\t\tfor _, descendant in ipairs(container:GetDescendants()) do\n\t\t\t\tif descendant:IsA("ImageLabel") or descendant:IsA("ImageButton") then\n\t\t\t\t\tlocal rarity = rarityNameFromColor(descendant.ImageColor3)\n\t\t\t\t\tif rarity then return rarity end\n\t\t\t\telseif descendant:IsA("TextLabel") or descendant:IsA("TextButton") then\n\t\t\t\t\tlocal rarity = rarityNameFromColor(descendant.TextColor3)\n\t\t\t\t\tif rarity then return rarity end\n\t\t\t\telseif descendant:IsA("UIStroke") and not fallbackRarity then\n\t\t\t\t\tfallbackRarity = rarityNameFromColor(descendant.Color)\n\t\t\t\telseif descendant:IsA("GuiObject") and not fallbackRarity then\n\t\t\t\t\tfallbackRarity = rarityNameFromColor(descendant.BackgroundColor3)\n\t\t\t\tend\n\t\t\tend\n\n\t\t\tif fallbackRarity then return fallbackRarity end\n\t\t\tcontainer = container.Parent\n\t\tend\n\n\t\treturn nil\n\tend\n\n\tlocal function findNearbyRewardText(numberItem, items)\n\t\tif type(items) ~= "table" then return nil end\n\n\t\tlocal bestText = nil\n\t\tlocal bestScore = math.huge\n\n\t\tfor _, item in ipairs(items) do\n\t\t\tif item ~= numberItem and not item.number then\n\t\t\t\tlocal candidate = cleanCandidateName(item.text)\n\t\t\t\tif candidate then\n\t\t\t\t\tlocal dx = math.abs((item.x or 0) - (numberItem.x or 0))\n\t\t\t\t\tlocal dy = math.abs((item.y or 0) - (numberItem.y or 0))\n\t\t\t\t\tif dx <= 110 and dy <= 85 then\n\t\t\t\t\t\tlocal score = dx + dy * 1.4\n\t\t\t\t\t\tif score < bestScore then\n\t\t\t\t\t\t\tbestScore = score\n\t\t\t\t\t\t\tbestText = candidate\n\t\t\t\t\t\tend\n\t\t\t\t\tend\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\n\t\treturn bestText\n\tend\n\n\n    local RewardHoverCache = setmetatable({}, {__mode = "k"})\n\n    local RewardAttributePriority = {\n        "PerkName",\n        "RewardName",\n        "ItemName",\n        "DisplayName",\n        "TraitName",\n        "DropName",\n        "Perk",\n        "Item",\n        "Title",\n    }\n\n    local function findRewardTileContainer(numberItem)\n        local object = numberItem and numberItem.object\n        if not object then return nil end\n\n        local best = nil\n        local bestArea = math.huge\n        local node = object.Parent\n\n        for _ = 1, 6 do\n            if not node then break end\n\n            if node:IsA("GuiObject") then\n                local size = node.AbsoluteSize\n                local area = size.X * size.Y\n\n                if size.X >= 24 and size.X <= 220\n                    and size.Y >= 24 and size.Y <= 220\n                    and area < bestArea then\n\n                    local hasImage = false\n                    for _, descendant in ipairs(node:GetDescendants()) do\n                        if descendant:IsA("ImageLabel") or descendant:IsA("ImageButton") then\n                            hasImage = true\n                            break\n                        end\n                    end\n\n                    if hasImage then\n                        best = node\n                        bestArea = area\n                    end\n                end\n            end\n\n            node = node.Parent\n        end\n\n        return best or object.Parent\n    end\n\n    local function rewardNameFromMetadata(container)\n        if not container then return nil end\n\n        local objects = {container}\n        for _, descendant in ipairs(container:GetDescendants()) do\n            objects[#objects + 1] = descendant\n        end\n\n        for _, object in ipairs(objects) do\n            local attributes = {}\n            pcall(function()\n                attributes = object:GetAttributes()\n            end)\n\n            for _, key in ipairs(RewardAttributePriority) do\n                local candidate = cleanCandidateName(attributes[key])\n                if candidate then return candidate end\n            end\n\n            for _, value in pairs(attributes) do\n                local candidate = cleanCandidateName(value)\n                if candidate then return candidate end\n            end\n\n            if object:IsA("StringValue") then\n                local candidate = cleanCandidateName(object.Value)\n                if candidate then return candidate end\n            elseif object:IsA("ObjectValue") and object.Value then\n                local candidate = cleanCandidateName(object.Value.Name)\n                if candidate then return candidate end\n            end\n        end\n\n        return nil\n    end\n\n    local function visibleTextSnapshot()\n        local snapshot = {}\n        for _, object in ipairs(playerGui:GetDescendants()) do\n            if screenGui and object:IsDescendantOf(screenGui) then\n                continue\n            end\n\n            local value = getTextFromObject(object)\n            if value and value ~= "" and isVisibleTextObject(object) then\n                snapshot[value] = true\n            end\n        end\n        return snapshot\n    end\n\n    local function scoreTooltipCandidate(textValue, object, cursorX, cursorY)\n        local candidate = cleanCandidateName(textValue)\n        if not candidate then return nil, -math.huge end\n\n        local lower = string.lower(candidate)\n        local length = string.len(candidate)\n        local score = 0\n\n        if length <= 32 then score += 20 else score -= math.min(40, length - 32) end\n        if length >= 3 and length <= 18 then score += 12 end\n        if string.find(lower, "chance", 1, true) then score -= 30 end\n        if string.find(lower, "rarity", 1, true) then score -= 25 end\n        if string.find(lower, "%", 1, true) then score -= 25 end\n\n        -- Result tooltips are normally close to the hovered reward tile.\n        if object and object:IsA("GuiObject") then\n            local pos = object.AbsolutePosition\n            local size = object.AbsoluteSize\n            local centerX = pos.X + size.X * 0.5\n            local centerY = pos.Y + size.Y * 0.5\n            local distance = math.sqrt(\n                (centerX - (cursorX or centerX)) ^ 2\n                + (centerY - (cursorY or centerY)) ^ 2\n            )\n\n            if distance <= 220 then\n                score += 45\n            elseif distance <= 420 then\n                score += 18\n            else\n                score -= math.min(35, distance / 50)\n            end\n\n            local node = object\n            for _ = 1, 5 do\n                if not node then break end\n                local nodeName = string.lower(tostring(node.Name or ""))\n                if string.find(nodeName, "tooltip", 1, true)\n                    or string.find(nodeName, "hover", 1, true)\n                    or string.find(nodeName, "perk", 1, true)\n                    or string.find(nodeName, "reward", 1, true)\n                    or string.find(nodeName, "info", 1, true) then\n                    score += 18\n                    break\n                end\n                node = node.Parent\n            end\n        end\n\n        -- Names like CRIPPLE / GEAR BEGINNER are commonly rendered uppercase.\n        local letters = string.gsub(candidate, "[^%a]", "")\n        if letters ~= "" and letters == string.upper(letters) then\n            score += 10\n        end\n\n        return candidate, score\n    end\n\n    local function rewardNameFromHover(container)\n        if not container or not container:IsA("GuiObject") then return nil end\n\n        if RewardHoverCache[container] ~= nil then\n            return RewardHoverCache[container] or nil\n        end\n\n        pcall(function()\n            VirtualInputManager:SendMouseMoveEvent(8, 8, game)\n        end)\n        task.wait(0.04)\n\n        local before = visibleTextSnapshot()\n\n        local position = container.AbsolutePosition\n        local size = container.AbsoluteSize\n        local x = math.floor(position.X + size.X * 0.5)\n        local y = math.floor(position.Y + size.Y * 0.5)\n\n        local inset = Vector2.new(0, 0)\n        pcall(function()\n            inset = GuiService:GetGuiInset()\n        end)\n\n        pcall(function()\n            VirtualInputManager:SendMouseMoveEvent(x + inset.X, y + inset.Y, game)\n        end)\n\n        task.wait(0.20)\n\n        local bestName = nil\n        local bestScore = -math.huge\n\n        for _, object in ipairs(playerGui:GetDescendants()) do\n            if screenGui and object:IsDescendantOf(screenGui) then\n                continue\n            end\n\n            local value = getTextFromObject(object)\n            if value and value ~= "" and isVisibleTextObject(object) and not before[value] then\n                local candidate, score = scoreTooltipCandidate(value, object, x, y)\n                if candidate and score > bestScore then\n                    bestScore = score\n                    bestName = candidate\n                end\n            end\n        end\n\n        RewardHoverCache[container] = bestName or false\n        return bestName\n    end\n\n\n    local function findObtainedY(items)\n        for _, item in ipairs(items or {}) do\n            local lower = string.lower(tostring(item.text or ""))\n            if lower == "obtained" or string.find(lower, "obtained", 1, true) then\n                return tonumber(item.y) or 0\n            end\n        end\n        return nil\n    end\n\n    local function tileQuantity(tile)\n        if not tile then return 1 end\n\n        local best = nil\n        for _, object in ipairs(tile:GetDescendants()) do\n            local value = getTextFromObject(object)\n            if value and value ~= "" and isVisibleTextObject(object) then\n                local cleaned = cleanGuiText(value)\n                local number = parseNumber(cleaned)\n\n                if number and number > 0 and number <= 999 then\n                    -- Reward tile count labels are normally tiny values.\n                    if not best or number < best then\n                        best = number\n                    end\n                end\n            end\n        end\n\n        return best or 1\n    end\n\n    local function collectRewardTiles(root, items)\n        if not root then return {} end\n\n        local obtainedY = findObtainedY(items) or 0\n        local candidates = {}\n\n        for _, object in ipairs(root:GetDescendants()) do\n            if object:IsA("GuiObject")\n                and object.Visible\n                and object.AbsoluteSize.X >= 35\n                and object.AbsoluteSize.X <= 180\n                and object.AbsoluteSize.Y >= 35\n                and object.AbsoluteSize.Y <= 180 then\n\n                local hasIcon = false\n                for _, descendant in ipairs(object:GetDescendants()) do\n                    if descendant:IsA("ImageLabel")\n                        or descendant:IsA("ImageButton") then\n                        hasIcon = true\n                        break\n                    end\n                end\n\n                if hasIcon then\n                    local centerY = object.AbsolutePosition.Y + object.AbsoluteSize.Y * 0.5\n                    if centerY > obtainedY + 12 then\n                        candidates[#candidates + 1] = object\n                    end\n                end\n            end\n        end\n\n        -- Keep smallest leaf-like tile candidates.\n        table.sort(candidates, function(a, b)\n            local areaA = a.AbsoluteSize.X * a.AbsoluteSize.Y\n            local areaB = b.AbsoluteSize.X * b.AbsoluteSize.Y\n            return areaA < areaB\n        end)\n\n        local deduped = {}\n        for _, candidate in ipairs(candidates) do\n            local overlapsExisting = false\n\n            for _, existing in ipairs(deduped) do\n                if candidate:IsDescendantOf(existing)\n                    or existing:IsDescendantOf(candidate) then\n                    overlapsExisting = true\n                    break\n                end\n\n                local a = candidate.AbsolutePosition\n                local as = candidate.AbsoluteSize\n                local b = existing.AbsolutePosition\n                local bs = existing.AbsoluteSize\n\n                local centerAX = a.X + as.X * 0.5\n                local centerAY = a.Y + as.Y * 0.5\n                local centerBX = b.X + bs.X * 0.5\n                local centerBY = b.Y + bs.Y * 0.5\n\n                if math.abs(centerAX - centerBX) < 12\n                    and math.abs(centerAY - centerBY) < 12 then\n                    overlapsExisting = true\n                    break\n                end\n            end\n\n            if not overlapsExisting then\n                deduped[#deduped + 1] = candidate\n            end\n        end\n\n        -- Group every reward row below OBTAINED. V5.2 only returned the widest\n        -- row, which dropped lower-row rewards from the webhook scan.\n        local rows = {}\n        for _, tile in ipairs(deduped) do\n            local centerY = tile.AbsolutePosition.Y + tile.AbsoluteSize.Y * 0.5\n            local placed = false\n\n            for _, row in ipairs(rows) do\n                if math.abs(row.CenterY - centerY) <= 28 then\n                    row.Tiles[#row.Tiles + 1] = tile\n                    row.CenterY = (row.CenterY * (row.Count or 1) + centerY) / ((row.Count or 1) + 1)\n                    row.Count = (row.Count or 1) + 1\n                    placed = true\n                    break\n                end\n            end\n\n            if not placed then\n                rows[#rows + 1] = {CenterY = centerY, Count = 1, Tiles = {tile}}\n            end\n        end\n\n        table.sort(rows, function(a, b) return a.CenterY < b.CenterY end)\n\n        local allTiles = {}\n        for _, row in ipairs(rows) do\n            table.sort(row.Tiles, function(a, b)\n                return a.AbsolutePosition.X < b.AbsolutePosition.X\n            end)\n            for _, tile in ipairs(row.Tiles) do\n                allTiles[#allTiles + 1] = tile\n            end\n        end\n\n        return allTiles\n    end\n\n    local function findRewardNameForTile(tile)\n        if not tile then return nil end\n\n        local metadataName = rewardNameFromMetadata(tile)\n        if metadataName then\n            return metadataName\n        end\n\n        local hoverName = rewardNameFromHover(tile)\n        if hoverName then\n            return hoverName\n        end\n\n        for _, descendant in ipairs(tile:GetDescendants()) do\n            local textValue = getTextFromObject(descendant)\n            if textValue and textValue ~= "" then\n                local candidate = cleanCandidateName(textValue)\n                if candidate then\n                    return candidate\n                end\n            end\n        end\n\n        local rarity = nil\n        local fakeNumberItem = {\n            object = tile,\n            x = tile.AbsolutePosition.X,\n            y = tile.AbsolutePosition.Y,\n        }\n\n        rarity = inspectRewardRarity(fakeNumberItem)\n        if rarity then\n            return "Unknown " .. rarity .. " reward"\n        end\n\n        return "Unknown reward"\n    end\n\n    local function tileLooksLikeResource(tile)\n        if not tile then return false end\n        local keywords = {"exp", "experience", "gold", "money", "cash", "gem"}\n        local function matches(value)\n            local lower = string.lower(tostring(value or ""))\n            for _, keyword in ipairs(keywords) do\n                if string.find(lower, keyword, 1, true) then return true end\n            end\n            return false\n        end\n\n        if matches(tile.Name) then return true end\n        for _, object in ipairs(tile:GetDescendants()) do\n            if matches(object.Name) then return true end\n            local value = getTextFromObject(object)\n            if value and matches(value) then return true end\n        end\n        return false\n    end\n\n    local function extractRewardsFromTiles(root, items)\n        local tiles = collectRewardTiles(root, items)\n        if #tiles <= 2 then return {} end\n\n        local drops = {}\n\n        for index, tile in ipairs(tiles) do\n            -- Result layouts always begin with EXP and Gold. Gems are optional;\n            -- only skip later resource tiles when their metadata/text actually says so.\n            local resourceTile = index <= 2 or tileLooksLikeResource(tile)\n            if not resourceTile then\n                local name = findRewardNameForTile(tile) or "Unknown reward"\n                local quantity = tileQuantity(tile)\n\n                drops[#drops + 1] = {\n                    name = name,\n                    quantity = quantity,\n                }\n            end\n        end\n\n        return drops\n    end\n\n    local function findRewardNameNearNumber(numberItem, items)\n        local object = numberItem.object\n        if not object then return nil end\n\n        local tile = findRewardTileContainer(numberItem)\n\n        local metadataName = rewardNameFromMetadata(tile)\n        if metadataName then return metadataName end\n\n        local hoverName = rewardNameFromHover(tile)\n        if hoverName then return hoverName end\n\n        local nearbyText = findNearbyRewardText(numberItem, items)\n        if nearbyText then return nearbyText end\n\n        local container = tile or object.Parent\n        for _ = 1, 4 do\n            if not container then break end\n\n            for _, descendant in ipairs(container:GetDescendants()) do\n                if descendant ~= object then\n                    local textValue = getTextFromObject(descendant)\n                    if textValue and textValue ~= "" then\n                        local candidate = cleanCandidateName(textValue)\n                        if candidate then return candidate end\n                    end\n                end\n            end\n\n            for _, descendant in ipairs(container:GetDescendants()) do\n                if descendant:IsA("ImageLabel") or descendant:IsA("ImageButton") then\n                    local candidate = cleanCandidateName(descendant.Name)\n                    if candidate then return candidate end\n                end\n            end\n\n            local containerName = cleanCandidateName(container.Name)\n            if containerName then return containerName end\n            container = container.Parent\n        end\n\n        local rarity = inspectRewardRarity(numberItem)\n        if rarity then\n            return "Unknown " .. rarity .. " reward"\n        end\n\n        return "Unknown reward"\n    end\n\n\tlocal function extractRewards(root, items)\n\t\tlocal rewardNumberItems = collectRewardNumberItems(items)\n\t\tlocal rewards = {\n\t\t\texp = 0,\n\t\t\tgold = 0,\n\t\t\tgems = 0,\n\t\t\tdrops = {},\n\t\t}\n\n\t\tif #rewardNumberItems >= 3 then\n\t\t\trewards.exp = rewardNumberItems[1].number or 0\n\t\t\trewards.gold = rewardNumberItems[2].number or 0\n\t\t\trewards.gems = rewardNumberItems[3].number or 0\n\n            local tileDrops = extractRewardsFromTiles(root, items)\n            if #tileDrops > 0 then\n                rewards.drops = tileDrops\n                return rewards\n            end\n\n\t\t\tfor index = 4, #rewardNumberItems do\n\t\t\t\tlocal item = rewardNumberItems[index]\n\t\t\t\tlocal quantity = tonumber(item.number) or 0\n\t\t\t\tif quantity > 0 then\n\t\t\t\t\tlocal dropName = findRewardNameNearNumber(item, items) or "Unknown drop"\n\t\t\t\t\ttable.insert(rewards.drops, {\n\t\t\t\t\t\tname = dropName,\n\t\t\t\t\t\tquantity = quantity,\n\t\t\t\t\t})\n\t\t\t\tend\n\t\t\tend\n\t\telse\n\t\t\t-- Fallback for alternate result UIs that label EXP/Gold/Gems directly.\n\t\t\trewards.exp = findMetricValue(items, {"exp", "xp", "experience"})\n\t\t\trewards.gold = findMetricValue(items, {"gold", "money", "cash"})\n\t\t\trewards.gems = findMetricValue(items, {"gems", "gem"})\n\t\tend\n\n\t\treturn rewards\n\tend\n\n\tlocal function formatDrops(drops)\n\t\tif type(drops) ~= "table" or #drops == 0 then\n\t\t\treturn "None detected"\n\t\tend\n\n\t\tlocal totals = {}\n\t\tlocal order = {}\n\t\tfor _, drop in ipairs(drops) do\n\t\t\tlocal name = tostring(drop.name or "Unknown drop")\n\t\t\tif name == "" then name = "Unknown drop" end\n\t\t\tlocal quantity = tonumber(drop.quantity) or 0\n\t\t\tif quantity > 0 then\n\t\t\t\tif not totals[name] then\n\t\t\t\t\ttable.insert(order, name)\n\t\t\t\t\ttotals[name] = 0\n\t\t\t\tend\n\t\t\t\ttotals[name] += quantity\n\t\t\tend\n\t\tend\n\n\t\tif #order == 0 then\n\t\t\treturn "None detected"\n\t\tend\n\n\t\tlocal lines = {}\n\t\tfor _, name in ipairs(order) do\n\t\t\ttable.insert(lines, "\u{2022} **" .. name .. "** x" .. tostring(totals[name]))\n\t\tend\n\n\t\treturn table.concat(lines, "\\n")\n\tend\n\n\tlocal function sanitizeDrops(drops)\n\t\tlocal clean = {}\n\t\tlocal seen = {}\n\t\tfor _, drop in ipairs(type(drops) == "table" and drops or {}) do\n\t\t\tlocal name = cleanCandidateName(drop.name)\n\t\t\tlocal lower = string.lower(tostring(name or ""))\n\t\t\tlocal quantity = math.max(0, math.floor((tonumber(drop.quantity) or 0) + 0.5))\n\t\t\tlocal untrusted = name == nil\n\t\t\t\tor lower == "unknown drop"\n\t\t\t\tor lower == "unknown reward"\n\t\t\t\tor string.find(lower, "unknown ", 1, true) == 1\n\n\t\t\tif not untrusted and quantity > 0 then\n\t\t\t\tlocal key = string.lower(name)\n\t\t\t\tif not seen[key] then\n\t\t\t\t\tseen[key] = {name = name, quantity = 0}\n\t\t\t\t\tclean[#clean + 1] = seen[key]\n\t\t\t\tend\n\t\t\t\tseen[key].quantity += quantity\n\t\t\tend\n\t\tend\n\t\treturn clean\n\tend\n\n\tlocal function rewardSnapshotSignature(data)\n\t\tlocal parts = {\n\t\t\ttostring(math.max(0, tonumber(data and data.exp) or 0)),\n\t\t\ttostring(math.max(0, tonumber(data and data.gold) or 0)),\n\t\t\ttostring(math.max(0, tonumber(data and data.gems) or 0)),\n\t\t}\n\t\tfor _, drop in ipairs(data and data.drops or {}) do\n\t\t\tparts[#parts + 1] = string.lower(tostring(drop.name or ""))\n\t\t\t\t.. "=" .. tostring(tonumber(drop.quantity) or 0)\n\t\tend\n\t\treturn table.concat(parts, "|")\n\tend\n\n\tlocal function containsRareNamedDrop(drops)\n\t\tfor _, drop in ipairs(type(drops) == "table" and drops or {}) do\n\t\t\tlocal lower = string.lower(tostring(drop.name or ""))\n\t\t\tif string.find(lower, "mythic", 1, true)\n\t\t\t\tor string.find(lower, "serum", 1, true) then\n\t\t\t\treturn true\n\t\t\tend\n\t\tend\n\t\treturn false\n\tend\n\n\tlocal function collectUniqueLines(items)\n\t\tlocal lines = {}\n\t\tlocal seen = {}\n\n\t\tfor _, item in ipairs(items) do\n\t\t\tlocal text = item.text\n\t\t\tif text ~= "" and not seen[text] then\n\t\t\t\tseen[text] = true\n\t\t\t\ttable.insert(lines, text)\n\t\t\tend\n\t\tend\n\n\t\treturn lines\n\tend\n\n\tlocal function makeSignature(resultType, lines)\n\t\tlocal signature = resultType\n\t\tfor index = 1, math.min(#lines, 12) do\n\t\t\tsignature = signature .. "|" .. lines[index]\n\t\tend\n\t\treturn signature\n\tend\n\n\tlocal function trimForDiscord(text, limit)\n\t\ttext = tostring(text or "")\n\t\tlimit = limit or 1000\n\t\tif string.len(text) <= limit then return text end\n\t\treturn string.sub(text, 1, limit - 3) .. "..."\n\tend\n\n\tlocal function detectResultType(statusLower, lines)\n\t\tlocal joined = string.lower(table.concat(lines, " "))\n\t\tlocal source = tostring(statusLower or "") .. " " .. joined\n\n\t\tif string.find(source, "failed", 1, true) or string.find(source, "defeat", 1, true) then\n\t\t\treturn "failed"\n\t\tend\n\t\tif string.find(source, "complete", 1, true) or string.find(source, "victory", 1, true) then\n\t\t\treturn "completed"\n\t\tend\n\t\treturn "result"\n\tend\n\n    function V3ResultGuard.PanelStarting(root)\n        if not root then return false end\n\n        for _, object in ipairs(root:GetDescendants()) do\n            local value = getTextFromObject(object)\n            if value and value ~= "" and isVisibleTextObject(object) then\n                local lower = string.lower(value)\n                if string.find(lower, "starting", 1, true)\n                    or string.find(lower, "loading mission", 1, true)\n                    or string.find(lower, "teleporting", 1, true) then\n                    return true\n                end\n            end\n        end\n\n        return false\n    end\n\n    function V3ResultGuard.ActiveMissionEvidence()\n        if V4RaidDirector and V4RaidDirector.Enabled == true then\n            return true\n        end\n\n        local alive = 0\n        pcall(function()\n            alive = getCachedAliveTitanCount()\n        end)\n\n        if alive > 0 then\n            return true\n        end\n\n        -- Objective history alone is weak evidence; require a live progress row.\n        for _, key in ipairs(MissionObjectiveHistory.Order) do\n            local value = tostring(MissionObjectiveHistory.LatestByKey[key] or "")\n            if string.match(value, "%[%s*%d+%s*/%s*[1-9]%d*%s*%]") then\n                return true\n            end\n        end\n\n        return false\n    end\n\n    function V3ResultGuard.ValidData(data)\n        if type(data) ~= "table" then return false end\n        if tostring(data.timeTaken or "Unknown") == "Unknown" then return false end\n\n        -- A real result panel can be a 0-kill failure, but it must at least have\n        -- a populated result clock and a recognized result type.\n        return data.resultType == "completed"\n            or data.resultType == "failed"\n            or data.resultType == "result"\n    end\n\n    function V3ResultGuard.ResetTaskHistoryForRun()\n        MissionObjectiveHistory.Order = {}\n        MissionObjectiveHistory.LatestByKey = {}\n        MissionObjectiveHistory.LastUpdatedAt = 0\n    end\n\n\tlocal function createMissionResultEmbed(data)\n\t\tlocal isFailed = data.resultType == "failed"\n        local isRaid = tostring(data.runType or "Mission") == "Raid"\n\t\tlocal title = isFailed\n            and (isRaid and "\u{274c} Raid Failed" or "\u{274c} Mission Failed")\n            or (isRaid and "\u{2705} Raid Completed" or "\u{2705} Mission Completed")\n\t\tlocal color = isFailed and 15158332 or 3066993\n\n\t\tlocal rewardLine = "EXP **" .. formatNumber(data.exp or 0)\n\t\t\t.. "**  \u{2022}  Gold **" .. formatNumber(data.gold or 0)\n\t\t\t.. "**  \u{2022}  Gems **" .. formatNumber(data.gems or 0) .. "**"\n\t\tlocal description = "Verified from a stable result-panel snapshot."\n\n\t\tlocal embed = {\n\t\t\ttitle = title,\n\t\t\tdescription = trimForDiscord(description, 3800),\n\t\t\tcolor = color,\n\t\t\ttimestamp = os.date("!%Y-%m-%dT%H:%M:%SZ"),\n\t\t\tfields = {},\n\t\t\tfooter = {text = "SliceHub V9.4 \u{2022} Webhook V2"},\n\t\t\tpingRare = containsRareNamedDrop(data.drops),\n\t\t}\n\n        table.insert(embed.fields, {\n            name = isRaid and "\u{2694}\u{fe0f} Raid" or "\u{1f9ed} Mission",\n            value = trimForDiscord(isRaid and ((data.raidName or "Unknown raid") .. "\\n" .. tostring(data.missionDisplay or "Unknown map")) or (data.missionDisplay or "Unknown mission"), 1000),\n            inline = false,\n        })\n\n\t\ttable.insert(embed.fields, {\n\t\t\tname = "\u{23f1}\u{fe0f} Performance",\n\t\t\tvalue = "Time **" .. tostring(data.timeTaken or "Unknown")\n\t\t\t\t.. "**  \u{2022}  Kills **" .. formatNumber(data.titanKills or 0)\n\t\t\t\t.. "**  \u{2022}  Damage **" .. formatNumber(data.damageDealt or 0)\n\t\t\t\t.. "**  \u{2022}  Crits **" .. formatNumber(data.criticalHits or 0) .. "**",\n\t\t\tinline = false,\n\t\t})\n\n\t\ttable.insert(embed.fields, {\n\t\t\tname = "\u{1f4b0} Verified Rewards",\n\t\t\tvalue = rewardLine,\n\t\t\tinline = false,\n\t\t})\n\n        local queueActive, queueState = V51QueueRuntime.IsActive()\n        if isRaid and queueActive and type(queueState) == "table" then\n            table.insert(embed.fields, {\n                name = "\u{1f501} Raid Queue",\n                value = "Entry " .. tostring(queueState.Index or 1) .. "/" .. tostring(type(queueState.Entries) == "table" and #queueState.Entries or 0)\n                    .. " \u{2022} Entry progress " .. tostring(queueState.EntryDone or 0)\n                    .. " \u{2022} Total clears " .. tostring(queueState.TotalCompleted or 0)\n                    .. " \u{2022} Failures " .. tostring(queueState.TotalFailed or 0),\n                inline = false,\n            })\n        end\n\n        table.insert(embed.fields, {\n            name = isRaid and "\u{1f4cb} Raid Objectives" or "\u{1f4cb} Mission Tasks",\n            value = trimForDiscord(data.objectives or "No tasks detected", 1000),\n            inline = false,\n        })\n\n\t\ttable.insert(embed.fields, {\n\t\t\tname = "\u{1f381} Named Drops",\n\t\t\tvalue = trimForDiscord(formatDrops(data.drops), 1000),\n\t\t\tinline = false,\n\t\t})\n\n\t\tif WebhookConfig.includeRawDebug then\n\t\t\tlocal rawText = table.concat(data.lines or {}, "\\n")\n\t\t\t\t.. "\\n\\nRun recorder:\\n" .. V94RunRecorder.Summary(10)\n\t\t\tif rawText ~= "" then\n\t\t\t\ttable.insert(embed.fields, {\n\t\t\t\t\tname = "Raw GUI Debug",\n\t\t\t\t\tvalue = trimForDiscord(rawText, 1000),\n\t\t\t\t\tinline = false,\n\t\t\t\t})\n\t\t\tend\n\t\tend\n\n\t\tif WebhookConfig.enableStats then\n\t\t\tlocal statsOk, stats = pcall(getPlayerStats)\n\t\t\tif statsOk and type(stats) == "table" and stats.trusted == true then\n\t\t\t\tlocal statParts = {}\n\t\t\t\tif stats.level then table.insert(statParts, "**Level:** " .. tostring(stats.level)) end\n\t\t\t\tif stats.prestige then table.insert(statParts, "**Prestige:** " .. tostring(stats.prestige)) end\n\t\t\t\tif stats.gold then table.insert(statParts, "**Gold:** " .. tostring(stats.gold)) end\n\t\t\t\tif stats.gems then table.insert(statParts, "**Gems:** " .. tostring(stats.gems)) end\n\t\t\t\tif #statParts > 0 then\n\t\t\t\t\ttable.insert(embed.fields, {\n\t\t\t\t\t\tname = "Player Stats",\n\t\t\t\t\t\tvalue = table.concat(statParts, " | "),\n\t\t\t\t\t\tinline = false,\n\t\t\t\t\t})\n\t\t\t\tend\n\t\t\tend\n\t\tend\n\n\t\treturn embed\n\tend\n\n\tlocal function extractMissionResultData(root, statusLower)\n\t\tlocal items = getVisibleTextItems(root)\n\t\tlocal lines = collectUniqueLines(items)\n\t\tlocal resultType = detectResultType(statusLower, lines)\n\t\tlocal rewards = extractRewards(root, items)\n\t\tlocal trustedDrops = sanitizeDrops(rewards.drops)\n        local runMeta = V3MissionIdentity.GetRunMetadataForWebhook()\n\n\t\treturn {\n            runType = runMeta.RunType,\n            raidName = runMeta.RaidName,\n            difficulty = runMeta.Difficulty,\n            raidChoice = runMeta.RaidChoice,\n\t\t\tresultType = resultType,\n\t\t\ttimeTaken = findClockValue(items),\n\t\t\tdamageDealt = findMetricValue(items, {"damage dealt", "damage"}),\n\t\t\ttitanKills = findMetricValue(items, {"titans killed", "titan killed", "titans", "titan"}),\n\t\t\tcriticalHits = findMetricValue(items, {"critical hits", "critical", "crit"}),\n\t\t\texp = rewards.exp,\n\t\t\tgold = rewards.gold,\n\t\t\tgems = rewards.gems,\n\t\t\tdrops = trustedDrops,\n\t\t\trewardSignature = table.concat({\n\t\t\t\ttostring(rewards.exp or 0),\n\t\t\t\ttostring(rewards.gold or 0),\n\t\t\t\ttostring(rewards.gems or 0),\n\t\t\t\ttostring(#trustedDrops),\n\t\t\t}, "|"),\n            missionDisplay = V3MissionIdentity.GetMissionDisplayForWebhook(),\n            objectives = V3MissionIdentity.GetMissionObjectiveSummary(),\n\t\t\tlines = lines,\n\t\t}\n\tend\n\n\tlocal function updateLastRunTracker(data)\n\t\tif type(data) ~= "table" then return end\n\t\tlocal outcome = tostring(data.resultType or "result")\n\t\tlocal kills = tonumber(data.titanKills) or 0\n\t\tlocal timeTaken = tostring(data.timeTaken or "Unknown")\n\t\tlocal damage = tonumber(data.damageDealt) or 0\n\t\tState.LastRunOutcome = outcome\n\t\tState.LastRunKills = kills\n\t\tState.LastRunTime = timeTaken\n\t\tState.LastRunSummary = string.format("%s | %d kills | %s | %s dmg", string.upper(outcome), kills, timeTaken, formatNumber(damage))\n\t\tif lastRunStatusLabel then\n\t\t\tlastRunStatusLabel.Text = "Last run: " .. State.LastRunSummary\n\t\tend\n\t\trefreshAutoMissionStatus()\n\t\tsaveSettingsIfReady()\n\tend\n\n\tlocal function clearFinishedRunContext()\n\t\tMissionObjectiveHistory.Order = {}\n\t\tMissionObjectiveHistory.LatestByKey = {}\n\t\tMissionObjectiveHistory.LastUpdatedAt = 0\n\t\tMissionObjectiveHistory.SelectedObjective = nil\n\t\tMissionObjectiveHistory.SelectedMap = nil\n\t\tMissionObjectiveHistory.MetadataUpdatedAt = 0\n\t\tV3MissionIdentity.MapTracker.ObservedMap = nil\n\t\tV3MissionIdentity.MapTracker.ObservedAt = 0\n\tend\n\n\tlocal function sendMissionResultFromGui(root, statusLower)\n        -- V9.4: poll until both the result identity and reward snapshot are stable.\n        -- Never send the first half-populated animation frame.\n        local data = nil\n        local startedAt = os.clock()\n        local lastRewardSnapshot = nil\n        local stableRewardReads = 0\n\n        repeat\n            local refreshedRoot, refreshedStatus = findMissionResultRoot()\n            root = refreshedRoot or root\n            statusLower = refreshedStatus or statusLower\n\n            if not root or V3ResultGuard.PanelStarting(root) then\n                return false\n            end\n\n            data = extractMissionResultData(root, statusLower)\n            if V3ResultGuard.ValidData(data) then\n\t\t\t\tlocal snapshot = rewardSnapshotSignature(data)\n\t\t\t\tif snapshot == lastRewardSnapshot then\n\t\t\t\t\tstableRewardReads += 1\n\t\t\t\telse\n\t\t\t\t\tlastRewardSnapshot = snapshot\n\t\t\t\t\tstableRewardReads = 1\n\t\t\t\tend\n\n\t\t\t\tV94Webhook.LastRewardSignature = snapshot\n\t\t\t\tV94Webhook.LastStableReads = stableRewardReads\n\t\t\t\tV94Webhook.Status = "VERIFYING RESULT \u{2022} stable " .. tostring(stableRewardReads) .. "/2"\n\n\t\t\t\